(window.courseContentFiles = window.courseContentFiles || {})["000002/0007"] = "<!DOCTYPE html>\n<html lang=\"bg\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>1</title>\n  <link rel=\"stylesheet\" href=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.css\">\n  <style>\n    body {\n      font-family: \"Open Sans\", Arial, sans-serif;\n      max-width: 1550px;\n      margin: 0.5rem auto;\n      padding: 0 1rem;\n      line-height: 1.6;\n      color: #1f2937;\n    }\n    h1, h2, h3, h4 {\n      font-weight: 600;\n      margin-top: 0.7em;\n      margin-bottom: 0;\n      color: #588157;\n    }\n    h1 { font-size: 1.65em; }\n    h2 { font-size: 1.3em; }\n    h3 { font-size: 1.1em; margin-bottom: 0; }\n    h4 { font-size: 1.05em; margin-bottom: 0; }\n    h1 + h2, h1 + h3, h1 + h4, h2 + h3, h2 + h4, h3 + h4 { margin-top: 0.1em; }\n    p {\n      margin: 0.3em 0;\n      white-space: pre-wrap;\n    }\n    hr {\n      margin: 0.45em 0 0.2em;\n    }\n    hr + h1,\n    hr + h2,\n    hr + h3,\n    hr + h4 {\n      margin-top: 0.2em;\n    }\n    hr + p,\n    hr + ul,\n    hr + ol,\n    hr + blockquote,\n    hr + pre,\n    hr + table {\n      margin-top: 0.08em;\n    }\n    p + ul, p + ol { margin-top: 0.2em; }\n    h1 + p, h2 + p, h3 + p, h4 + p,\n    h1 + ul, h2 + ul, h3 + ul, h4 + ul,\n    h1 + ol, h2 + ol, h3 + ol, h4 + ol {\n      margin-top: 0;\n    }\n    ul, ol {\n      margin: 0.2em 0;\n      padding-left: 1.5em;\n      list-style-position: outside;\n    }\n    li { margin: 0.2em 0; }\n    li p {\n      margin: 0;\n      padding: 0;\n      display: inline;\n    }\n    li > ul, li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    ul ul, ul ol, ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    ul ul { list-style-type: circle; }\n    ul ul ul { list-style-type: square; }\n    strong { font-weight: 600; }\n    em { font-style: italic; }\n    code {\n      background: rgba(218, 215, 205, 0.3);\n      padding: 2px 6px;\n      border-radius: 3px;\n      font-family: \"Courier New\", monospace;\n      font-size: 0.9em;\n    }\n    pre {\n      background: rgba(255, 255, 255, 0.5);\n      padding: 12px;\n      border-radius: 4px;\n      overflow-x: auto;\n      margin: 0.5em 0;\n      font-family: \"Courier New\", monospace;\n    }\n    pre code {\n      background: none;\n      padding: 0;\n    }\n    blockquote {\n      border-left: 3px solid #588157;\n      padding-left: 1em;\n      margin: 0.5em 0;\n      font-style: italic;\n      color: #166534;\n    }\n    table {\n      border-collapse: collapse;\n      margin: 0.75em 0;\n      width: 100%;\n      table-layout: auto;\n    }\n    th, td {\n      border: 1px solid rgba(2, 2, 2, 0.2);\n      padding: 6px 10px;\n      text-align: left;\n      vertical-align: top;\n      height: 24px;\n      line-height: 1.2;\n    }\n    thead th {\n      background: rgba(88, 129, 87, 0.13);\n      font-weight: 600;\n    }\n    tbody tr:nth-child(odd) {\n      background: rgba(88, 129, 87, 0.06);\n    }\n    /* Image alignment rules for exported content and md-viewer */\n    img[data-align=\"left\"] {\n      display: block;\n      margin: 8px auto 8px 0;\n    }\n    img[data-align=\"center\"] {\n      display: block;\n      margin: 8px auto;\n    }\n    img[data-align=\"right\"] {\n      display: block;\n      margin: 8px 0 8px auto;\n    }\n    .audio-link-inline {\n      display: inline-flex;\n      align-items: center;\n      gap: 8px;\n      margin: 0.2em 0;\n      max-width: 100%;\n      vertical-align: middle;\n    }\n    .audio-link-icon {\n      width: 28px;\n      height: 28px;\n      border: 1px solid #588157;\n      border-radius: 999px;\n      background: #f0f7f0;\n      color: #2f5d50;\n      cursor: pointer;\n      font-size: 14px;\n      line-height: 1;\n      display: inline-flex;\n      align-items: center;\n      justify-content: center;\n      flex: 0 0 auto;\n    }\n    .audio-link-inline audio {\n      position: absolute;\n      width: 1px;\n      height: 1px;\n      opacity: 0;\n      overflow: hidden;\n      pointer-events: none;\n    }\n    .audio-link-icon img {\n      width: 14px;\n      height: 14px;\n      object-fit: contain;\n      pointer-events: none;\n    }\n    a {\n      color: inherit; /* Changed to inherit */\n      text-decoration: underline;\n    }\n    a:hover {\n      color: #74b673;\n    }\n    /* Keep <p> tags inside list items on same line (as they appear in editor) */\n    li p {\n      margin: 0 !important;\n      padding: 0 !important;\n      display: inline !important;\n    }\n    /* Prevent nested list paragraph issues */\n    li > ul,\n    li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    /* Ensure list structure is clean */\n    ul ul, ul ol,\n    ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    @media (max-width: 900px) {\n      body {\n        margin: 0.5rem 0;\n        padding: 0 0.5rem;\n        font-size: 16px;\n      }\n      h1 { font-size: 1.65em; }\n      h2 { font-size: 1.3em; }\n      h3 { font-size: 1.1em; }\n      p { margin: 0.3em 0; }\n      ul, ol { padding-left: 1.5em; }\n      li { margin: 0.2em 0; }\n      table { font-size: 0.9em; }\n      th, td { padding: 6px 10px; }\n    }\n    .editor-note {\n      text-decoration: underline dotted #a3b18a;\n      text-decoration-thickness: 2px;\n      text-underline-offset: 2px;\n      text-decoration-skip-ink: none;\n      cursor: help;\n      position: relative;\n    }\n    .note-tooltip {\n      display: none;\n      position: absolute;\n      background-color: #f0f7f0;\n      color: #1f2937;\n      border: 1px solid #588157;\n      border-radius: 4px;\n      padding: 8px 12px;\n      width: fit-content;\n      max-width: min(700px, calc(100vw - 20px));\n      max-height: calc(100vh - 20px);\n      overflow: auto;\n      box-sizing: border-box;\n      box-shadow: 0 2px 8px rgba(0,0,0,0.2);\n      z-index: 10000;\n      font-size: 0.9em;\n      line-height: 1.4;\n      word-wrap: break-word;\n    }\n    .note-tooltip ul, .note-tooltip ol {\n      margin: 0 !important;\n      padding-left: 20px !important;\n    }\n    .note-tooltip li {\n      margin: 0 0 0.1em 0 !important;\n      padding: 0 !important;\n      line-height: 1.2 !important;\n    }\n    .note-tooltip li:last-child {\n      margin-bottom: 0 !important;\n    }\n    .note-tooltip .note-table-scroll {\n      overflow-x: hidden;\n      margin: 0.3em 0;\n      max-width: 100%;\n    }\n    .note-tooltip table {\n      border-collapse: collapse;\n      width: 100%;\n      max-width: 100%;\n      min-width: 0;\n      table-layout: fixed;\n      background: #ffffff;\n    }\n    .note-tooltip th,\n    .note-tooltip td {\n      border: 1px solid rgba(88, 129, 87, 0.35);\n      padding: 4px 8px;\n      text-align: left;\n      vertical-align: top;\n      line-height: 1.3;\n      white-space: normal;\n      overflow-wrap: anywhere;\n      word-break: break-word;\n    }\n    .note-tooltip thead th {\n      background: rgba(88, 129, 87, 0.12);\n      font-weight: 600;\n    }\n  </style>\n  <script>\n    document.addEventListener('DOMContentLoaded', function() {\n      const tooltip = document.createElement('div');\n      tooltip.className = 'note-tooltip';\n      document.body.appendChild(tooltip);\n\n      function parseNoteMarkdown(text) {\n        if (!text) return '';\n\n        const splitTableCells = function(line) {\n          return String(line || '')\n            .trim()\n            .replace(/^\\|/, '')\n            .replace(/\\|$/, '')\n            .split('|')\n            .map(function(cell) { return cell.trim(); });\n        };\n\n        const isTableSeparatorLine = function(line) {\n          const cells = splitTableCells(line);\n          return cells.length > 0 && cells.every(function(cell) {\n            return /^:?-{3,}:?$/.test(cell);\n          });\n        };\n\n        const getTableAlignment = function(cell) {\n          if (/^:-{3,}:$/.test(cell)) return 'center';\n          if (/^-{3,}:$/.test(cell)) return 'right';\n          if (/^:-{3,}$/.test(cell)) return 'left';\n          return '';\n        };\n\n        let lines = text.split('\\n');\n        let html = [];\n        let stack = [];\n\n        for (let i = 0; i < lines.length; i++) {\n          let line = lines[i];\n\n          let indentMatch = line.match(/^(\\s*)/);\n          let indent = indentMatch ? indentMatch[1].length : 0;\n          let content = line.trim();\n\n          const nextLine = i + 1 < lines.length ? lines[i + 1].trim() : '';\n          const maybeTableHeader = content.includes('|') && splitTableCells(content).length >= 2;\n          const maybeTableSeparator = nextLine.includes('|') && isTableSeparatorLine(nextLine);\n\n          if (maybeTableHeader && maybeTableSeparator) {\n            while (stack.length > 0) {\n              let closed = stack.pop();\n              html.push('</' + closed.type + '>');\n            }\n\n            const headerCells = splitTableCells(content);\n            const alignCells = splitTableCells(nextLine);\n\n            html.push('<div class=\"note-table-scroll\"><table><thead><tr>');\n            headerCells.forEach(function(cell, idx) {\n              const align = getTableAlignment(alignCells[idx] || '');\n              const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n              html.push('<th' + alignAttr + '>' + cell + '</th>');\n            });\n            html.push('</tr></thead><tbody>');\n\n            i += 2;\n            while (i < lines.length) {\n              const rowLine = lines[i].trim();\n              if (!rowLine || !rowLine.includes('|')) break;\n              if (isTableSeparatorLine(rowLine)) {\n                i++;\n                continue;\n              }\n\n              const rowCells = splitTableCells(rowLine);\n              if (rowCells.length === 0) {\n                i++;\n                continue;\n              }\n\n              html.push('<tr>');\n              rowCells.forEach(function(cell, idx) {\n                const align = getTableAlignment(alignCells[idx] || '');\n                const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n                html.push('<td' + alignAttr + '>' + cell + '</td>');\n              });\n              html.push('</tr>');\n              i++;\n            }\n\n            html.push('</tbody></table></div>');\n            i--;\n            continue;\n          }\n\n          let isUl = /^[-*]\\s+(.+)/.test(content);\n          let isOl = /^\\d+\\.\\s+(.+)/.test(content);\n\n          if (isUl || isOl) {\n            let listType = isUl ? 'ul' : 'ol';\n            let match = isUl ? content.match(/^[-*]\\s+(.+)/) : content.match(/^\\d+\\.\\s+(.+)/);\n            let itemText = match[1];\n\n            if (stack.length === 0) {\n              stack.push({ type: listType, indent: indent });\n              html.push('<' + listType + '>');\n            } else {\n              let last = stack[stack.length - 1];\n\n              if (indent > last.indent) {\n                stack.push({ type: listType, indent: indent });\n                html.push('<' + listType + '>');\n              } else if (indent < last.indent) {\n                while (stack.length > 0 && stack[stack.length - 1].indent > indent) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                }\n                if (stack.length === 0 || stack[stack.length - 1].indent !== indent) {\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                } else if (stack[stack.length - 1].type !== listType) {\n                   let closed = stack.pop();\n                   html.push('</' + closed.type + '>');\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                }\n              } else {\n                if (last.type !== listType) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                  stack.push({ type: listType, indent: indent });\n                  html.push('<' + listType + '>');\n                }\n              }\n            }\n            html.push('<li>' + itemText + '</li>');\n          } else {\n            if (content !== '') {\n               while (stack.length > 0) {\n                 let closed = stack.pop();\n                 html.push('</' + closed.type + '>');\n               }\n            }\n            if (/^(?:---|\\*\\*\\*|___)$/.test(content)) {\n              html.push('<hr>');\n            } else if (/^#{1,4}\\s+/.test(content)) {\n              const headingMatch = content.match(/^(#{1,4})\\s+(.+)$/);\n              if (headingMatch) {\n                const level = headingMatch[1].length;\n                html.push('<h' + level + '>' + headingMatch[2] + '</h' + level + '>');\n              }\n            } else if (content) {\n              html.push(content + '<br>');\n            } else {\n              html.push('<br>');\n            }\n          }\n        }\n\n        while (stack.length > 0) {\n          let closed = stack.pop();\n          html.push('</' + closed.type + '>');\n        }\n\n        let result = html.join('')\n          .replace(/!\\[(.*?)\\]\\((.*?)\\)/g, '<img src=\"$2\" alt=\"$1\">')\n          .replace(/\\*\\*(.+?)\\*\\*/g, '<strong>$1</strong>')\n          .replace(/__(.+?)__/g, '<strong>$1</strong>')\n          .replace(/\\*(.+?)\\*/g, '<em>$1</em>')\n          .replace(/_(.+?)_/g, '<em>$1</em>')\n          .replace(/`(.+?)`/g, '<code>$1</code>')\n          .replace(/\\[(.+?)\\]\\((.+?)\\)/g, '<a href=\"$2\" target=\"_blank\">$1</a>');\n\n        result = result\n          .replace(/<br><ul>/g, '<ul>')\n          .replace(/<br><ol>/g, '<ol>')\n          .replace(/</ul><br>/g, '</ul>')\n          .replace(/</ol><br>/g, '</ol>');\n\n        return result;\n      }\n\n      document.body.addEventListener('mouseover', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          const note = e.target.dataset.note;\n          if (note) {\n            tooltip.innerHTML = parseNoteMarkdown(note);\n            tooltip.style.display = 'block';\n            const rect = e.target.getBoundingClientRect();\n            const tooltipRect = tooltip.getBoundingClientRect();\n            const pageX = window.scrollX || window.pageXOffset;\n            const pageY = window.scrollY || window.pageYOffset;\n            const maxLeft = pageX + window.innerWidth - tooltipRect.width - 10;\n            const minLeft = pageX + 10;\n\n            let left = rect.left + pageX;\n            if (left > maxLeft) left = maxLeft;\n            if (left < minLeft) left = minLeft;\n\n            let top = rect.bottom + pageY + 6;\n            const maxTop = pageY + window.innerHeight - tooltipRect.height - 10;\n            if (top > maxTop) {\n              top = rect.top + pageY - tooltipRect.height - 6;\n            }\n            if (top < pageY + 10) top = pageY + 10;\n\n            tooltip.style.left = left + 'px';\n            tooltip.style.top = top + 'px';\n          }\n        }\n      });\n\n      document.body.addEventListener('mouseout', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          setTimeout(() => {\n            if (!tooltip.matches(':hover')) {\n              tooltip.style.display = 'none';\n            }\n          }, 100);\n        }\n      });\n\n      tooltip.addEventListener('mouseleave', function() {\n        tooltip.style.display = 'none';\n      });\n    });\n  </script>\n</head>\n<body>\n<blockquote style=\"text-align: left\">До 7ма са проверени, след това copy pasted. Малко са дълги, трябва да се съкратят.</blockquote><h1 style=\"text-align: center; color: rgb(88, 129, 87)\">Тема 1: БТЕ – дефиниция, рискови фактори, класификация и клиника</h1><h2 style=\"color: rgb(88, 129, 87)\">Дефиниция и обща характеристика</h2><p><strong>Белодробният тромбемболизъм (БТЕ)</strong> представлява <strong>запушване на клон на белодробната артерия или клонове</strong>, най-често в резултат на миграция на тромби, изхождащи от дълбоките вени на долните крайници или на вените в областта на таза. </p><p>Венозният тромбоемболизъм (ВТЕ) е общо понятие, което включва <strong>дълбоката венозна тромбоза (ДВТ)</strong> и <strong>белодробния емболизъм (БЕ)</strong>. Промените в белия дроб се разглеждат като етап в протичането на единен болестен процес:</p><ol><li>Тромбоза на периферната вена.</li><li>Емболизация на белодробната артерия.</li><li>Инфарциране на белодробния паренхим (в някои случаи).</li></ol><p><strong>Източници на емболи:</strong></p><ul><li>Повече от <strong>95%</strong> от белодробните емболии произлизат от <strong>дълбоките вени на долните крайници</strong>, най-често <strong>v. poplitea</strong>.</li><li>Значение имат и вените на малкия таз, периутеринния и хемороидалния плексус.</li><li>Много рядко заболяването може да се изяви като <strong>първична (автохтонна) тромбоза</strong> на белодробните артерии (в около 4.1% от случаите, често при хронични белодробни заболявания).</li></ul><p>Острата белодробна емболия остава една от основните причини за смъртност, като при 25% от пациентите клиничната манифестация е <strong>внезапна смърт</strong>.</p><p><img src=\"https://files.coursebook.lol/Coursebook%20Assets/2026-05-05/coursebook-assets/assets/%D0%91%D0%A2%D0%95-%D0%A4%D0%B8%D0%B31.png\" alt=\"БТЕ-Фиг1.png\" data-original-src=\"https://files.coursebook.lol/Coursebook%20Assets/2026-05-05/coursebook-assets/assets/%D0%91%D0%A2%D0%95-%D0%A4%D0%B8%D0%B31.png\" data-width=\"60\" style=\"max-width: 100%; height: auto; display: block; min-width: 300px; width: 378px\" data-broken-cleanup-bound=\"1\"></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"color: rgb(88, 129, 87)\">Рискови фактори и етиопатогенеза</h2><p>Основна роля за разбирането на рисковите фактори играе <strong>Класическата триада на Вирхов</strong>, която представя основните механизми, водещи до БТЕ:</p><h3 style=\"color: rgb(88, 129, 87)\">1. Триада на Вирхов</h3><ul><li><strong>Стаза:</strong> Наблюдава се при имобилизиране, напреднала възраст, при операция.</li><li><strong>Хиперкоагулация:</strong></li><ul><li>Бременност, карцином, хормоно-заместителна терапия.</li><li>Полицитемия вера, тромбоцитоза.</li><li>Генетични дефекти (Фактор V на Лайден, Протеин С или S дефицит, мутация на фактор 8, протромбинова мутация, антитромбин III дефицит).</li><li>Хронични белодробни заболявания, сърдечна недостатъчност, предсърдно мъждене.</li></ul><li><strong>Съдово възпаление:</strong></li><ul><li>Хирургия, разширени вени, тромбофлебит.</li><li>Фрактура на долните крайници, изгаряния.</li></ul></ul><h3 style=\"color: rgb(88, 129, 87)\">2. Придобити рискови фактори</h3><p>Най-честите <strong>транзиторни или обратими рискови фактори</strong> за БТЕ са:</p><ul><li>Напреднала възраст.</li><li>Продължителна имобилизация (вкл. продължително пътуване).</li><li>Операции (особено ортопедични и коремни).</li><li>Фрактури и тъканни травми.</li><li><strong>Злокачествени заболявания</strong> и химиотерапия.</li><li><strong>Бременност и раждане:</strong> Рискът е 5 пъти по-висок при бременни, като 66% от БТЕ настъпват след раждането.</li><li>Употреба на <strong>естрогени</strong> (перорални контрацептиви или хормонална заместителна терапия – трикратно повишаване на риска).</li><li><strong>ХОББ</strong> и сърдечна декомпенсация.</li><li><strong>Тютюнопушене</strong> (независим рисков фактор).</li><li>Затлъстяване.</li><li>Наличие на постоянен катетър или протезни повърхности.</li><li>Други състояния: Нефротичен синдром, болест на Бюргер, синдром на Бехчет, възпалителна болест на дебелото черво, лупусен антикоагулант.</li></ul><p>Съществува и специфична ситуация, наречена <strong>\"Тоалетен синдром\"</strong> – остра белодробна емболия, проявяваща се по време на дефекация поради изпълнение на Валсалва маньовър, който повишава налягането и улеснява откъсването на венозен тромб.</p><h3 style=\"color: rgb(88, 129, 87)\">3. Унаследени рискови фактори (Тромбофилии)</h3><p>Свързани са със състояние на <strong>хиперкоагулабилност</strong>. Индивиди, носещи повече от един рисков фактор, са с по-висок риск. Най-честите генетични аномалии включват:</p><ul><li>Дефицит на <strong>антитромбин III, протеин С, протеин S</strong>.</li><li><strong>Фактор V Leiden</strong> (резистентност към активиран протеин С).</li><li><strong>Протромбин 20210А</strong> мутация.</li><li>Повишени нива на хомоцистеин (хиперхомоцистеинемия).</li></ul><h2 style=\"color: rgb(88, 129, 87)\">Патофизиология</h2><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p>Най-често източник на пулмоналните емболи са дълбоките вени на долните крайници и таза. Тромбите се откъсват от тези вени, емболизират белодробните артерии и причиняват промени в <strong>хемодинамиката</strong> и <strong>газовата обмяна</strong>.</p><h4 style=\"color: rgb(88, 129, 87)\">Промени в хемодинамиката</h4><p>Определят се от размера на ембола, кардиопулмоналния статус и компенсаторните адаптации. Острият БТЕ води до:</p><ol><li><strong>Анатомична обструкция</strong> на съда.</li><li>Освобождаване на пулмонални артериални <strong>вазоконстриктори</strong>, които водят до <strong>увеличение на пулмоналното съдово съпротивление и дяснокамерно (ДК) следнатоварване</strong>.</li><li>Внезапното увеличаване на ДК следнатоварване може да предизвика <strong>ДК дилатация и хипокинезия, трикуспидална регургитация и накрая ДК недостатъчност</strong>.</li><li><strong>Намалененият ДК дебит</strong> и изместването на междукамерната преграда наляво в диастола затруднява левокамерното пълнене.</li><li>Бърза прогресия до <strong>системна артериална хипотензия и сърдечен арест</strong>.</li><li>Намаленото системно артериално налягане води до намалена коронарна перфузия и намалена доставка на кислород до деснокамерния миокард.</li></ol><h4 style=\"color: rgb(88, 129, 87)\">Промени в газовата обмяна</h4><p>Механизмите, водещи до влошаване на газовата обмяна, включват:</p><ol><li><strong>Нарушено отношение вентилация/перфузия</strong>.</li><li><strong>Увеличение на мъртвото пространство</strong> за сметка на алвеоларното мъртво пространство (зоната периферно от емболията се вентилира, но не получава функционален кръвоток).</li><li><strong>Дясно-ляв шънт</strong>:</li><ul><li>(а) интрапулмонален шънт (отваряне на артерио-венозни анастомози);</li><li>(б) интракардиален шънт (отваряне на foramen ovale при масивен БТЕ).</li></ul><li><strong>Редуцирано кислородно насищане</strong> в смесената венозна кръв.</li></ol><p><strong>Артериалната хипоксемия</strong> и <strong>увеличеният алвеоларно-артериален градиент [(A-a)pO2]</strong> са двете най-важни нарушения на газовата обмяна. </p><p><strong>Хипервентилацията</strong> може да допринесе за развитието на <strong>хипокапния и респираторна алкалоза</strong>.</p><p><strong>Белодробен инфаркт</strong> се среща рядко, тъй като са налице три източника на кислород (клонове на белодробната артерия, бронхиална артерия и дихателните пътища).  Необходимо е да бъдат нарушени 2 от тези 3 източника на кислород, за да се достигне до белодробен инфаркт. Инфаркт е по-вероятно да се получи при пациенти със съществуваща левокамерна недостатъчност или белодробно заболяване.</p><img src=\"https://files.coursebook.lol/Coursebook%20Assets/2026-05-05/coursebook-assets/assets/%D0%91%D0%A2%D0%95-%D0%A4%D0%B8%D0%B32.png\" alt=\"БТЕ-Фиг2.png\" data-original-src=\"https://files.coursebook.lol/Coursebook%20Assets/2026-05-05/coursebook-assets/assets/%D0%91%D0%A2%D0%95-%D0%A4%D0%B8%D0%B32.png\" data-width=\"50\" style=\"max-width: 100%; height: auto; display: block; min-width: 300px; width: 454px\" data-broken-cleanup-bound=\"1\"><br><br><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"color: rgb(88, 129, 87)\">Класификация</h2><p>Белодробният тромбемболизъм се класифицира по няколко критерия, които са важни за терапевтичното поведение и прогнозата.</p><h3 style=\"color: rgb(88, 129, 87)\">1. Според клиничния риск (Тежест на острия БЕ)</h3><p>Тази класификация се базира на риска от ранна смърт (вътреболнична или 30-дневна) и клиничния статус:</p><ul><li><strong>Високорисков БТЕ:</strong> Подозира се или се потвърждава при наличие на <strong>клинична нестабилност</strong> (шок или хипотония).</li><li><strong>Невисокорисков БТЕ:</strong> При отсъствие на клинична нестабилност.</li></ul><p><strong>Дефиниция за клинична нестабилност:</strong></p><ul><li>Необходимост от кардиопулмонална ресусцитация.</li><li><strong>Обструктивен шок:</strong> Систолно АН &lt; 90 mmHg или нужда от вазопресори за поддържане на АН ≥ 90 mmHg, въпреки адекватно обемно заместване, придружено от белези на хипоперфузия (<p>влошен психичен статус; студена, лепкава кожа; олигурия/анурия; увеличен серумен лактат</p>).</li><li><strong>Персистираща хипотензия:</strong> Систолно АН &lt; 90 mmHg или спад с ≥ 40 mmHg за повече от 15 минути<p>, което не е причинено от новопоявила се аритмия, хиповолемия или сепсис.</p></li></ul><h3 style=\"color: rgb(88, 129, 87)\">2. Според големината на ембола</h3><ul><li><strong>Масивен БТЕ:</strong></li><ul><li>Клинично се проявява с <strong>шок и/или хипотония</strong> (систолно налягане &lt; 90 mmHg и<p>ли спад с ≥ 40 mmHg за повече от 15 минути</p>).</li><li>Води до остра дясна сърдечна недостатъчност.</li><li>Честа причина за внезапна сърдечна смърт.</li></ul><li><strong>Субмасивен БТЕ:</strong></li><ul><li>Пациенти с хемодинамична стабилност (без хипотония), но с <strong>ехокардиографски признаци на дяснокамерна хипокинезия или дилатация</strong> (остро ДК обременяване).</li></ul><li><strong>Немасивен БТЕ:</strong></li><ul><li>Протича<strong> без промяна в артериалното налягане</strong>.</li><li>Предимно респираторни симптоми (с или без инфаркт).</li><li>Оклузията е под 50% от a. pulmonalis или <p>оклузия на по-малки клонове с общ диаметър &lt; 50%</p>.</li></ul></ul><h3 style=\"color: rgb(88, 129, 87)\">3. Според начина на протичане</h3><ul><li><strong>Остър БТЕ.</strong></li><li><strong>Рецидивиращ БТЕ (хроничен):</strong> Свързва се с несвоевременно диагностициране или персистиращ източник (често неоплазми).</li><li><strong>Хронично рецидивираща микроемболична БТЕ:</strong> Най-трудна за диагноза. Характеризира се с развитие на хронично белодробно сърце, неясно начало, уморяемост и задух.</li></ul><h3 style=\"color: rgb(88, 129, 87)\">4. Работна класификация за ежедневната практика</h3><p><strong>А. Кардиална форма:</strong></p><ol><li>Остра</li><li>Подостра</li><li>Хронична</li></ol><p><strong>Б. Белодробна форма:</strong></p><ol><li>Обикновена белодробна:</li><ul><li>Безинфарктна</li><li>Инфарктна</li></ul><li>Микротромбемболична</li></ol><p><strong>В. Хронична рецидивираща форма:</strong></p><ul><li>Рецидивираща инфарктна</li><li>Рецидивираща микротромбемболична</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"color: rgb(88, 129, 87)\">Клинична картина</h2><p>Клиниката се определя от формата на емболизма, големината на тромба, възрастта на болния и придружаващите заболявания. В 90% от случаите съмнението възниква при наличие на диспнея, гръдна болка или синкоп.</p><h3 style=\"color: rgb(88, 129, 87)\">Основни симптоми и признаци</h3><p><strong>Типичната тетрада включва:</strong></p><ol><li><strong>Тахипнея</strong></li><li><strong>Диспнея</strong></li><li><strong>Тахикардия</strong></li><li><strong>Хипотония</strong></li></ol><p>Към тях често се добавят <strong>гръдна болка</strong> и <strong>хемоптиза</strong> (кръвохрачене).</p><h3 style=\"color: rgb(88, 129, 87)\">Клинични форми на протичане</h3><p>Острият БТЕ обикновено се представя по четири главни начина:</p><ol><li><strong>Пулмонален синдром:</strong> Типична плеврална болка със или без хемоптиза; възможна е поява на локални признаци като плеврално триене.</li><li><strong>Изолирана диспнея:</strong> Остра диспнея без кръвохрак или циркулаторна нестабилност, но при пациент с рискови фактори.</li><li><strong>Хемодинамична нестабилност (Циркулаторен колапс):</strong> Хипотензия, която може да е съпроводена със синкоп. Дължи се на централен масивен БЕ, водещ до дясна сърдечна недостатъчност.</li><li><strong>Хемодинамична нестабилност при лош резерв:</strong> Малки емболи могат да бъдат катастрофални при възрастни пациенти с ограничен кардиореспираторен резерв.</li></ol><h3 style=\"color: rgb(88, 129, 87)\">Специфика на отделните форми</h3><h4 style=\"color: rgb(88, 129, 87)\">1. Кардиална форма на БТЕ</h4><ul><li><strong>Остро протичане:</strong></li><ul><li>В 70-80% смъртта настъпва моментално или до няколко часа.</li><li><strong>Симптоми:</strong> Мълниеносно развиващ се <strong>тежък задух</strong>, <strong>студена пот</strong>, <strong>прекордиална болка </strong>(наподобяваща стенокардия), гадене, <p><strong>смъртен страх</strong></p>.</li><li><strong>Обективно:</strong> Изразена <strong>цианоза</strong>, <strong>тахипнея</strong>, <strong>конвулсии</strong>, <strong>разширени шийни вени </strong>(десностранен застой), <strong>кръвохрак</strong>.</li><li><p><strong>При палпация</strong>: <strong>Филиформен пулс</strong>, студени крайници, увеличен и болезнен <strong>хепар</strong>, тромбофлебит или флеботромбоза.</p><br></li><li><p><strong>При перкусия/аускултация</strong>: Разширена дясна сърдечна граница с <strong>акцентиран II тон</strong> на белодробната артерия, галопен ритъм, бронхоспазъм, хъркащи, мъркащи хрипове и <strong>плеврален излив</strong>.</p><br></li><li><p><strong>Болка в гърдите</strong> (52-86%): Свързана с функционална коронарна недостатъчност, остро разширение устието на белодробната артерия, исхемия на белодробната тъкан.</p><br></li><li><strong>Церебрален синдром:</strong> <p>Свързан с мозъчна хипоксична енцефалопатия – психомоторно възбуждение, менингиална симптоматика, епилепсия, полиневрити.</p></li><li><strong>Абдоминален синдром:</strong> <p>Коремна болка, дължаща се на остро разтягане на глисоновата капсула на черния дроб и рефлекторно нарушение на мезентериалното кръвообращение.</p></li></ul><li><strong>Подостро и хронично протичане:</strong></li><ul><li><p><strong style=\"font-weight: bold\">Подостро</strong><strong>: </strong>Няколко седмици без изразена симптоматика, завършва фатално поради <strong style=\"font-weight: bold\">деснокамерна сърдечна недостатъчност</strong>.</p><br></li><li><p><strong>Хронично</strong>: Свързано с голям тромб с прогресивно увеличаване на размерите. Налице е пристъпно изявена клиника на плеврална болка, задух, тахикардия, бронхо-обструкция. Смъртта настъпва от развитие на <strong>белодробна хипертония</strong> и <strong>деснокамерна недостатъчност</strong>.</p></li></ul></ul><h4 style=\"color: rgb(88, 129, 87)\">2. Белодробна форма на БТЕ</h4><p>Клиниката е вариабилна и по-малко драматична от кардиалната форма.</p><ul><li><strong>Безинфарктна форма:</strong></li><ul><li>Липсват симптоми на изразена сърдечна и белодробна недостатъчност.</li><li>Може да има лека болка, тахикардия, кашлица или преходна хипотония.</li></ul><li><strong>Инфарктна форма:</strong></li><ul><li><strong>Болка:</strong> Внезапна, локализирана в съответната гръдна половина (не зад гръдната кост).</li><li><strong>Задух:</strong> Наблюдава се в 80-90% от случаите, обикновено без ортопнея.</li><li><p><strong>Други симптоми</strong>: <strong>Кашлица, тахикардия, цианоза, кръвохрак в 10-56%, повишена температура</strong>.</p></li><li><strong>Физикално:</strong> Могат да се чуят влажни хрипове и да се установят данни за плеврален излив.</li><li><p><strong>Подозиране на БТЕ</strong>: При необяснимо температурно състояние при болни на постелен режим, при внезапен задух с неясна генеза, внезапна аритмия при преминаване от постелен към нормален режим.</p><br></li></ul></ul><h4 style=\"color: rgb(88, 129, 87)\">3. Микротромбемболична форма</h4><ul><li>Трудна за диагностика.</li><li>Характеризира се с <strong>хронично белодробно сърце</strong>, \"светлеещ\" бял дроб на рентген.</li><li>Симптоми: неясно начало, синкопи, световъртеж, уморяемост, задух при усилие.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Прогноза</h2><ul><li>Смъртността, асоциирана с БТЕ, е <strong>подценена</strong>.</li><li>Тя надхвърля <strong>15%</strong> в първите 3 месеца след поставяне на диагнозата.</li><li>При <strong>25%</strong> от пациентите клиничната манифестация на БТЕ е <strong>внезапната смърт</strong>.</li><li>Острата белодробна емболия остава <strong>една от основните причини за смъртност</strong>.</li></ul><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><br><br><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center; color: rgb(88, 129, 87)\">Тема 2: БТЕ – диагностичен алгоритъм и лечение на масивната форма</h1><h2>Дефиниция на масивна форма (Висок риск)</h2><p>Масивният БТЕ се дефинира чрез наличието на <strong>клинична нестабилност</strong>, която води до остра дясна сърдечна недостатъчност и висок риск от внезапна смърт.</p><p><strong>Клиничната нестабилност включва:</strong></p><ul><li><strong>Сърдечен арест:</strong> Нужда от кардиопулмонална ресусцитация.</li><li><strong>Обструктивен шок:</strong> Систолно АН <strong>&lt; 90 mmHg</strong> (или нужда от вазопресори <p>за поддържане на АН ≥ 90 mmHg</p>) + белези на <strong>органна хипоперфузия</strong> (лактат, олигурия, обърканост).</li><li><strong>Персистираща хипотония:</strong> Спад на систолното АН с <strong>≥ 40 mmHg</strong> за над 15 мин., който не се дължи на сепсис, аритмия или хиповолемия.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"color: rgb(88, 129, 87)\">Диагностични методи и изследвания</h2><p>Диагнозата се поставя въз основа на анамнестичните данни, физикалното, лабораторното изследване, данните от ЕКГ, рентгеновото и сцинтиграфското изследване. В <strong>90%</strong> съмнението възниква от клинични симптоми като диспнея, болки в гърдите или синкоп.</p><h3>1. Лабораторни изследвания: Д-димер</h3><p>Д-димерът е ключов за изключване на БТЕ, действайки като <strong>директен маркер за фибринолиза</strong> и <strong>индиректен за тромбообразуване</strong>.</p><ul><li>Тестът се характеризира едновременно с <strong>висока чувствителност (&gt;90%) и ниска/умерена специфичност</strong>.</li><li>Положителният резултат е неспецифичен (ниска позитивна предиктивна стойност), тъй като се влияе от възпаление, тумори, възраст, операции и бременност.</li><li><strong>Клинична стойност:</strong> Основната му сила е в неговата <strong>висока негативна предиктивна стойност</strong>. Негативен резултат (<strong>&lt; 500 ng/ml</strong>) изключва БТЕ с висока сигурност при ниска/междинна вероятност, спестявайки излишни образни изследвания и лечение.</li></ul><h3 style=\"color: rgb(88, 129, 87)\">2. Други лабораторни показатели</h3><ul><li><strong>Ензими:</strong> Повишени стойности на ЛДХ (<p>специално ЛДХ1, ЛДХ5 при нормални стойности на АСАТ</p>), повишен индиректен билирубин.</li><li><strong>Кръвна картина:</strong> Левкоцитоза с олевяване, намалени тромбоцити, увеличен фибриноген и фибриндеградационни продукти.</li><li><strong>Артериални кръвни газове:</strong> Често се наблюдават <strong>хипоксемия</strong> и <strong>хипокапния</strong> (поради хипервентилация) с увеличен алвеоларно-артериален градиент (&gt; 20 mmHg). Могат да бъдат и нормални.</li></ul><h3 style=\"color: rgb(88, 129, 87)\">3. Електрокардиография (ЕКГ)</h3><p>При остър масивен БТЕ ЕКГ показва белези на <strong>дяснокамерно обременяване</strong> и промяна на електрическата ос надясно:</p><ul><li><strong>Синдром S1Q3T3:</strong> Дълбока S-вълна в I отвеждане, Q-вълна в III отвеждане, инверсия на Т-вълната в III отвеждане.</li><li><strong>P-pulmonale:</strong> Висока и заострена Р вълна над &gt; 2.5 мм (израз на ДП обременяване).</li><li><strong></strong><p><strong>ДК ангажимент</strong>: Поява на <strong>непълен или пълен</strong><strong> десен бедрен блок</strong> и <strong>негативни Т-вълни</strong> от V1-4.</p></li><li>В други случаи <strong>синусовата тахикардия</strong> може да бъде единствения белег на БТЕ. Не са редки случаите на <strong>пристъпно предсърдно мъждене</strong>.</li></ul><p><img src=\"https://cdn.medizzy.com/3omCKqCRPZmTDo9iQev2Z4HR0_w=/494x395/img/posts/15edcc5c-ac91-4bc2-adcc-5cac91dbc2c8\" alt=\"https://cdn.medizzy.com/3omCKqCRPZmTDo9iQev2Z4HR0_w=/494x395/img/posts/15edcc5c-ac91-4bc2-adcc-5cac91dbc2c8\" data-original-src=\"https://cdn.medizzy.com/3omCKqCRPZmTDo9iQev2Z4HR0_w=/494x395/img/posts/15edcc5c-ac91-4bc2-adcc-5cac91dbc2c8\" data-width=\"100\" style=\"max-width: 100%; height: auto; display: block; min-width: 300px; width: 494px\" data-broken-cleanup-bound=\"1\"></p><h3>4. Ехокардиография (ЕхоКГ)</h3><p>Ехокардиографията е <strong>критична</strong> при хемодинамично нестабилни пациенти (масивна форма). Тя може да се извърши до леглото на болния и да определи терапевтичното поведение.</p><ul><li><strong>Индиректни признаци (ДК обременяване):</strong></li><ul><li>Дяснокамерна дисфункция и дилатация.</li><li>Повишено систолно налягане в белодробната артерия.</li><li>Повишена скорост на трикуспидалната регургитация (&gt; 3.0-3.5 m/sec).</li><li>Дилатирана долна празна вена с намален инспираторен колапс.</li><li>Съотношение ДК/ЛК теледиастолен диаметър &gt; 0.5.</li></ul><li><strong>Директни признаци:</strong> Визуализиране на тромби в белодробната артерия или десните кухини (чрез трансезофагеална ЕхоКГ).</li><li><strong>Значение на ЕхоКГ при шок:</strong> Ако пациент е в шок и ЕхоКГ <strong>не показва</strong> белези на ДК обременяване, БТЕ е малко вероятна причина за хемодинамичната нестабилност.</li></ul><h3 style=\"color: rgb(88, 129, 87)\">5. Образни изследвания</h3><strong>1. </strong><a href=\"https://radiopaedia.org/articles/pulmonary-embolism?lang=us\" style=\"font-weight: 600; text-decoration-thickness: initial\">Рентгеново изследване</a>&nbsp;-&nbsp;при БТЕ служи за изключване на други обяснения за оплаквания от пациента.<ul><li><strong>Признаци на остро белодробно сърце: </strong></li><ul><li>Разширение на дясна граница на сърцето</li><li>Разширените на конуса на белодробната артерия</li><li>Разширена на v. cava superior.</li></ul><li><strong>Нарушен кръвоток от a. pulmonalis:</strong></li><ul><li>Разширени хилуси</li><li><strong>Олигемия</strong> - намален съдов рисунък, увеличена просветляемост на паренхима</li><li>Огнищни сенки</li><li>Дисковидни ателектази - едностранни или двустранни</li></ul><li><strong>Белодробен инфаркт:</strong></li><ul><li>Неясен инфаркт тип \"гнездо\"</li><li><strong>Клиновидно уплътнение</strong> на белодробната тъкан.</li><li>Лобарна пневмония.</li><li>Оток на белите дробове, тип тумор.</li><li>Кръгли и овални сенки (3-4 cm) на сагиталните рентгенограми.</li></ul></ul><strong>2. Спирална Компютърна Томография (сКТ) / КТ-ангиография:</strong> <ul><li><u>Златен стандарт</u>. </li><li><strong>Директни белези</strong>: Пряко визуализиране на <strong>интралуминален дефект</strong> (тромб) под формата на хиподензна зона на фона на контрастирания съд. Тромбът може да е свободен или фиксиран към стената. При пълна обструкция луменът може да е нормален/дилатиран, но дистално няма контрастна материя. Метод на избор при суспектна белодробна тромбемболия е <strong>компютър-томографска ангиопулмография</strong>, комбинирана с изследване на вените на таза и долните крайници.</li><li><strong>Срокове</strong>: Образните изследвания трябва да бъдат извършени до <strong>1 час при масивен</strong> и до <strong>24 часа при немасивен БТЕ</strong>.</li></ul><strong>3. Белодробна ангиография:</strong> <ul><li>\"Златен стандарт\" (референтен метод), но е инвазивен. </li><li><p>Прилага се за пациенти, при които неинвазивната диагноза не носи информация.</p></li><li><p>Вероятно БТЕ с нормална ангиограма <strong>не се лекува с антикоагуланти</strong>.</p></li></ul><strong>4. Белодробна сцинтиграфия:</strong> <ul><li><strong>Неинвазивна и безопасна</strong> диагностична методика.</li><li>За <strong>перфузионна диагностика</strong> венозно се инжектират макроагрегати, маркирани с 99m-технеций (Тс). </li><li><strong>В случаите на оклузия на разклонения на белодробната артерия, капилярната част от периферно лежащото съдово русло няма да получи такива частици, което ще доведе до “студена” зона на съответните образи.</strong></li><li><strong>Класификация</strong>:</li><ul><li><strong>Отхвърляне на БТЕ </strong>(нормална).</li><li><strong>Доказан БТЕ</strong> (висока вероятност): Минимум един сегментен перфузионен дефект или перфузионен дефект от по-висок порядък  с локално нормална вентилация или нормална находка на рентгенография на гръден кош.</li><li><strong>Нито отхвърлен, нито доказан БТЕ</strong> (недиагностична).</li></ul></ul><p><strong>5. Компресионна ултрасонография на вени</strong></p><ul><li>Тъй като над 70% от пациентите с БТЕ имат дълбока венозна тромбоза (ДВТ), диагностицирането на <strong>проксимална ДВТ</strong> чрез ехография е достатъчно основание за започване на антикоагулантна терапия при суспектен БТЕ, без да се налагат допълнителни белодробни изследвания.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"color: rgb(88, 129, 87)\">Диагностичен алгоритъм при Масивна форма (Високорисков БТЕ)</h2><p>Алгоритъмът при пациенти със суспектен високорисков БЕ, т.е. представящи се с <strong>шок или хипотония</strong>, следва следната логика:</p><ol><li><strong>Суспектен БТЕ с Шок/Хипотония:</strong></li><ul><li>Първа стъпка е преценка дали може незабавно да се извърши <strong>КТ-ангиография</strong>.</li></ul><li><strong>Ако КТ е възможна веднага:</strong></li><ul><li>Прави се КТ-ангиография.</li><li>Положителен резултат -&gt; <strong>Специфично лечение за високорисков БТЕ</strong> (Тромболиза/Емболектомия).</li><li>Отрицателен резултат -&gt; Търсене на друга причина за шока.</li></ul><li><strong>Ако КТ НЕ е възможна веднага (пациентът е твърде нестабилен):</strong></li><ul><li>Извършва се <strong>Ехокардиография</strong> (до леглото на болния).</li></ul><li><strong>Резултат от Ехокардиографията:</strong></li><ul><li><strong>Липса на ДК обременяване:</strong> Изключва БТЕ като причина за хемодинамичната нестабилност -&gt; Търсене на друга причина.</li><li><strong>Наличие на ДК обременяване (недвусмислено):</strong></li><ul><li>Ако пациентът може да се стабилизира за транспорт -&gt; КТ-ангиография.</li><li>Ако пациентът е силно нестабилен -&gt; Приема се диагнозата и се започва <strong>Специфично лечение за високорисков БТЕ</strong>.</li></ul></ul></ol><p><img src=\"https://files.coursebook.lol/Coursebook%20Assets/2026-05-05/coursebook-assets/assets/%D0%91%D0%A2%D0%95-%D0%A4%D0%B8%D0%B35.png\" alt=\"БТЕ-Фиг5.png\" data-original-src=\"https://files.coursebook.lol/Coursebook%20Assets/2026-05-05/coursebook-assets/assets/%D0%91%D0%A2%D0%95-%D0%A4%D0%B8%D0%B35.png\" data-width=\"70\" style=\"max-width: 100%; height: auto; display: block; min-width: 300px; width: 606.9px\" data-broken-cleanup-bound=\"1\"></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"color: rgb(88, 129, 87)\">Диагноза на Дълбоката Венозна Тромбоза (ДВТ)</h2><ul><li><strong>Асимптомна ДВТ</strong> се наблюдава при над <strong>70%</strong> от пациентите с доказана симптомна БТЕ.</li><li>Диагностицирането на ДВТ с подозиран БТЕ е <strong>достатъчно доказателство</strong> за започване на антикоагулантна терапия без последващи изследвания.</li><li><strong>Контрастна венография</strong>: <strong>\"Златен стандарт\"</strong>, но се прилага рядко (инвазивна и трудно осъществявана при остро болни пациенти).</li><li><strong>Ултрасонография</strong>: <strong>Липса на пълна компресия на вената</strong> при прилагане на налягане е добре валидизиран критерий.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"color: rgb(88, 129, 87)\">Диференциална диагноза</h2><p>От значение е отчитането на <strong>клиничния фон</strong> (рискови фактори за БТЕ, предшестваща стенокардия, съдов инцидент) и <strong>характерът на болката</strong>. </p><p>При БТЕ тя е остра, <strong>постоянна</strong>, <strong>без ирадиация</strong>, свързана с дишането, а при инфаркт на миокарда - <strong>вълнообразна</strong>, <strong>с ирадиация</strong>, несвързана с дишането, има акроцианоза и няма кръвохрак и плеврално триене. </p><p><strong>От значение</strong> са и биохимичните изследвания (напр. тропонини, креатинкиназа за ИМ).</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"color: rgb(88, 129, 87)\">Лечение на масивната форма</h2><p>Основната цел при масивния БТЕ е бързото възстановяване на белодробния кръвоток и овладяване на острата циркулаторна недостатъчност, която е водеща причина за смърт.</p><h3 style=\"color: rgb(88, 129, 87)\">1. Овладяване на острата циркулаторна недостатъчност</h3><ul><li><strong>Кислородотерапия:</strong> Дозирана кислородотерапия през цялото време.</li><li><strong>Инотропни средства:</strong></li><ul><li>Използват се при пациенти с <strong>нисък сърдечен индекс</strong> и нормално или ниско кръвно налягане.</li><li>Препарати на избор: <strong>Добутамин</strong> и <strong>Допамин</strong>.</li><li>Ефект: Водят до значимо нарастване на сърдечния индекс без значима промяна в сърдечната честота.</li></ul><li><strong>Вливане на течности:</strong> Ползата е противоречива. Обемът <strong>не трябва да надхвърля 500 мл</strong>, за да не се претовари допълнително дясната камера.</li></ul><h3 style=\"color: rgb(88, 129, 87)\">2. Фибринолитична (Тромболитична) терапия</h3><p>Масивният БТЕ (протичащ с шок и хипотония) е абсолютно показание за фибринолитична терапия, освен ако няма абсолютни противопоказания. Тя може да се приложи до <strong>14-ия ден</strong> от началото на оплакванията.</p><p><strong>Схема на приложение:</strong></p><ol><li><strong>Хепарин:</strong> Започва се с болусна доза <strong>5 000 – 10 000 IU Нефракциониран хепарин (НФХ)</strong>.</li><li><strong>Фибринолитик:</strong> Основен препарат е <strong>rtPA - Alteplase (Actilyse)</strong>.</li><ul><li><strong>Стандартна доза:</strong> 100 mg i.v. за 2 часа (<strong>10 mg болус + 90 mg инфузия</strong>).</li><li><strong>При сърдечен арест:</strong> Един флакон Alteplase (<strong>50 mg</strong>) i.v. струйно.</li></ul><li><strong>Продължение:</strong> След тромболизата се продължава с НФХ в постоянна венозна инфузия (поне 1250 IU/h) за 5-7 дни под контрол на аРТТ (увеличаване 1,5 – 2,5 пъти).</li></ol><h3 style=\"color: rgb(88, 129, 87)\">3. Хирургично и интервенционално лечение</h3><p>Тези методи се прилагат при пациенти с масивен БТЕ, които са <strong>противопоказани за тромболитично лечение</strong> или при които фибринолизата е била <strong>неефективна</strong>.</p><ul><li><strong>Хирургична емболектомия:</strong> Оперативно отстраняване на ембола.</li><li><strong>Механична реперфузия (Катетърна терапия):</strong></li><ul><li>Поставяне на катетър в белодробната артерия.</li><li>Методи: <strong>Механична фрагментация</strong> на тромба, аспирация на тромби.</li><li><strong>Фармакомеханичен подход:</strong> Съчетава механична или ултразвукова фрагментация на тромба с <em>in situ</em> (локална) намалена доза тромболиза.</li></ul><li><strong>Венозни филтри (Vena Cava Filters):</strong> Поставят се в долната празна вена при пациенти, при които антикоагулацията е контраиндицирана или има рецидивиращ БТЕ въпреки лечението.</li></ul><h3 style=\"color: rgb(88, 129, 87)\">4. Пост-терапевтично поведение</h3><p>След овладяване на острото състояние се преминава към <strong>Перорална Антикоагулантна Терапия</strong>:</p><ul><li>Започва се възможно най-рано (първите 72 часа), застъпвайки се с хепарина.</li><li>Използват се <strong>Антагонисти на Витамин К (Acenocumarol)</strong>.</li><li>Цел: Постигане на <strong>INR 2.0 – 3.0</strong> в два последователни дни, след което директният антикоагулант (хепарин) се спира.</li><li>Алтернатива: Нови перорални антикоагуланти (Rivaroxaban, Apixaban), особено при пациенти без карцином.</li></ul><h2>Профилактика</h2><hr style=\"color: rgb(88, 129, 87)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><ul><li><strong>Първичната профилактика е предпочитана</strong>.</li><li><strong>Вторична профилактика&nbsp;</strong>се запазва за пациенти, при които първичната е контраиндицирана или неефективна.</li><li><strong>Пациентите, подлежащи на хирургична операция се подразделят на следните рискови групи:</strong></li></ul><table style=\"table-layout: fixed\"><tbody><tr><td style=\"width: 207px\"><strong><span style=\"color: rgb(88, 129, 87)\">Рискова група</span></strong></td><td style=\"width: 1012px\"><strong><span style=\"color: rgb(88, 129, 87)\">Характеристика</span></strong></td><td style=\"width: 452px\"><strong><span style=\"color: rgb(88, 129, 87)\">Риск за развитие без профилактика</span></strong></td><td style=\"width: 473px\"><strong><span style=\"color: rgb(88, 129, 87)\">Препоръка</span></strong></td></tr><tr><td style=\"width: 207px\"><strong>Нисък риск</strong></td><td style=\"width: 1012px\">Пациенти &lt; 40 г.<br>без рискови фактори<br>обща анестезия &lt; 30 мин<br>малка абдоминална или торакална операция</td><td style=\"width: 452px\">Проксимална ДВТ: 1,0%;<br>Фатална БТЕ: &lt; 0,01%.</td><td style=\"width: 473px\"><strong>Не се препоръчва профилактика</strong>.</td></tr><tr><td style=\"width: 207px\"><strong>Среден риск</strong></td><td style=\"width: 1012px\">Пациенти &gt; 40 г.<br>с нужда за обща анестезия &gt; 30 мин<br>и имат един или повече от изброените рискови фактори<br></td><td style=\"width: 452px\">Проксимална ДВТ: 2–10%;<br>Фатална БТЕ: 0,1–0,7%.</td><td style=\"width: 473px\"><strong>Дозиран спрямо килограмите НМХ</strong>.</td></tr><tr><td style=\"width: 207px\"><strong>Висок риск</strong></td><td style=\"width: 1012px\">Пациенти &gt; 40 г., подлежащи на<br>операция за малигнено заболяване или отропедична процедура на долен крайник <br>с обща анестезия &gt; 30 мин<br>имат инхибиторен дефицит или други рискови фактори</td><td style=\"width: 452px\">Проксимална ДВТ: 10–20%;<br>Фатална БТЕ: 1,0–5,0%.</td><td style=\"width: 473px\"><strong>Дозиран спрямо килограмите НМХ</strong>.</td></tr></tbody></table><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><br><br><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center; color: rgb(88, 129, 87)\">Тема 3: БТЕ – диагностичен алгоритъм и лечение на немасивната форма</h1><h2 style=\"color: rgb(88, 129, 87)\">Характеристика на немасивната и субмасивната форма</h2><p>Класификацията на белодробния тромбемболизъм (БТЕ) се базира на риска от ранна смърт и хемодинамичния статус на пациента. <strong>Немасивната форма</strong> се определя като <strong>невисокорисков БТЕ</strong>, тъй като при нея липсва клинична нестабилност (шок или хипотония).</p><h3 style=\"color: rgb(88, 129, 87)\">1. Немасивен БТЕ</h3><ul><li><strong>Хемодинамика:</strong> Протича <strong>без промяна в артериалното налягане</strong> (пациентът е стабилен).</li><li><strong>Симптоматика:</strong> Налице са предимно <strong>респираторни симптоми</strong> (задух, тахипнея, плеврална болка), със или без инфаркт на белия дроб.</li><li><strong>Степен на обструкция:</strong> Оклузията е под <strong>50%</strong> от артерия пулмоналис или засяга по-малки клонове с общ диаметър &lt; 50%.</li></ul><h3 style=\"color: rgb(88, 129, 87)\">2. Субмасивен БТЕ</h3><p>Това е специфична подгрупа от пациенти с немасивен БТЕ, които изискват повишено внимание.</p><ul><li><strong>Дефиниция:</strong> Пациенти с <strong>хемодинамична стабилност</strong> (без хипотония), но с наличие на <strong>ехокардиографски признаци на дяснокамерна (ДК) хипокинезия или дилатация</strong>.</li><li><strong>Значение:</strong> Тези белези показват остро дяснокамерно обременяване, което може да влоши прогнозата въпреки нормалното кръвно налягане.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"color: rgb(88, 129, 87)\">Диагностичен подход: Клинична оценка и Лаборатория</h2><p>При пациенти без шок и хипотония (суспектен невисокорисков БЕ) диагностичната стратегия цели да идентифицира пациентите, които нямат БТЕ и съответно нямат нужда от лечение, както и да потвърди диагнозата при тези, които имат.</p><h3 style=\"color: rgb(88, 129, 87)\">1. Оценка на клиничната вероятност</h3><p>В 90% от случаите съмнението възниква от клинични симптоми (диспнея, гръдна болка, синкоп). Въвеждането на <strong>\"оценка на клиничната вероятност\"</strong> позволява правилна интерпретация на изследванията.</p><p>Оценката се базира на наличието на:</p><ul><li><strong>Задух и/или тахипнея</strong>, с или без плевритен тип гръдна болка и/или хемоптое.</li><li><strong>Липса на друго състояние</strong>, което би могло да обясни оплакванията.</li><li><strong>Наличие на рискови фактори</strong>.</li></ul><p>Вероятността се класифицира като <strong>ниска</strong>, <strong>междинна</strong> или <strong>висока</strong>.</p><h3 style=\"color: rgb(88, 129, 87)\">2. Ролята на Д-димер в диагностиката</h3><p>Изследването на Д-димер е крайъгълен камък в диагностичния алгоритъм на немасивната форма, особено за <strong>изключване</strong> на заболяването.</p><ul><li><strong>Механизъм:</strong> Д-димерът е продукт, който се образува при лизиране на прекръстосан фибрин от плазмина. Той е <strong>директен маркер за фибринолитична активност</strong> и индиректен за тромбообразуване.</li><li><strong>Чувствителност и Специфичност:</strong></li><ul><li>Тестовете имат <strong>висока чувствителност (над 90%)</strong>. Това означава, че фалшиво отрицателните резултати са много редки.</li><li><strong>Специфичността е ниска</strong>. Повишение се наблюдава при множество други състояния: <strong>възпаление, тумори, напреднала възраст, бременност, постоперативни състояния</strong>. Поради това позитивният резултат има ниска предиктивна стойност (не доказва БТЕ).</li></ul><li><strong>Клинично значение:</strong></li><ul><li>Основната сила на теста е в неговата <strong>висока негативна предиктивна стойност</strong>.</li><li><strong>Отрицателен резултат (&lt; 500 ng/ml)</strong> може да <strong>изключи БТЕ</strong> с висока сигурност при пациенти с ниска или междинна вероятност. Това спестява необходимостта от скъпи и лъчеви натоварващи изследвания (като КТ).</li></ul></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"color: rgb(88, 129, 87)\">Образни изследвания при немасивна форма</h2><p>Ако клиничната оценка и/или Д-димерът насочват към БТЕ, се преминава към образни методи за потвърждение.</p><h3 style=\"color: rgb(88, 129, 87)\">1. Спирална Компютърна Томография (сКТ) / КТ-ангиография</h3><ul><li><strong>Основен метод:</strong> Това е метод на избор (златен стандарт в съвременната практика) за немасивни форми.</li><li><strong>Находка:</strong> Позволява пряко визуализиране на тромба като <strong>хиподензна зона (интралуминален дефект)</strong> в контрастирания съд.</li><li><strong>Комбиниран подход:</strong> Често се прави КТ-ангиопулмография, комбинирана с изследване на вените на таза и долните крайници (КТ-венография).</li></ul><h3 style=\"color: rgb(88, 129, 87)\">2. Белодробна сцинтиграфия (Вентилационно-перфузионна)</h3><ul><li><strong>Приложение:</strong> Неинвазивен и безопасен метод, алтернатива при противопоказания за КТ (напр. бъбречна недостатъчност, алергия към контраст).</li><li><strong>Критерии за диагноза:</strong></li><ul><li><strong>Висока вероятност (Доказан БТЕ):</strong> Минимум един сегментен перфузионен дефект (липса на кръвоснабдяване) при запазена вентилация в същата зона (<strong>mismatch</strong>).</li><li><strong>Нормална сцинтиграфия:</strong> Отхвърля БТЕ.</li></ul></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"color: rgb(88, 129, 87)\">Диагностичен алгоритъм (Стъпка по стъпка)</h2><p>Алгоритъмът при пациенти <strong>без шок или хипотония</strong> (невисокорисков БТЕ) зависи от първоначалната клинична преценка:</p><h3 style=\"color: rgb(88, 129, 87)\">А. При Ниска или Междинна клинична вероятност</h3><ol><li><strong>Първа стъпка:</strong> Изследване на <strong>Д-димер</strong>.</li><li><strong>Резултат от Д-димер:</strong></li><ul><li><strong>Отрицателен (&lt; 500 ng/ml):</strong> <strong>Изключва БТЕ</strong>. Не се налага лечение. Диагностичният процес за БТЕ приключва.</li><li><strong>Положителен (&gt; 500 ng/ml):</strong> Не доказва БТЕ, но изисква потвърждение.</li></ul><li><strong>Втора стъпка (при положителен Д-димер):</strong> Извършва се <strong>КТ-ангиография</strong>.</li><ul><li><strong>КТ отрицателна:</strong> Няма БТЕ. Не се лекува.</li><li><strong>КТ положителна:</strong> <strong>Потвърден БТЕ</strong> -&gt; Започва се лечение.</li></ul></ol><h3 style=\"color: rgb(88, 129, 87)\">Б. При Висока клинична вероятност</h3><ol><li><strong>Първа стъпка:</strong> <strong>Директно КТ-ангиография</strong>.</li><ul><li><em>Забележка:</em> При висока вероятност Д-димерът не се изследва, защото дори да е отрицателен, той не би бил достатъчно надежден да отхвърли диагнозата при толкова силни клинични данни.</li></ul><li><strong>Резултат от КТ:</strong></li><ul><li><strong>КТ положителна:</strong> Потвърден БТЕ -&gt; Лечение.</li><li><strong>КТ отрицателна:</strong> Ако въпреки отрицателната КТ съмнението остава много високо, може да се обсъдят допълнителни методи (напр. ангиография или сцинтиграфия), но обикновено БТЕ се отхвърля.</li></ul></ol><p><img src=\"https://files.coursebook.lol/Coursebook%20Assets/2026-05-05/coursebook-assets/assets/%D0%91%D0%A2%D0%95-%D0%A4%D0%B8%D0%B36.png\" alt=\"БТЕ-Фиг6.png\" data-original-src=\"https://files.coursebook.lol/Coursebook%20Assets/2026-05-05/coursebook-assets/assets/%D0%91%D0%A2%D0%95-%D0%A4%D0%B8%D0%B36.png\" data-width=\"50\" style=\"max-width: 100%; height: auto; display: block; min-width: 300px; width: 433.5px\" data-broken-cleanup-bound=\"1\"></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"color: rgb(88, 129, 87)\">Диагноза на Дълбоката Венозна Тромбоза (ДВТ)</h2><ul><li><strong>Асимптомна ДВТ</strong> се наблюдава при над <strong>70%</strong> от пациентите с доказана симптомна БТЕ.</li><li>Диагностицирането на ДВТ с подозиран БТЕ е <strong>достатъчно доказателство</strong> за започване на антикоагулантна терапия без последващи изследвания.</li><li><strong>Контрастна венография</strong>: <strong>\"Златен стандарт\"</strong>, но се прилага рядко (инвазивна и трудно осъществявана при остро болни пациенти).</li><li><strong>Ултрасонография</strong>: <strong>Липса на пълна компресия на вената</strong> при прилагане на налягане е добре валидизиран критерий.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"color: rgb(88, 129, 87)\">Диференциална диагноза</h2><p>От значение е отчитането на <strong>клиничния фон</strong> (рискови фактори за БТЕ, предшестваща стенокардия, съдов инцидент) и <strong>характерът на болката</strong>. </p><p>При БТЕ тя е остра, <strong>постоянна</strong>, <strong>без ирадиация</strong>, свързана с дишането, а при инфаркт на миокарда - <strong>вълнообразна</strong>, <strong>с ирадиация</strong>, несвързана с дишането, има акроцианоза и няма кръвохрак и плеврално триене. </p><p><strong>От значение</strong> са и биохимичните изследвания (напр. тропонини, креатинкиназа за ИМ).</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"color: rgb(88, 129, 87)\">Лечение на немасивната форма</h2><p>Терапията на немасивния БТЕ е медикаментозна (антикоагулантна). Тромболиза (фибринолиза) <strong>не се препоръчва</strong> рутинно за пациенти без хипотония, поради риск от кървене, освен в редки случаи на влошаване.</p><h3 style=\"color: rgb(88, 129, 87)\">1. Начална парентерална антикоагулация</h3><p>Лечението трябва да започне възможно най-бързо. Предпочитат се <strong>Нискомолекулни хепарини (НМХ)</strong> или <strong>Фондапаринукс</strong> пред Нефракционирания хепарин (НФХ), тъй като имат по-предсказуем ефект и не изискват мониториране на aPTT.</p><ul><li><strong>Нискомолекулни хепарини (НМХ):</strong> Дозират се спрямо телесното тегло (подкожно).</li><ul><li><strong>Nadroparin (Fraxiparine)</strong></li><li><strong>Enoxaparin (Clexane)</strong></li><li><strong>Dalteparin (Fragmin)</strong></li><li><em>Контрол:</em> Препоръчва се следене на тромбоцитите поради риск от хепарин-индуцирана тромбоцитопения.</li></ul><li><strong>Fondaparinux (Arixtra):</strong> Селективен инхибитор на фактора Ха. Ефективна алтернатива.</li><li><strong>Нефракциониран хепарин (НФХ):</strong> Използва се по-рядко при немасивни форми (освен при тежка бъбречна недостатъчност). Дозировка: болус 5 000 – 10 000 IU, последван от инфузия.</li></ul><h3 style=\"color: rgb(88, 129, 87)\">2. Перорална Антикоагулантна Терапия (ПОАТ)</h3><p>Целта е продължителна профилактика на рецидивите.</p><p><strong>А. Антагонисти на Витамин К:</strong></p><ul><li>Основен препарат: <strong>Acenocumarol</strong>.</li><li><strong>Начало:</strong> Започва се <strong>възможно най-рано (още в първите 72 часа)</strong>, едновременно с парентералния хепарин (застъпване).</li><li><strong>Прицелни стойности:</strong> Целта е достигане на <strong>INR между 2.0 и 3.0</strong>.</li><li><strong>Спиране на хепарина:</strong> Парентералният антикоагулант се спира, когато INR е в терапевтични граници (2.0–3.0) в <strong>два последователни дни</strong>.</li><li><em>Внимание:</em> При висока начална доза Sintrom има риск от парадоксален хиперкоагулационен ефект (некроза), затова е важно застъпването с хепарин.</li></ul><p><strong>Б. Нови перорални антикоагуланти:</strong></p><ul><li>Представители: <strong>Rivaroxaban (Xarelto)</strong>, <strong>Apixaban (Eliquis)</strong>.</li><li>Те са добра алтернатива на VKA. При тях може да се използва схема с начална по-висока доза, без задължително предварително лечение с хепарин (за Rivaroxaban и Apixaban) или след кратък курс хепарин (за Edoxaban).</li></ul><h3 style=\"color: rgb(88, 129, 87)\">3. Лечение при специфични групи пациенти</h3><ul><li><strong>Пациенти с активен карцином:</strong></li><ul><li>Препоръчват се <strong>Нискомолекулни хепарини (НМХ)</strong> за продължително лечение (поне за <strong>6 месеца</strong>). Те са по-ефективни и безопасни от Acenocoumarol при онкоболни.</li><li>Алтернатива: Edoxaban и Rivaroxaban (освен при рак на гастро-интестиналния тракт поради риск от кървене).</li></ul><li><strong>Антифосфолипиден синдром:</strong></li><ul><li>Препоръчват се <strong>само Витамин К антагонисти (Acenocoumarol)</strong>. Новите антикоагуланти не са показани.</li></ul></ul><h3 style=\"color: rgb(88, 129, 87)\">4. Продължителност на лечението</h3><p>Продължителността зависи от причината за емболията (рисковия фактор):</p><ul><li><strong>3 месеца:</strong> При наличие на <strong>временен/реверзибелен</strong> рисков фактор (напр. операция, травма, гипс).</li><li><strong>Поне 6 месеца:</strong> При <strong>идиопатичен БТЕ</strong> (неизвестна причина).</li><li><strong>Постоянно (доживот):</strong></li><ul><li>При <strong>рецидивиращ БТЕ</strong>.</li><li>При наличие на <strong>персистиращи рискови фактори</strong> (напр. активен рак, антифосфолипиден синдром).</li></ul></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"color: rgb(88, 129, 87)\">Венозни филтри (Vena Cava Filters)</h2><p>При немасивна форма поставянето на филтър в долната празна вена се обсъжда само в краен случай:</p><ol><li>Когато антикоагулацията е <strong>абсолютно противопоказана</strong> (напр. активно кървене).</li><li>При <strong>рецидивиращ БТЕ</strong> въпреки адекватната антикоагулантна терапия.</li></ol><p><strong>Риск:</strong> Филтрите могат да увеличат риска от дълбока венозна тромбоза (ДВТ) в дългосрочен план.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"color: rgb(88, 129, 87)\">Профилактика</h2><ul><li><strong>Първичната профилактика е предпочитана</strong>.</li><li><strong>Вторична профилактика&nbsp;</strong>се запазва за пациенти, при които първичната е контраиндицирана или неефективна.</li><li><strong>Пациентите, подлежащи на хирургична операция се подразделят на следните рискови групи:</strong></li></ul><table><tbody><tr><td><strong><span style=\"color: rgb(88, 129, 87)\">Рискова група</span></strong></td><td><span style=\"color: rgb(88, 129, 87)\"><strong>Характеристика</strong></span></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Риск за развитие без профилактика</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Препоръка</span></strong></td></tr><tr><td><strong>Нисък риск</strong></td><td>Пациенти &lt; 40 г.<br>без рискови фактори<br>обща анестезия &lt; 30 мин<br>малка абдоминална или торакална операция</td><td>Проксимална ДВТ: 1,0%;<br>Фатална БТЕ: &lt; 0,01%.</td><td><strong>Не се препоръчва профилактика</strong>.</td></tr><tr><td><strong>Среден риск</strong></td><td>Пациенти &gt; 40 г.<br>с нужда за обща анестезия &gt; 30 мин<br>и имат един или повече от изброените рискови фактори<br></td><td>Проксимална ДВТ: 2–10%;<br>Фатална БТЕ: 0,1–0,7%.</td><td><strong>Дозиран спрямо килограмите НМХ</strong>.</td></tr><tr><td><strong>Висок риск</strong></td><td>Пациенти &gt; 40 г., подлежащи на<br>операция за малигнено заболяване или отропедична процедура на долен крайник <br>с обща анестезия &gt; 30 мин<br>имат инхибиторен дефицит или други рискови фактори</td><td>Проксимална ДВТ: 10–20%;<br>Фатална БТЕ: 1,0–5,0%.</td><td><strong>Дозиран спрямо килограмите НМХ</strong>.</td></tr></tbody></table><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><br><br><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center; color: rgb(88, 129, 87)\">Тема 4: Рак на белия дроб – рискови фактори, морфологична класификация, клиника и диагностичен алгоритъм</h1><h2 style=\"color: rgb(88, 129, 87)\">Епидемиология</h2><p>Според данни на СЗО, карциномът на трахеята, бронхите и белите дробове е водеща причина за смърт в Европейския регион. В България ракът на белите дробове е <strong>най-честото злокачествено заболяване при мъжете</strong> (19.3%) и пето по честота при жените. Смъртността от него надвишава тази, причинена от рак на млечната жлеза, дебелото черво и простатата, взети заедно.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"color: rgb(88, 129, 87)\">Рискови фактори</h2><p>Основна роля играят фактори на околната среда и генетични предиспозиции:</p><ul><li><strong>Тютюнопушене:</strong> Основен рисков фактор. Рискът се увеличава с броя на цигарите и пакето-годините. Отказът от тютюнопушене на всяка възраст значително намалява риска.</li><li><strong>Пасивно тютюнопушене.</strong></li><li><strong>Газ Радон:</strong> Продуцира се от естествения разпад на уран в почвата, скалите и водата. Навлиза в сградите чрез пукнатини в основите.</li><li><strong>Професионални канцерогени:</strong> Излагане на <strong>азбест</strong>, арсен, хром, никел, кадмий и петролни продукти (особено опасно при пушачи).</li><li><strong>Хронични белодробни заболявания:</strong> Белези от туберкулоза, хроничен бронхит, ХОББ.</li><li><strong>Фамилна анамнеза:</strong> Относителният риск е <strong>2.4 пъти по-голям</strong> за индивиди с роднини с болестта (наследствен генетичен фактор при около 8% от случаите). Полиморфизми на хромозома 6 и 15 се свързват с повишен риск.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"color: rgb(88, 129, 87)\">Патогенеза</h2><p>Развитието е вероятно в резултат на въздействие върху бронхиалния епител на различни карциногенни вещества, активиращи реакции, които предизвикват степенни, до мутагенни процеси и неконтролируемо размножаване на атипични клетки.</p><strong>Генни мутации</strong>:<br><ul><li><strong>EGFR (Рецептор на епидермалния растежен фактор):</strong> Играе роля в регулирането на клетъчното размножаване, апоптозата, ангиогенезата и туморната инвазия. Генетичните мутации, водещи до дисрегулация му, обикновено се наблюдават при <strong>недребоклетъчен белодробен карцином</strong>, което обяснява използването на <strong>EGFR-инхибитори</strong> при лечението на заболяването.</li><li>Мутация в <strong>EML4-ALK тирозинкиназа</strong> се среща в 4% от недребноклетъчните белодробни карциноми.</li><li>Мутация в <strong>K-ras прото-онкогени</strong> е отговорна за 10-30% от белодробните аденокарциноми.</li></ul><strong>Наследствен генетичен фактор:</strong>&nbsp;<br><ul><li>Приблизително <strong>8%</strong> от случаите, с относителен риск <strong>2.4 пъти по-голям</strong> за индивиди с роднини с болестта.  </li><li>Полиморфизмите на хромозома 6 и 15 са свързани с повишен риск.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"color: rgb(88, 129, 87)\">Класификация</h2><h3 style=\"color: rgb(88, 129, 87)\">1. Класификация по Локализация</h3><p>Определя достъпността за диагностика (ендоскопска или перкутанна):</p><ul><li><strong>Централен:</strong> Локализиран в главни, лобарни и сегментни бронхи. Достъпен е ендоскопски (чрез бронхоскопия). Може да бъде ендобронхиоларен или перибронхиоларен.</li><li><strong>Периферен:</strong> Разположен дистално от сегментните бронхи. Трудно се доказва ендоскопски, но е достъпен за трансторакална аспирационна биопсия (ТТАБ), тъй като често е до гръдната стена.</li><li><strong>Върхов (Тумор на Pancoast-Tobias):</strong> Особена форма, разположена във върха на белия дроб.</li></ul><p><img src=\"https://files.blackboard.lol/PCarcinoma-Figure1.png\" alt=\"https://files.blackboard.lol/PCarcinoma-Figure1.png\" data-original-src=\"https://files.blackboard.lol/PCarcinoma-Figure1.png\" data-width=\"50\" style=\"max-width: 100%; height: auto; display: block; min-width: 300px; width: 273.5px\" data-broken-cleanup-bound=\"1\"></p><blockquote><p>Фигура 1. Схематично представяне на топографията (десен бял дроб) и усложненията (ляв бял дроб) при белодробен карцином. \nА-върхов (Панкоаст-Тобиас); В-периферен карцином; С-пневмонична форма; D-централен карцином; \n1-емфизем; 2-ателектаза; 3-плеврален излив; 4-бронхиектазии.</p></blockquote><h3 style=\"color: rgb(88, 129, 87)\">2. Морфологична (Клинична) Класификация</h3><p>Тази класификация е критична за избора на поведение и лечение.</p><h4 style=\"color: rgb(88, 129, 87)\">А. Недребноклетъчен карцином (НДК)</h4><p>Съставлява <strong>75-80%</strong> от случаите на белодробен карцином.</p><ul><li><strong>Плоскоклетъчен карцином:</strong></li><ul><li><strong>Най-честият</strong> хистологичен тип.</li><li>Силно свързан с тютюнопушенето.</li><li>Локализира се <strong>централно</strong>, до големите въздухоносни пътища.</li><li><p>Обикновено се представя с<strong> плътно хомогенно засенчване </strong>на пулмографията, но може да разпадне и да изглежда рентгенологично като абсцес</p>.</li><li>Често се представя с <strong>хиперкалциемия</strong>.</li></ul><li><strong>Аденокарцином:</strong></li><ul><li><p><strong>Не е задължително свързан</strong> с тютюнопушенето.</p><br></li><li>Развива се от алвеоларните и бронхиоларните жлезни клетки.</li><li>Типично <strong>периферно</strong> разположена маса.</li><li><p>Може да бъде <strong>първичен</strong> белодробен или <strong>вторичен</strong> от други места, особено когато е налице инфилтрация на плеврата и последващ <strong>плеврален излив</strong>.</p></li></ul><li><strong>Алвеоларен клетъчен карцином:</strong></li><ul><li>Рядък вид. Може да причини <strong>бронхорея</strong> (обилно отделяне на спутум) и инфилтративни засенчвания.</li></ul><li><strong>Други типове:</strong> Едроклетъчен карцином, Аденосквамозен карцином, Саркоматоиден карцином.</li></ul><h4 style=\"color: rgb(88, 129, 87)\">Б. Дребноклетъчен карцином (ДКК)</h4><p>Съставлява <strong>20-25%</strong> от случаите.</p><ul><li><strong>Изключително агресивен:</strong> Нелекуван има средна преживяемост от 6 седмици.</li><li>Само в 1% се среща при непушачи.</li><li><strong>Локализация:</strong> В 90-95% е <strong>централно</strong> разположен (до лобарен или главен бронх).</li><li><strong>Метастазиране:</strong> Обикновено е метастазирал по време на диагнозата (хематогенни разсейки в черен дроб, кости, костен мозък, главен мозък, надбъбреци).</li><li><strong>Лечение:</strong> Хирургията обикновено не е подходяща; туморът е химио- и радиочувствителен.</li><li>Често се асоциира с <strong>Паранеопластични синдроми</strong> (напр. Синдром на Иценко-Кушинг).</li></ul><h4 style=\"color: rgb(88, 129, 87)\">В. Допълнително типизиране</h4><ul><li><strong>Хистопатологична степен (Grading):</strong> От G1 до G4 (високо, умерено, нискодиференциран и недиференциран).</li><li><strong>Молекулярно-патологично типизиране:</strong>&nbsp;</li><ul><li>Тестване за <strong>EGFR-мутации</strong> и <strong>ALK-пренареждане</strong>.&nbsp;</li><li>Препоръчва се при <strong>недребноклетъчен карцином</strong> (особено аденокарцином) в напреднал стадий, тъй като наличието им позволява таргетна терапия.</li><li><p>Таргетната терапия е <strong>по-ефективна и по-добре поносима</strong> от стандартната химиотерапия при наличие на тези мутации.</p><br></li><li><p>Тестването е <strong>критично</strong> за избор на лечение при <strong>напреднало заболяване (IIIB-IV)</strong>, тъй като ранните стадии (I и II) се лекуват предимно хирургично.</p></li></ul></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"color: rgb(88, 129, 87)\">Клинична картина</h2><p>В до <strong>25%</strong> от случаите заболяването протича <strong>безсимптомно</strong>. Клиничните прояви се делят на локални, метастатични, паранеопластични и неспецифични.</p><h3 style=\"color: rgb(88, 129, 87)\">1. Локални туморни ефекти</h3><ul><li><strong>Кашлица:</strong> Постоянна кашлица или промяна в характера на хроничната („пушаческа“) кашлица.</li><li><strong>Хемоптиза:</strong> Кръвохрачене, типично описвано с вид на <strong>„малиново желе“</strong>.</li><li><strong>Гръдна болка:</strong> При ангажиране на плеврата или гръдната стена.</li><li><strong>Пневмония/Ателектаза:</strong> Нерезорбираща се пневмония или лобарна ателектаза вследствие на бронхиална обструкция.</li><li><strong>Диспнея:</strong> Необясним задух поради бронхиално стеснение.</li><li><strong>Дисфония/Афония:</strong> Промяна или загуба на гласа при туморна инвазия на левия <strong>n. laryngeus recurrens</strong>.</li><li><strong>Дисфагия:</strong> Затруднено гълтане при компресия на хранопровода.</li><li><strong>Плеврален излив:</strong> При директна инвазия или метастази в плеврата.</li><li><strong>Високо стоящ диафрагмален купол:</strong> При парализа на n. phrenicus.</li></ul><h3 style=\"color: rgb(88, 129, 87)\">2. Специфични синдроми</h3><ul><li><strong>Синдром на Pancoast-Tobias (Върхов тумор):</strong> Туморът във върха на белия дроб може да обхване шийната част на симпатикуса, брахиалния плексус и ребрата.</li><ul><li><strong>Симптоми:</strong> Болки в рамото и слабост на малките мускули на ръката.</li><li><strong>Синдром на Claude Bernard-Horner:</strong> Птоза, миоза и енофталм (поради ангажиране на симпатикуса).</li></ul></ul><h3 style=\"color: rgb(88, 129, 87)\">3. Метастатични ефекти</h3><ul><li><strong>Лимфаденопатия:</strong> Шийна или супраклавикуларна (в 30% от болните).</li><li><strong>Хепатомегалия:</strong> Чернодробни метастази.</li><li><strong>Костни болки/фрактури:</strong> Костни метастази.</li><li><strong></strong><p><strong>Неврологична симптоматика:</strong> Мозъчни метастази (главоболие, гадене, огнищен дефицит).</p></li><li><strong>Синдром на горна празна вена:</strong> Оток на лицето и шията, разширени вени на гръдния кош (при компресия от медиастинални лимфни възли).</li><li><p><strong>Дисфагия:</strong> Вследствие на компресия от големи медиастинални лимфни възли.</p><br></li></ul><h3 style=\"color: rgb(88, 129, 87)\">4. Паранеопластични синдроми</h3><p>Дължат се на продукция на хормонподобни субстанции от тумора.</p><ul><li><strong>При Дребноклетъчен карцином (ДКК):</strong> Най-чест е <strong>Синдром на Иценко-Кушинг</strong> (ектопична секреция на АСТН) и синдром на неадекватна секреция на АДХ.</li><li><strong>При Недребноклетъчен карцином (НДК):</strong> Най-честа е <strong>хиперкалциемията</strong> (продукция на субстанция, подобна на паратироидния хормон).</li></ul><h3 style=\"color: rgb(88, 129, 87)\">5. Неспецифични симптоми</h3><p>Кахексия, слабост, умора, депресия.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"color: rgb(88, 129, 87)\">Диагностичен алгоритъм</h2><p><strong>Кога е необходимо да се проведат изследвания:</strong></p><ul><li>Нововъзникнала персистираща кашлица или влошаване на съществуваща кашлица.</li><li>Кръвохрак.</li><li>Персистиращи „бронхити\" или чести респираторни инфекции.</li><li>Гръдна болка.</li><li>Необяснима загуба на тегло и/или умора.</li><li>Диспнея или хриптене.</li><li>Анамнеза за излагане на тютюнопушене и други рискови фактори.</li><li><p>Съмнение за белодробен карцином трябва да има при всеки пациент над 40 г. (особено пушач) с персистираща кашлица, хемоптиза или нерезорбираща се пневмония.</p></li></ul><h3 style=\"color: rgb(88, 129, 87)\">1. Лабораторни изследвания</h3><ul><li>Кръвна картина, биохимия (чернодробни показатели, калций, натрий), хемостазеология.</li><li><strong>Цитологично изследване на храчка:</strong> Търсене на туморни клетки.</li><li><p><strong>Изследване на плеврален пунктат </strong>(биохимично, цитологично).</p></li><li><p><strong>Трансторакална тънкоиглена аспирационна биопсия (ТТАБ)</strong> под КТ контрол при периферно разположени тумори (цитилогично, хистологично изследване).</p><br></li><li><p><strong>Биопсия на периферен лимфен възел</strong> (хистологично изследване).</p><br></li><li><p><strong>Туморни маркери</strong>: Карциноембрионален антиген (СЕА), антидиуретичен хормон (АДХ) и др. (спомагателни).</p></li></ul><h3 style=\"color: rgb(88, 129, 87)\">2. Образни изследвания</h3><ul><li><strong>Рентгенография на бели дробове (Фас и Профил):</strong> Първи метод. <p>За оценка на местоположението, ангажимента на плеврата, деструкция на ребра, интраторакални метастази, медиастинална лимфаденопатия.</p></li><ul><li><p>Незабавна при пациенти с кръвохрак и п</p><p>репоръчителна при следните клинични симптоми, персистиращи повече от три седмици: кашлица или промяна в характера на хроничната кашлица, неясна гръдна болка, загуба на тегло, костни болки, задух.</p><br></li></ul><li><strong>Компютърна томография на гръден кош и горен абдомен:</strong> <p>За оценка на големината, разположението на тумора и неговите метастази. <strong>КТ е задължителна стъпка</strong> за диагноза и TNM стадиране.</p></li><li><strong>Магнитно-резонансна томография:</strong> <p>Метод на избор за доказване/отхвърляне на метастатични лезии в <strong>кости, мозък и надбъбреци</strong>. Използва се и за оценка на Т- и N-стадий при тумор тип Pancoast.</p></li><li><strong>Позитрон емисионна томография (ПЕТ/КТ):</strong>&nbsp;</li><ul><li><p>Мултимодална техника (KT+PET).&nbsp;</p></li><li><p>Сканирането с глюкозен аналог (FDG) се основава на засилен <strong>глюкозен метаболизъм</strong> в туморните клетки и представлява анатомично-метаболитен изобразяващ метод.</p></li><li><p>Докато КТ ни представя анатомичните структури, ПЕТ измерва метаболитната активности и функцията на тъканите.</p></li><li><p>Уместна при <strong>всички пациенти с НДК</strong> за търсене на далечни метастази преди избор на лечение.</p></li></ul></ul><h3 style=\"color: rgb(88, 129, 87)\">3. Ендоскопски и Инвазивни методи (За морфологична диагноза)</h3><ul><li><strong>Фибробронхоскопия:</strong> Основен метод за централни тумори. Позволява:</li><ul><li>Оглед и биопсия (щипкова, четкова).</li><li>Бронхоалвеоларен лаваж.</li><li>Трансбронхиална пункционна биопсия (при перибронхиален растеж).</li><li><p>Трансбронхиална белодробна биопсия (при дисеминирани лезии).</p><br></li></ul><li><strong>Автофлуоресцентна бронхоскопия:</strong>&nbsp;</li><ul><li><p>При осветяване със синя светлина нормалната лигавица изглежда зелена, патологичните зони – морави. </p></li><li><p>Препоръчва се при тежка дисплазия, карцином <em>in situ</em> или суспектни туморни клетки в храчка при нормална образна диагностика.</p></li></ul><li><strong>Ендобронхиален ултразвук (ЕБУЗ) / Езофагеален ултразвук (ЕУЗ):</strong> За биопсия на увеличени медиастинални лимфни възли (стадиране).</li><li><strong>Трансторакална тънкоиглена аспирационна биопсия (ТТАБ):</strong> Под КТ или ултразвуков контрол. Прилага се при <strong>периферно</strong> разположени тумори.</li><li><strong>Видеоасистирана торакоскопия (VATS) и Медиастиноскопия:</strong> Хирургични методи за биопсия и стадиране.</li><li><strong>Торакоцентеза:</strong> Изследване на плеврален пунктат (цитология/биохимия) при наличие на излив.</li></ul><p><img src=\"https://files.coursebook.lol/Coursebook%20Assets/2026-05-05/coursebook-assets/assets/carcinom-figure2.png\" alt=\"carcinom-figure2.png\" data-original-src=\"https://files.coursebook.lol/Coursebook%20Assets/2026-05-05/coursebook-assets/assets/carcinom-figure2.png\" data-width=\"50\" style=\"max-width: 100%; height: auto; display: block; min-width: 300px; width: 620px\" data-broken-cleanup-bound=\"1\"><br><br></p><h3 style=\"color: rgb(88, 129, 87)\">4. Стадиране (TNM)</h3><p>След доказване на диагнозата се извършва стадиране по TNM системата (T-тумор, N-лимфни възли, M-метастази), което е определящо за прогнозата и терапевтичното поведение.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"color: rgb(88, 129, 87)\">Диференциална Диагноза</h2><ul><li>Туберкулоза</li><li>Саркоидоза</li><li>Силикоза</li><li>Пневмонии</li><li>Белодробен абсцес</li><li>Гъбични инфекции</li><li>Белодробни кисти</li><li>Бронхиектазии</li><li>Метастази с извънбелодробен произход</li></ul><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><br><br><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center; color: rgb(88, 129, 87)\">Тема 5: Рак на белия дроб – стадиране и принципи на лечение</h1><h2 style=\"color: rgb(88, 129, 87)\">TNM Стадиране</h2><p>Стадирането на белодробния карцином корелира с прогнозата и е определящо за избора на терапевтично поведение. То се извършва по системата <strong>TNM</strong> (Tumor-Node-Metastasis).</p><h3 style=\"color: rgb(88, 129, 87)\">T (Първичен тумор)</h3><ul><li><strong>Tx:</strong> Първичният тумор не може да се оцени или е доказан само с наличие на туморни клетки в храчка/бронхиален секрет при негативни образни изследвания и бронхоскопия.</li><li><strong>T0:</strong> Липсва първичен тумор.</li><li><strong>Tis:</strong> Карцином <em>in situ</em>.</li><li><strong>T1:</strong> Тумор <strong>≤ 3 cm</strong>, заобиколен от бял дроб или висцерална плевра, не по-проксимално от дялов бронх.</li><ul><li><strong>T1a(mi):</strong> Минимално инвазивен аденокарцином.</li><li><strong>T1a:</strong> Тумор <strong>≤ 1 cm</strong>.</li><li><strong>T1b:</strong> Тумор <strong>&gt; 1 но ≤ 2 cm</strong>.</li><li><strong>T1c:</strong> Тумор <strong>&gt; 2 но ≤ 3 cm</strong>.</li></ul><li><strong>T2:</strong> Тумор <strong>&gt; 3 но ≤ 5 cm</strong> или тумор с някоя от следните характеристики: нахлува във висцерална плевра; засяга главен бронх (без карината); ателектаза/обструктивен пневмонит до хилуса.</li><ul><li><strong>T2a:</strong> Тумор <strong>&gt; 3 но ≤ 4 cm</strong>.</li><li><strong>T2b:</strong> Тумор <strong>&gt; 4 но ≤ 5 cm</strong>.</li></ul><li><strong>T3:</strong> Тумор <strong>&gt; 5 cm, но ≤ 7 cm</strong> или свързан с отделни туморни възли в същия дял; или тумор, директно инвазиращ: гръдна стена (вкл. париетална плевра и тумори на горна бразда/Pancoast), френичен нерв, париетален перикард.</li><li><strong>T4:</strong> Тумор <strong>&gt; 7 cm</strong> или свързан с отделен туморен възел(и) в различен лоб от този на първичния тумор; или инвазиращ: сърце, големи съдове, трахея, възвратен ларингеален нерв, хранопровод, тяло на прешлен или бифуркация на трахея (карина).</li></ul><h3 style=\"color: rgb(88, 129, 87)\">N (Регионални лимфни възли)</h3><ul><li><strong>Nx:</strong> Регионалните лимфни възли не могат да се оценят.</li><li><strong>N0:</strong> Без метастаза в регионален възел.</li><li><strong>N1:</strong> Метастаза в <strong>ипсилатерални</strong> (от същата страна) перибронхиални и/или хилусни лимфни възли и интрапулмонарни възли.</li><li><strong>N2:</strong> Метастаза в <strong>ипсилатерален медиастинален</strong> и/или лимфен възел под бифуркацията на трахеята.</li><li><strong>N3:</strong> Метастаза в <strong>контралатерални</strong> (срещуположни) медиастинални, контралатерални хилусни, ипсилатерални или контралатерални скаленни или супраклавикуларни лимфни възли.</li></ul><h3 style=\"color: rgb(88, 129, 87)\">M (Далечна метастаза)</h3><ul><li><strong>M0:</strong> Без далечна метастаза.</li><li><strong>M1:</strong> Наличие на далечна метастаза.</li><ul><li><strong>M1a:</strong> Отделен туморен възел в контралатерален дял; тумор с плеврален или перикарден възел; малигнен плеврален или перикарден излив.</li><li><strong>M1b:</strong> Единична екстраторакална метастаза.</li><li><strong>M1c:</strong> Множествени екстраторакални метастази в един или повече органи.</li></ul></ul><h3>Групиране по стадии</h3><p><strong>Ранни стадии:</strong></p><ul><li><strong>Окултен рак</strong>: Tx, N0, M0</li><li><strong>Стадий 0</strong>: Tis, N0, M0</li></ul><p><strong>Стадий I (Локализиран тумор)</strong></p><ul><li><strong>Стадий IA1</strong>: T1(mi) или T1a, N0, M0</li><li><strong>Стадий IA2</strong>: T1b, N0, M0</li><li><strong>Стадий IA3</strong>: T1c, N0, M0</li><li><strong>Стадий IB</strong>: T2a, N0, M0</li></ul><p><strong>Стадий II (Локално напреднал)</strong></p><ul><li><strong>Стадий IIA</strong>: T2b, N0, M0</li><li><strong>Стадий IIB</strong>:</li><ul><li>T1a-c, N1, M0</li><li>T2a, N1, M0</li><li>T2b, N1, M0</li><li>T3, N0, M0</li></ul></ul><p><strong>Стадий III (Регионално разпространение)</strong></p><ul><li><strong>Стадий IIIA</strong></li><ul><li>T1a-c, N2, M0</li><li>T2a-b, N2, M0</li><li>T3, N1, M0</li><li>T4, N0, M0</li><li>T4, N1, M0</li></ul><li><strong>Стадий IIIB</strong></li><ul><li>T1a-c, N3, M0</li><li>T2a-b, N3, M0</li><li>T3, N2, M0</li><li>T4, N2, M0</li></ul><li><strong>Стадий IIIC</strong></li><ul><li>T3, N3, M0</li><li>T4, N3, M0</li></ul></ul><p><strong>Стадий IV (Метастатичен)</strong></p><ul><li><strong>Стадий IVA</strong>: </li><ul><li>Всяко T, Всяко N, M1a</li><li>Всяко T, Всяко N, M1b</li></ul><li><strong>Стадий IVB</strong>: Всяко T, Всяко N, M1c</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"color: rgb(88, 129, 87)\">Принципи на лечение и оценка на пациента</h2><p>Терапията на белодробния карцином бива два основни вида:</p><ol><li><strong>Радикална:</strong> Цели пълно отстраняване или унищожаване на тумора.</li><li><strong>Палиативна:</strong> Цели намаляване на болката и страданието на пациента, както и подобряване на качеството на живот.</li></ol><p><strong>Видът на лечението се определя от:</strong></p><ul><li>Хистологичния тип (дребноклетъчен или недребноклетъчен).</li><li>Размера и позицията на тумора.</li><li>Стадия на развитие (TNM).</li><li><strong>Здравния статус на пациента (Performance Status).</strong></li></ul><h3 style=\"color: rgb(88, 129, 87)\">Оценка на здравния статус (скала на ECOG)</h3><p>Тази оценка е критична за това дали пациентът може да понесе агресивно лечение:</p><ul><li><strong>0:</strong> Норма, способен на нормални дейности.</li><li><strong>1:</strong> С наличие на симптоми, но амбулаторен; на домашен режим, с поносими туморни прояви.</li><li><strong>2:</strong> С инвалидизиращи туморни прояви, но прекарва под 50% от времето на легло.</li><li><strong>3:</strong> Тежко инвалидизиран, прекарва над 50% от времето на легло.</li><li><strong>4:</strong> Тежко болен, 100% от времето е на легло.</li><li><strong>5:</strong> Смърт.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"color: rgb(88, 129, 87)\">Терапевтични методи (Модалности)</h2><h3 style=\"color: rgb(88, 129, 87)\">1. Хирургично лечение</h3><p>Основен метод за ранните стадии на недребноклетъчен карцином. За дребноклетъчен не се препоръва хирургично лечение.</p><ul><li><strong>Видове резекции:</strong> Лобектомия (стандарт), пулмонектомия (премахване на цял дроб). При ограничени респираторни резерви в ранен стадий са допустими сублобарни резекции.</li><li><strong>Лимфна дисекция:</strong> Задължително се придружава от системна медиастинална лимфна дисекция.</li><li><strong>VATS (Видеоасистирана торакоскопия):</strong> Минимално инвазивен метод.</li><li><strong>При плеврален излив:</strong> При малигнен плеврален излив се прави диагностична торакоцентеза и се обсъжда плеврален дренаж с <strong>талкова плевродеза</strong> (палиативно).</li></ul><h3 style=\"color: rgb(88, 129, 87)\">2. Лъчелечение (Радиотерапия)</h3><p>Може да бъде самостоятелно радикално, предоперативно (неоадювантно), следоперативно (адювантно) или палиативно.</p><ul><li><strong>Палиативно лъчелечение:</strong> Прилага се при метастази в мозъка, костите, при компресия на гръбначен мозък и при <strong>синдром на горна празна вена</strong>.</li><li><strong>Профилактично краниално лъчелечение:</strong> Препоръчва се при дребноклетъчен карцином за намаляване на риска от мозъчни метастази.</li><li><strong>Стереотактична радиотерапия (Радиохирургия):</strong> Роботизиран метод за високодозово облъчване. Тя е алтернатива на конвенционалната хирургия при пациенти над 65-70 г. с ранен стадий (тумор до 20 mm, N0) или за палиативно лечение на метастази близо до жизненоважни органи.</li></ul><h3 style=\"color: rgb(88, 129, 87)\">3. Химиотерапия</h3><p>В зависимост от етапа на недребноклетъчен рак на белия дроб и други фактори, химиотерапията може да се използва в различни ситуации:</p><ul><li><strong>Основно лечение:</strong> При напреднали стадии или противопоказания за операция.</li><li><strong>Съпътстваща:</strong> Заедно с лъчетерапия при тумори, инфилтриращи важни структури, но неспособни за хирургично отстраняване.</li><li><strong>Неадювантна:</strong> Преди операция за намаляване обема на тумора.</li><li><strong>Адювантна:</strong> След операция за унищожаване на останали микрометастази.</li></ul><h3 style=\"color: rgb(88, 129, 87)\">4. Таргетна (Прицелна) терапия</h3><p>Фокусира се върху специфични генетични аномалии в раковите клетки. Действа само при пациенти, чиито тумори имат доказани мутации:</p><ul><li><strong>EGFR-мутации</strong> (Рецептор на епидермалния растежен фактор).</li><li><strong>ALK-пренареждане</strong>.</li></ul><p>Блокирането на тези протеини води до смърт на раковите клетки.</p><h3 style=\"color: rgb(88, 129, 87)\">5. Имунотерапия</h3><p>Използва имунната система за борба с рака чрез т.нар. <strong>\"check-point\" инхибитори</strong> (Anti-PD-1, Anti-PD-L1, Anti-CTLA-4). Те премахват \"заслепяването\" на Т-клетките от тумора и позволяват на имунната система да го атакува.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"color: rgb(88, 129, 87)\">Лечение на Недребноклетъчен карцином (НДК)</h2><p>НДК съставлява 75-80% от случаите. Подходът зависи стриктно от стадия.</p><h3 style=\"color: rgb(88, 129, 87)\">Стадий I и II (Локализирано заболяване)</h3><ul><li><strong>Хирургично лечение:</strong> Метод на първи избор (лобектомия/пулмонектомия + лимфна дисекция).</li><li><strong>Адювантна химиотерапия:</strong></li><ul><li>Не се прилага при стадий IA.</li><li>Може да е полезна при селектирани случаи в стадий IB (тумор &gt; 4 cm).</li><li><strong>Стандарт за Стадий II:</strong> Хирургия, последвана от адювантна химиотерапия.</li></ul><li><strong>Лъчелечение:</strong> Прилага се при пациенти с противопоказания за операция или отказ от такава.</li></ul><h3 style=\"color: rgb(88, 129, 87)\">Стадий IIIA и IIIB (Локално авансирало заболяване)</h3><ul><li>Стандартният подход е <strong>комбинирана химио-лъчетерапия</strong>.</li><li>Химиотерапията включва двойна комбинация на <strong>платинов препарат</strong> (Cisplatin или Carboplatin) с трета генерация цитостатик (Docetaxel, Gemcitabine, Paclitaxel, Pemetrexed, Vinorelbine).</li></ul><h3 style=\"color: rgb(88, 129, 87)\">Стадий IV (Метастатично заболяване)</h3><ul><li><strong>Химиотерапия и Палиативна лъчетерапия.</strong></li><li><strong>Таргетна терапия (при наличие на мутации):</strong></li><ul><li>При <strong>EGFR-мутации:</strong> Тирозин-киназни инхибитори (<em>Gefitinib, Erlotinib, Afatinib</em>).</li><li>При <strong>ALK-пренареждане:</strong> <em>Crizotinib</em>.</li></ul><li><strong>Имунотерапия:</strong>&nbsp;</li><ul><li><em></em><p>Anti-PD-1: <em>Nivolumab </em>и <em>Pembrolizumab</em>.</p></li><li><p>Anti-PDL-1: <em>Durvalumab</em>, <em>Atezolizumab </em>и <em>Avelumab</em>.</p></li><li><p>Anti-CTLA-4: <em>Ipilimumab</em> и <em>Tremelimumab</em>.</p></li></ul></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"color: rgb(88, 129, 87)\">Лечение на Дребноклетъчен карцином (ДКК)</h2><p>ДКК е изключително агресивен, склонен към ранно метастазиране, но е силно чувствителен на химио- и лъчетерапия. <strong>Хирургично лечение рутинно не се препоръчва.</strong></p><h3 style=\"color: rgb(88, 129, 87)\">При локализирано заболяване</h3><ul><li><strong>Комбинирана химио-лъчетерапия.</strong></li><li><strong>Цитостатичен режим:</strong> Златен стандарт е комбинацията <strong>Cisplatin + Etoposide</strong>. Провеждат се 4-6 курса.</li><li><strong>Профилактично краниално лъчелечение:</strong> Препоръчва се след приключване на химиолъчелечението при пациенти в ремисия и добро състояние, за да се редуцира рискът от мозъчни метастази.</li></ul><h3 style=\"color: rgb(88, 129, 87)\">При метастазирало заболяване</h3><ul><li><strong>Химиотерапия:</strong> Стандартният подход е 4-6 курса (Cisplatin + Etoposide).</li><li><strong>Палиативна лъчетерапия:</strong> За симптоматичен контрол на първичния тумор и метастазите (напр. костни, мозъчни).</li><li>Профилактично облъчване на главен мозък може да се обсъди при пациенти с добър отговор към първоначалното лечение.</li></ul><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><br><br><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center; color: rgb(88, 129, 87)\">Тема 6: Белодробна туберкулоза- епидемиология, етиопатогенеза и диагноза</h1><h2 style=\"color: rgb(88, 129, 87)\">Епидемиология</h2><p>Туберкулозата е инфекциозно заболяване, от което ежегодно се разболяват около 9 млн. души, а умират около 2 млн. Това е инфекцията, която засяга най-голяма част от населението на Земята. Около <strong>1/3 от населението на земята</strong> носи в себе си Бацила на Koch.</p><p><strong>Начин на предаване:</strong></p><p>Заболяването се предава основно по <strong>въздушно-капков път</strong>. Източник на зараза са болните от туберкулоза хора, особено при т.нар. <strong>открити форми</strong> на белодробна туберкулоза, при които има каверни и в храчките се отделя бацила на Koch. Установено е, че каверна с диаметър около 2 cm може да съдържа към 100 млн. бацила.</p><p><strong>Основни епидемиологични показатели:</strong></p><ul><li><strong>Заболеваемост:</strong> Броят на всички <em>новозаболели</em> от туберкулоза през дадена календарна година, отнесен към 100 000 души население.</li><li><strong>Болестност:</strong> Всички болни от туберкулоза (<em>стари и нови</em>) за дадена календарна година, отнесени към 100 000 население.</li><li><strong>Бацилоотделяне:</strong> Болните с положителни микробиологични резултати, отнесени към 100 000 население.</li><li><strong>Смъртност:</strong> Починали от туберкулоза болни, отнесени към 100 000 население.</li></ul><p><strong>Проблемът с резистентността:</strong></p><p>Най-сериозният проблем в съвременната ера е нарастващата резистентност на Mycobacterium tuberculosis (МТ) към лекарствата. Най-честата причина за развитие на резистентност е неправилно провеждано лечение.</p><ul><li><strong>Монорезистентност:</strong> Резистентност към едно лекарство от I-ви ред.</li><li><strong>Полирезистентност:</strong> Резистентност към две или повече лекарства от I-ви ред (изключвайки едновременна резистентност към Isoniazid и Rifampicin).</li><li><strong>Мултирезистентност (<span class=\"editor-note\" data-note=\"Multidrug-resistant tuberculosis\" id=\"note-1769770952893-0\">MDR-ТВ</span>):</strong> Резистентност към <strong>Isoniazid и Rifampicin</strong> едновременно, с или без резистентност към друг медикамент.</li><li><strong>Екстензивна резистентност (<span class=\"editor-note\" data-note=\"Extensively drug-resistant tuberculosis\" id=\"note-1769770961009-1\">XDR-TB</span>):</strong> Мултирезистентност, съчетана с резистентност към който и да е флуорохинолон и към поне един от инжекционните продукти от втори ред (Капреомицин, Канамицин, Амикацин).</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"color: rgb(88, 129, 87)\">Етиология</h2><p>Причинители на заболяването са микобактериите от групата <strong>Mycobacterium tuberculosis complex</strong>, като най-чести са: <em>Mycobacterium tuberculosis (MT)</em>, <em>Mycobacterium africanum</em> и <em>Mycobacterium bovis</em>.</p><p><strong>Характеристика на причинителя (M. tuberculosis):</strong></p><ul><li>Строг аероб и облигатен паразит.</li><li><strong>Киселинно устойчиви бактерии:</strong> Клетъчната му стена е с богато липидно съдържание, което я прави устойчива към алкохол-киселина.</li><li><strong>Устойчивост:</strong> Устойчив е на редица химични и физични въздействия. В тъмни и непроветрени помещения остава жизнеспособен до <strong>3 години</strong>.</li><li><strong>Чувствителност:</strong> Загива след 5–10 мин. под въздействие на преки слънчеви лъчи или след 1–2 мин. от ултравиолетови лъчи. Хлорните препарати имат най-силен ефект.</li><li><strong>Размножаване:</strong> Размножава се много бавно – средно веднъж за около <strong>20 часа</strong>.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"color: rgb(88, 129, 87)\">Патогенеза:</h2><p>Туберкулозата е възпалителен инфекциозен процес с хроничен ход. След попадане на вирулентни бацили в алвеолите, те биват фагоцитирани от алвеоларните макрофаги.</p><ul><li>При първична експозиция се инфектират само 30% от контактните.&nbsp;<p>В тези организми се развива първична паренхимна лезия в белия дроб и инфекцията преминава към регионалните лимфни възли.</p></li><li>В 90% от инфектираните се развива специфичен клетъчно-медииран имунен отговор (4–6 седмици по-късно), който спира размножаването на бактериите -&gt; <strong>Латентна туберкулозна инфекция</strong>.</li><li>Само при <strong>7–10%</strong> от инфектираните се развива активно заболяване.</li></ul><h4 style=\"color: rgb(88, 129, 87)\">Първична туберкулоза</h4><p>Развива се в индивиди, които <strong>не са имали контакт с МТ</strong> до момента. Най-често са <strong>деца и юноши</strong> (първата експозиция обикновено е до 18 год.).</p><ul><li>В голям дял от случаите протича <strong>леко</strong>, с бедна симптоматика или <strong>безсимптомно</strong>.</li><li>Наличието на инфекция се регистрира с <strong>позитивиране на туберкулиновата проба</strong> и <strong>рентгенова находка</strong>.</li><li>От първичното белодробно огнище или от ангажиран регионален лимфен възел МТ могат да се разпространят по <strong>лимфохематогенен път</strong> – т.н. <strong>„генерализация“</strong> на процеса. Така МТ достига до други органи, където в зависимост от локалните и общите защитни механизми може да причини туберкулозно възпаление или да остане в <strong>дремещо състояние</strong> (месеци и години).</li><li>При нарушен имунитет, тези микобактерии могат да се реактивират и да доведат до развитие на някои от формите на <strong>извънбелодробна туберкулоза</strong>.</li><li>Хематогенно разсейване може да стане и на други етапи, наблюдавано по-често при болни с <strong>HIV/СПИН</strong>.</li><li>Първичните форми имат склонност към <strong>спонтанно оздравяване</strong>. На мястото на възпалението обикновено остават <strong>калцификати с \"дремещи\" микобактерии</strong> (латентна туберкулозна инфекция), която лесно може да премине в активна туберкулоза при определени ситуации.</li><li>Протичат \"по-разлято\", като при деца под 5-годишна възраст може да бъде <strong>дисеминирана</strong> в няколко органа едновременно (хемаготенно-дисеминирана туберкулоза).</li></ul><h4 style=\"color: rgb(88, 129, 87)\">Вторична туберкулоза</h4><p>Развиват се при индивиди с <strong>предшестваща първична инфекция</strong>. Срещат се най-често при <strong>възрастни</strong>, в резултат на <strong>ендогенна реактивация</strong> или <strong>екзогенна реинфекция</strong>.</p><ul><li><strong>Ендогенна реактивация:</strong> Свързана е с <strong>\"дремещи\" МТ</strong>, които най-често се намират в <strong>калцификати или фиброзни участъци</strong> (зоните на първичната инфекция). При нарушение на защитните сили, тези микобактерии се реактивират и предизвикват повторно заболяване.</li><li><strong>Екзогенна реинфекция:</strong> Свързана е с <strong>нова експозиция и заразяване отвън</strong>, но поради съществуващ вече специфичен имунен отговор, туберкулозният процес протича с характеристиките на вторична форма.</li><li>Различията в протичането на вторичните форми се дължат на <strong>променена реактивност</strong> на организма.</li><li>Сформираният специфичен имунитет довежда до <strong>по-ясно обособени и локализирани форми</strong>.</li><li>Те имат склонност към <strong>разпад</strong>, образуване на кухини (<strong>каверни</strong>) и <strong>бронхогенно разсейване</strong>.</li><li>Параспецифични реакции, серозити и ангажиране на регионалните лимфни възли са по-чести при <strong>първичните</strong> форми и значително по-редки при <strong>вторичните</strong>.</li><li>Вторичната белодробна туберкулоза има склонност към преминаване от по-леки към <strong>по-тежки форми</strong> и <strong>хронифициране</strong> с масивни фиброзни участъци и дебелостенни каверни.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"color: rgb(88, 129, 87)\">Патоанатомия</h2><p>Характерната находка при туберкулозно („специфично“) възпаление е <strong>туберкулозният гранулом (туберкул)</strong>, съдържащ <strong>казеозна некроза</strong>, <strong>епителоидни</strong> и <strong>гигантски клетки на Langhans</strong>.</p><h4 style=\"color: rgb(88, 129, 87)\">Фази на процеса:</h4><ol><li><strong>Ексудативна реакция</strong> на мястото на началната алтерация, съдържаща полинуклеарни левкоцити, които бързо се заместват от моноцити и макрофаги.</li><li>Под влияние на лимфокините от активираните Т-лимфоцити, макрофагите се преобразуват в <strong>епителоидни клетки</strong>.</li><li>Чрез сливане на макрофагите се образуват <strong>гигантските многоядрени клетки на Langhans</strong>, намиращи се периферно от <strong>казеозно-некротичния център</strong> (с голям брой МТ в него).</li><li>С напредване на процеса туберкулите <strong>конфлуират</strong> в големи огнища.</li></ol><h4 style=\"color: rgb(88, 129, 87)\">Развитие на заболяването:</h4><ul><li><strong>При благоприятно развитие:</strong> В туберкула се образуват колагенни и аргирофилни влакна. Епителоидните клетки се преобразуват във фибробласти, настъпва <strong>оздравяване с оформяне на звездовидни цикатрикси или с отлагане на калций</strong>.</li><li><strong>При неблагоприятно протичане:</strong> С преобладаване на ексудативна реакция и конфлуиране на огнищата, се оформя <strong>централна зона на разпад</strong>, като резултат на реакции между антигените и специфичните антитела. Оформят се кухини (<strong>каверни</strong>).</li></ul><h4 style=\"color: rgb(88, 129, 87)\">Допълнителни характеристики:</h4><ul><li><strong>Перифокално възпаление:</strong> Едновременно със специфичния възпалителен процес, около огнищата се образува и <strong>неспецифично (перифокално) възпаление</strong>.</li><li><strong>Пътища на разпространение:</strong> По <strong>съседство</strong>, по <strong>бронхогенен</strong>, <strong>лимфогенен</strong> или <strong>хематогенен път</strong>.</li><li><strong>Разнообразие на картината:</strong> Възможност за редуване и съчетаване на <strong>алтеративни, ексудативни и пролиферативни изменения</strong>, както и комбиниране на <strong>специфични с параспецифични тъканни реакции</strong>. </li><li><strong>Зависимост:</strong> Всичко зависи от <strong>имунния статус</strong> на макроорганизма и от <strong>микроорганизма</strong> (количество, патогенност и вирулентност).</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"color: rgb(88, 129, 87)\">Диагноза: Методи на изследване</h2><h3 style=\"color: rgb(88, 129, 87)\">I. Анамнеза</h3><p>Внимателният разпит е ключов за насочване към диагнозата. Търсят се следните синдроми и рискови фактори:</p><p><strong>1. Интоксикационен синдром:</strong></p><ul><li>Отпадналост, безапетитие, редукция на тегло.</li><li><strong>Фебрилитет</strong> (най-често субфебрилитет в следобедните часове).</li><li><strong>Обилно нощно изпотяване</strong> (най-често в областта на глава, шия, горна част на торакса).</li><li>При деца: <p>намалена двигателна активност, трудно концентриране на вниманието, емоционална неустойчивост, понижена успеваемост в училище.</p></li></ul><p><strong>2. Бронхобелодробен синдром:</strong></p><ul><li>Кашлица (суха или продуктивна).</li><li>Експекторация (възможно с примес на кръв).</li><li>Бодежи в гърдите (при плеврално засягане).</li><li>Задух (при напреднали форми).</li></ul><p><strong>3. Параспецифична симптоматика:</strong></p><ul><li>Среща се най-често при <strong>деца и юноши с първични форми</strong> на белодробна туберкулоза в резултат на образуване на параспецифични инфилтрати в други органи поради <strong>токсоалергична реакция</strong> към БК.&nbsp;</li><li>Най-чести са: <strong>нодозен еритем</strong>, <strong>фликтенулозен кератоконюнктивит</strong>, <strong>артралгии</strong> и др.</li></ul><strong>4. </strong><strong>Симптоми от страна на други органи, ангажирани от туберкулоза:</strong><br><ul><li>Могат да съществуват самостоятелно (при извънбелодробна локализация) или едновременно с белодробна симптоматика. Най-често присъстват при <strong>хематогенно-дисеминираните форми</strong>.</li><li><em>Оплаквания:</em> мъчително главоболие и повръщане при менингит, хематурия при бъбречна туберкулоза, болезнена и подута става при костно-ставна туберкулоза и т.н.</li></ul><p><strong>5. Други важни въпроси:</strong><strong><br></strong></p><ul><li>Проведена профилактика с <strong>Isoniazid </strong>или установяване на <strong>хиперергичен Туберкулинов кожен тест в миналото</strong>.</li><li>Проведена ваксинация и реваксинации с <strong>BCG</strong>.</li><li>Пребиваване в социални заведения (старчески дом, приют, затвор).</li><li>Престой в страни с висока заболеваемост от туберкулоза.</li><li>Предхождаща имуносупресираща терапия: лечение с кортикостероиди, лечение с <strong>анти-TNF-α-антитела</strong>, цитостатици, лъчетерапия и др.</li><li><strong>Предхождащо лечение с антибиотици</strong> (липсата на ефект от адекватна антибиотична терапия може да насочи към туберкулоза).</li><li>Тютюнопушене, алкохолизъм, наркомания и др.</li><li>Съпътстващи рискови заболявания: диабет, бронхиектазии, ХОББ и други хронични белодробни заболявания, неоплазии (лимфом, левкемия и др.), вроден имунен дефицит, <strong>СПИН</strong>/<strong>HIV</strong>, синдром на малабсорбция, органни трансплантации и др.</li><li><strong>Прекарана туберкулоза</strong> в миналото</li><li><strong>Контакт с туберкулозно болен</strong>, включително в миналото</li><li>Условия на живот</li></ul><h3 style=\"color: rgb(88, 129, 87)\">II. Физикален статус</h3><p>При туберкулоза често важи правилото <strong>„много се вижда (на рентген), малко се чува“</strong>.</p><ul><li>В ранните етапи физикалната находка може да е оскъдна или нормална.</li><li>При хронични и напреднали форми (каверни, фиброза) находката е богата: „много се вижда и много се чува“.</li><li><p><strong>Нормалната физикална находка не изключва туберкулоза</strong>.</p></li><li><p>При извънбелодробните локализации физикалната находка е разнообразна и зависи от засегнатия орган.</p><br></li></ul><h3 style=\"color: rgb(88, 129, 87)\">III. Образна диагностика</h3><strong>1. Рентгенови методи на изследване:</strong><br><ul><li><strong>Рентгенография</strong> фас и профил.</li><li><strong>TV скопия</strong> (за уточняване локализацията на процеса, визуализиране на интерлобарни изливи и др.).</li><li><strong>Класическа томография</strong> (добре се визуализират налични каверни).</li><li><strong>Латерография и латероскопия</strong> (при малки плеврални изливи).</li><li><strong>Флуорография</strong> (скрининг при рискови контингенти).</li></ul><ul><li><strong>Компютърна Томография&nbsp;</strong>на бял дроб и медиастинум или други органи (висока информативност).</li></ul><strong>2. Ехография на бял дроб:</strong> Има точно определени индикации:<br><ul><li>Разграничаване на плеврален излив от плеврално срастване.</li><li>Откриване на малки плеврални изливи, визуализиране на инкапсулати.</li></ul><ul><li><strong>Интервенционална пулмология:</strong> Под ултразвуков контрол се извършва <strong>трансторакална тънкоиглена аспирационна биопсия (ТТАБ)</strong>, а с <strong>ендобронхиална ултрасонография (ЕБУЗ)</strong> може да се вземат насочено материали за изследване при бронхоскопия.</li></ul><strong>3. Магнитно резонансна диагностика (MRI):</strong> Особено подходяща при съмнение за <strong>туберкулозен спондилит</strong>, както и за изследване на <strong>главен мозък, меки тъкани и съдови структури</strong>.<br><strong>4. Позитрон емисионна томография (РЕТ):</strong> Дава възможност за разграничаване на <strong>доброкачествен от злокачествен нодул</strong> в белия дроб или <strong>бенигнено от малигнено</strong> ангажиране на вътрегръдни лимфни възли.<br><strong>5. Сцинтиграфия:</strong> Използва се рядко във фтизиатрията, най-вече за диференциална диагноза на ПБТ.<h3 style=\"color: rgb(88, 129, 87)\">IV. Микробиологични методи</h3><p>Това са методите за потвърждаване на диагнозата („Златен стандарт“).</p><p><strong>1. Директна микроскопия:</strong></p><ul><li><p><strong>Оцветяване по Ziehl-Neelsen:</strong> Първият бактериологичен тест. Бърз, евтин и лесно приложим, но <strong>недостатъчно чувствителен и специфичен</strong>.</p></li><li><p><strong>Флуоресцентна микроскопия</strong> (флуорохромно оцветяване): Бърз, но значително <strong>по-скъп</strong> метод, който изисква добре подготвен персонал.</p></li></ul><p><strong>2. Културелни методи:</strong></p><p><strong>А. Конвенционални методи на култивиране:</strong></p><ul><li>Класическият метод е посявка върху твърда яйчна среда на <strong>Löwenstein-Jensen</strong>.</li><li>Много по-чувствителен и специфичен от директната микроскопия, но значително <strong>по-бавен</strong> (резултат – най-често в края на <strong>6-тата седмица</strong>).</li><li>Голямо предимство: може да се направи <strong>тест за лекарствена чувствителност (ТЛЧ)</strong>.</li><li>Този метод вече отстъпва на съвременните.</li></ul><p><strong>Б. Неконвенционални методи с автоматизирани системи за култивиране и възможност за ТЛЧ:</strong></p><ul><li>Радиометричен метод <strong>Bactec 460 ТВ</strong>.</li><li>Флуориметричен метод <strong>MGIT 960 System</strong>.</li><li>Колориметричен метод <strong>BacT/ALERT-3D</strong>.</li><li>Значително <strong>скъсяват времето</strong> за позитивиране на посявките (средно <strong>7-8 дни</strong>) и за резултата от ТЛЧ (средно <strong>8 дни</strong>), но са по-скъпи и изискват обучен персонал.</li></ul><p><strong>В. Бързи молекулярни тестове:</strong></p><ul><li><strong>Xpert MTB/RIF</strong> и <strong>Xpert MTB/RIF Ultra</strong>.</li><li>Регистрират наличието на <strong>МТ</strong> и <u>оценяват наличието на <strong>резистентност към Рифампицин</strong></u>.</li><li>Дават резултат в рамките на <strong>2 часа</strong>, цената им не е висока и стават по-достъпни.</li><li>Процедурата не изисква специална подготовка и обучен персонал.</li><li>Възможност за инсталиране в <strong>мобилна лаборатория</strong>.</li><li>В най-новите препоръки са <strong>първи метод за изследване</strong> на пациента, заедно с директната микроскопия.</li></ul><p><strong>3. Други методи:</strong></p><ul><li>Хроматография.</li><li><strong>Polymerase Chain Reaction (PCR)</strong>.</li></ul><h3 style=\"color: rgb(88, 129, 87)\">V. Имунологични методи</h3><p><strong>1. Изследване на туберкулинова чувствителност с проба на Mantoux (Туберкулинов кожен тест - ТКТ)</strong></p><ul><li><strong>Принцип</strong>: Вътрекожното инжектиране на <strong>пречистен протеинов дериват (ППД)</strong> е класически пример за <strong>забавен тип алергична реакция</strong>. Т-лимфоцитите, които са сенсибилизирани в резултат на предхождаща инфекция с МТ, се насочват към мястото на апликацията и там освобождават <strong>лимфокини</strong>. Те причиняват <strong>индурация</strong> поради локална вазодилатация, едем, отлагане на фибрин и привличане на други клетки на възпалението към този участък.</li><li><strong>Реактивността спрямо ППД</strong> дава възможност за преценка на клетъчния имунен отговор на пациента.</li><li><strong>Провеждане в България:</strong> ТКТ се прави с <strong>5 туберкулинови единици </strong>български ППД туберкулин <strong>строго интрадермално</strong>.</li><li>Реакцията се отчита на <strong>72-ия час </strong><p>чрез измерване на напречния размер на <strong>индурацията</strong> (не еритемата!).</p></li><li>Според размера на инфилтрата резултатите биват:</li><ul><li><strong>Отрицателен:</strong> 0–5 мм.</li><li><strong>Нормергичен:</strong> 6–14 мм.</li><li><strong>Хиперергичен:</strong> ≥ 15 мм (или наличие на була, лимфангит, остатъчна пигментация, последваща дексвамация на мястото на инфилтрата).</li></ul><li><strong>Предимства: </strong></li><ul><li>ТКТ е <strong>евтин</strong> и <strong>лесно изпълним тест.</strong></li><li>С него има дългогодишен опит и затова все още е <strong>класическият метод за търсене на </strong><strong>латентна туберкулозна инфекция</strong>.</li><li>Той е много подходящ в диагностиката на туберкулозата при <strong>деца и юноши</strong> поради по-висока информативност в тази възраст.</li></ul></ul><ul><li><strong>Недостатъци:</strong></li><ul><li>Информативността на теста е <strong>ниска при имунокомпрометирани пациенти</strong> и при тежки форми на туберкулоза (<strong>фалшиво отрицателен ТКТ</strong>).</li><li>Повлиява се значително от предхождаща <strong>BCG ваксинация</strong> (може да бъде <strong>фалшиво хиперергичен</strong>).</li><li>Установява се и <strong>кръстосана положителна реакция</strong> при наличие на антигени на <u>нетуберкулозни микобактерии</u>.</li><li>Затова тестът на Mantoux <strong>винаги</strong> трябва да се интерпретира съобразно наличните епидемиологични, клинични и параклинични данни.</li></ul></ul><p><strong>2. Интерферон-гама тестове - interferon-gamma release assays (IGRA)</strong></p><ul><li><strong>Видове:</strong> QuantiFERON-TB Gold In-Tube и T-Spot ТВ.</li><li><strong>Принцип: </strong>Те използват <strong>специфични за МТ антигени</strong>, за да стимулират Т-клетките в проба от венозна кръв на пациента. Ако са били изложени на предишно въздействие от страна на МТ, Т-клетките секретират цитокина <strong>интерферон-гама</strong> в плазмата, което показва наличието на туберкулозна инфекция.</li><li><p><strong>Използване </strong>- най-често при:<strong> </strong></p></li><ul><li><p>Пациенти с позитивно Манту, преди окончателно вземане на решение за лечение на<strong> </strong></p><p><strong>латентна туберкулозна инфекция.</strong></p></li><li>Пациенти, обсъждани за лечение с анти-TNF-α-антитела.</li><li>Имунокомпрометирани пациенти.</li><li>За изследване на ваксинирани контактни лица.</li></ul><li><strong>Предимство:</strong> Не се влияят от BCG ваксинация.</li><li><strong>Ограничение: </strong></li><ul><li>ИГТ <strong>не могат да отдиференцират</strong> дали тази инфекция е активна или латентна.</li><li><p>Въпреки множеството им предимства, широкото им използване все още е възпрепятствано поради <strong>високата цена</strong>.</p></li></ul></ul><h4 style=\"color: rgb(88, 129, 87)\">VI. Параклинични методи</h4><p>Най-често при активна туберкулоза е налице следната констелация:</p><ul><li><strong>Лаборатория: </strong>Умерено ускорена <strong>СУЕ</strong>, левкоцитоза с олевяване, лимфопения и еозинофилопения (начало) -&gt; лимфоцитоза и еозинофилия (късно).</li><li><p><strong>Аденозиндеаминаза (ADA):</strong> Повишени стойности (&gt; 40 IU/L) в плеврален пунктат, асцитна течност или ликвор са показателни за туберкулозен плеврит.</p><br></li><li><strong>Диспротеинемия:</strong> намаление на албумините, увеличение на алфа2-, гама глобулините и фибриногена.</li><li>Нормална параклиника не изключва активно заболяване.</li></ul><h4 style=\"color: rgb(88, 129, 87)\">VII. Инвазивни методи</h4><ul><li><strong>Фибробронхоскопия:</strong> оглед, вземане на бронхиален аспират за изследване, четкова, шипкова и трансбронхиална белодробна биопсия, <strong>бронхоалвеоларен лаваж</strong>, биопсия под ултразвуков контрол (<strong>EBUS-TBNA</strong>).</li><li><strong>Трансторакална тънкоиглена аспирационна биопсия (ТТАБ)</strong>.</li><li><strong>Биопсия на периферни лимфни възли</strong>, кожни изменения или други органи за морфологично доказване на туберкулоза.</li><li><strong>Плеврална биопсия</strong> (на сляпо или насочена чрез <strong>видео-асистирана торакоскопия (VATS)</strong>, медиастиноскопия, открита белодробна биопсия за морфологична диагноза.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"color: rgb(88, 129, 87)\">Дефиниции на случаите (по СЗО)</h2><ol><li><strong>Вероятен случай:</strong> Пациент със симптоми, предполагащи ТБ.</li><li><strong>Микробиологично диагностициран случай:</strong> Биологичен материал е положителен (микроскопия, посявка или молекулярен тест).</li><li><strong>Клинично диагностициран случай:</strong> Не е доказан бактериологично, но диагнозата е поставена от специалист на базата на клиника и рентген, и е започнато лечение.</li></ol><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><br><br><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center; color: rgb(88, 129, 87)\">Тема 7: Белодробна туберкулоза – клинични форми - неготова</h1><h2 style=\"color: rgb(88, 129, 87)\">Класификация и обща характеристика</h2><p>От патогенетична гледна точка формите на белодробната туберкулоза се делят на <strong>първични</strong> и <strong>вторични</strong>.</p><p><strong>1. Първични форми:</strong></p><ul><li>Развиват се при индивиди, които <strong>не са имали контакт</strong> с Mycobacterium tuberculosis (МТ) до момента (най-често деца и юноши).</li><li>Имат склонност към спонтанно оздравяване, калциниране на лезиите и <strong>лимфохематогенно разпространение (генерализация)</strong>.</li><li>Често протичат \"по-разлято\".</li></ul><p><strong>2. Вторични форми:</strong></p><ul><li>Развиват се при индивиди с <strong>предшестваща първична инфекция</strong> (най-често възрастни) в резултат на ендогенна реактивация или екзогенна реинфекция.</li><li>Протичат по-локализирано поради изградения имунитет.</li><li>Имат склонност към <strong>разпад, образуване на каверни</strong> и <strong>бронхогенно разсейване</strong>.</li><li>Ангажирането на лимфни възли е рядко.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"color: rgb(88, 129, 87)\">Първична туберкулоза</h2><h3 style=\"color: rgb(88, 129, 87)\">Първичен белодробен комплекс</h3><p>Състои се от три задължителни компонента:</p><ol><li><strong>Първичен афект (Белодробно огнище на Ghon):</strong>&nbsp;</li><ul><li>Специфично възпаление на паренхима с малки размери (1.5–2 cm), обикновено в долните отдели, по-често вдясно.</li><li>Около него има <strong>перифокално </strong>(параспецифично) <strong>възпаление</strong>.</li><li><p><strong>Оздравяване:</strong> В хода на оздравителния процес на мястото на казеозната некроза се отлагат калциеви соли и се визуализира окръглен калцификат (калцирано огнище на Ghon).</p><br></li></ul><li><strong>Лимфангит:</strong> Възпаление на лимфните пътища към хилуса.</li><li><strong>Лимфаденит:</strong>&nbsp;</li><ul><li><p>Специфично възпаление на <strong>един или повече регионални хилусни лимфни възела</strong>.</p></li><li><p>Понякога се въвличат и други интраторакални групи (напр. паратрахеални и бифуркационни).</p></li><li><p><strong>Оздравяване:</strong> </p><p>При благоприятна еволюция постепенно в ангажираните лимфни възли се отлагат калциеви соли.</p></li><li><p><strong>Латентност:</strong> Обикновено в тях, както и в огнището на Ghon, за цял живот персистират дремещите L-форми на МТ.</p></li></ul></ol><p><strong>Клиника:</strong></p><ul><li>В 2/3 от случаите протича <strong>леко </strong><p>със слабо изразен интоксикационен и бронхобелодробен синдром</p> или <strong>безсимптомно</strong>.</li><li>Може да има умерено изразен интоксикационен и бронхобелодробен синдром.&nbsp;<p>Често остава недиагностицирана, ако не се направи рентгенография.</p></li><li><p>При <strong>имунокомпрометирани пациенти </strong>и <strong>деца </strong>в <strong>кърмаческа </strong>и <strong>ранна детска възраст </strong>заболяването протича с добре изразена симптоматика. Възможни са усложнения (първична казеозна пневмония, ателектаза) и фатален изход.</p><br></li><li>В редки случаи може да еволюира към хронично протичаща първична туберкулоза, при която са налице хронична туберкулозна интоксикация и изразена белодробна симптоматика.</li></ul><p><strong>Физикален статус:</strong></p><ul><li>Най-често не се долавят патологични феномени поради малките размери на засегнатия участък.</li><li>При масивна перифокална реакция може да се установят физикални белези на инфилтрат.</li><li>Нерядко има съпътстващ <strong>плеврален излив</strong>, който, при достигане на по-големи размери, се регистрира и с физикални методи.</li></ul><p><strong>Изследвания:</strong></p><ul><li><strong>Имунологични: и Микробиологични</strong></li><ul><li>ТКТ (Туберкулинов кожен тест): Най-често използвано изследване, което в детска възраст е с висока информативна стойност. Обикновено е хиперергичен.</li><li>Забележка: При имунокомпрометирани деца може да е фалшиво отрицателен. В такива случаи е по-добре да се направи някой от ИГТ (Интерферон-гама тестове).</li></ul><li><strong>Бацилоотделяне</strong>: Доказва се рядко.</li><li><strong>Рентгенография</strong>:</li><ul><li><strong>Класически образ</strong>: Т.нар. „<strong>гирички</strong>“ (уголемен хилус, засенчване в паренхима и ивицести сенки между тях) се среща в случаите, когато първичният афект е отдалечен от хилуса.</li><li>Когато афектът е в близост до хилуса, перифокалните изменения около двете компоненти конфлуират и се получава инфилтративно засенчване, което прилича на пневмония.</li><li>Калцификати в паренхима и лимфните възли се виждат след дълъг срок от време (година и повече), поради което те се свързват с прекаран, а не активен в момента процес.</li></ul><li><strong>Лабораторни изследвания (Параклиника):</strong></li><ul><li>Най-често се регистрира обичайната за активна туберкулоза констелация.</li><li>Нормалната параклиника не изключва това заболяване.</li></ul></ul><p><strong>Усложнения:</strong></p><p>Срещат се най-често при <strong>кърмачета </strong>и <strong>деца </strong>в <strong>ранна детска възраст </strong>или <strong>имунокомпрометирани пациенти</strong>.</p><ul><li><strong>Първична казеозна пневмония</strong>.</li><ul><li>Рядко може да протече с разпад и оформяне на <strong>първична каверна</strong> и с <strong>бронхогенно разсейване</strong>.</li></ul><li><strong>Лимфохематогенни разсейки </strong>в други органи, водещи до изява и на друга органна локализация.</li><ul><li><i>Риск</i>: Най-често на тези места МТ остава в латентно състояние, но съществува риск за изява на ПБТ (постпървична туберкулоза) след различно дълъг период от време.</li></ul><li><strong>Масивна ателектаза и плеврит</strong>.</li></ul><p><strong>Прогноза и протичане</strong></p><ul><li>По правило, те са <strong>благоприятни</strong>.</li><li>Често е налице <strong>спонтанно обратно развитие </strong>и <strong>оздравяване с оформяне на калцификати в паренхима и лимфните възли</strong>, където туберкулозните микобактерии остават в <strong>дремещо състояние</strong>.</li><li>След време, при имуносупресия или други заболявания, те могат да се реактивират и причинят вторична туберкулоза.</li></ul><h3>Туберкулоза на вътрегръдните лимфни възли - до тука е готово</h3><p>Това е <strong>най-честата форма</strong> на първична туберкулоза у деца и юноши (70–80%). В белодробния паренхим липсва специфично възпаление, има само параспецифичен инфилтрат.</p><p><strong>Клинични варианти:</strong></p><ol><li><strong>Туморовиден бронхаденит:</strong> Лимфните възли са значително уголемени и повече на брой. Водещ е <strong>бронхобелодробният синдром</strong> със суха, битонална, мъчителна кашлица (поради притискане на бронхи).</li><li><strong>Инфилтративен бронхаденит:</strong> Единични възли със силно изразено параспецифично възпаление в съседния паренхим. Водещ е <strong>интоксикационният синдром</strong>.</li></ol><p><strong>Усложнения:</strong></p><ul><li>Ателектази.</li><li><strong>Адено-бронхиална фистула:</strong> Пробив на лимфния възел в бронха, водещ до бронхогенно разсейване.</li></ul><h3 style=\"color: rgb(88, 129, 87)\">Хематогенно-дисеминирана туберкулоза</h3><p>Характеризира се с разсейване на МТ по кръвен път при срив в имунитета. Разграничават се 4 форми:</p><h4 style=\"color: rgb(88, 129, 87)\">1. Туберкулозен сепсис</h4><ul><li>Най-тежката форма, завършваща летално.</li><li>Среща се при кърмачета и имунокомпрометирани (СПИН).</li><li>Осейване на всички органи, отрицателен Туберкулинов кожен тест (ТКТ) поради анергия.</li></ul><h4 style=\"color: rgb(88, 129, 87)\">2. Остра милиарна туберкулоза</h4><p>Еднократен тласък на разсейване. Измененията са еднакви по големина (<strong>милиарни сенки 1–2 mm</strong>) и фаза на развитие. Има 3 подформи:</p><ul><li><strong>Тифоидна:</strong> Имитира коремен тиф. Водещи са симптоми от Гастроинтестиналния тракт (ГИТ) и тежка интоксикация. Белодробната находка е бедна.</li><li><strong>Белодробна:</strong> Силна кашлица и задух, цианоза. Налице е дисоциация: <strong>тежка диспнея при бедна физикална находка</strong>.</li><li><strong>Менингеална (Туберкулозен менингит):</strong> Засягане на мозъчните обвивки. Протича в 3 стадия:</li><ol><li><em>Продромален:</em> Постепенна интоксикация, промяна в характера (липсва при другите менингити).</li><li><em>Менингорадикулерно дразнене:</em> Главоболие, повръщане, фотофобия.</li><li><em>Централно-мозъчна симптоматика:</em> Засягане на черепно-мозъчни нерви, гърчове, кома.</li></ol><ul><li><strong>Ликвор:</strong> Бистър, „мрежица“ от фибрин при престой, лимфоцитна плеоцитоза, ниска захар.</li></ul></ul><h4 style=\"color: rgb(88, 129, 87)\">3. Подостра хематогенно-дисеминирана</h4><ul><li>Няколко тласъка за 2–3 седмици.</li><li><strong>Полиморфизъм:</strong> Измененията са с различна големина.</li><li>Образуват се <strong>„щамповани“ каверни</strong> (тънкостенни) във върховете.</li><li>Протича с периоди на затихване и обостряне.</li></ul><h4 style=\"color: rgb(88, 129, 87)\">4. Хронична хематогенно-дисеминирана</h4><ul><li>Множество тласъци за дълъг период.</li><li><strong>Изразен полиморфизъм:</strong> Пресни и стари огнища, фиброза, калцификати, емфизем, плеврални сраствания.</li><li>Развива се хронично белодробно сърце.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"color: rgb(88, 129, 87)\">Вторична туберкулоза</h2><h3 style=\"color: rgb(88, 129, 87)\">Огнищна туберкулоза</h3><p>Начална форма на вторична туберкулоза.</p><ul><li><strong>Характеристика:</strong> Групирани ацинозни и нодозни огнища с малки размери.</li><li><strong>Локализация:</strong> Обикновено <strong>върхово-подключично</strong> едностранно (рентгенов образ на „гирлянда“ или „грозд“).</li><li><strong>Клиника:</strong> Бедна или липсваща симптоматика. Често се открива случайно.</li><li><strong>Прогноза:</strong> Добра, при лечение настъпва пълно оздравяване.</li></ul><h3 style=\"color: rgb(88, 129, 87)\">Инфилтративно-пневмонична туберкулоза</h3><p>Най-честата вторична форма. Типична е тенденцията към <strong>разпад и образуване на каверни</strong>. Половината от болните са бацилоотделители.</p><p><strong>Варианти:</strong></p><ol><li><strong>Кръгъл инфилтрат:</strong> Окръглена сянка (2–3 см), обикновено върхово-подключично (тип Assmann). При разпад се вижда пръстеновидна сянка.</li><li><strong>Облаковиден инфилтрат:</strong> Петнисто-ивицесто засенчване с неясни граници.</li><ul><li><strong>Физикална находка:</strong> Характерна е дисоциацията – <strong>„много се вижда (на рентген), а малко се чува (на слушалка)“</strong>.</li></ul><li><strong>Лобит:</strong> Инфилтратът обхваща цял лоб (най-често горен десен). Има рязка граница по интерлобарната бразда.</li><li><strong>Казеозна пневмония:</strong></li><ul><li>Тежка форма, срещана при имунокомпрометирани.</li><li>Преобладават казеозно-некротичните изменения с множество просветлявания (разпад).</li><li>Протича остро, с тежка интоксикация и лоша прогноза.</li></ul></ol><h3 style=\"color: rgb(88, 129, 87)\">Туберкулом</h3><p>Окръглена формация (2–3 cm), резултат от инкапсулиране на инфилтрат или запълване на каверна.</p><ul><li><strong>Структура:</strong> Казеозна некроза в центъра (с микобактерии), обградена от фиброзна капсула.</li><li><strong>Рентген:</strong> Сянка с голяма плътност и ясни граници. При разпад се вижда <strong>ексцентрично просветляване</strong> (полулунно).</li><li><strong>Клиника:</strong> Бедна, често безсимптомна.</li></ul><h3 style=\"color: rgb(88, 129, 87)\">Кавернозна туберкулоза</h3><p>Характеризира се с наличие на <strong>изолирана каверна</strong> (пръстеновидна сянка) без значителни възпалителни изменения наоколо.</p><ul><li><strong>Развитие:</strong> Обикновено е етап от лечението на инфилтративната форма, когато инфилтратът се резорбира, но каверната персистира.</li><li><strong>Усложнение:</strong> Опасност от руптура на съд и <strong>тежко хемоптое</strong>.</li><li>Кухината е благоприятен терен за наслагване на други инфекции (аспергилом).</li></ul><h3 style=\"color: rgb(88, 129, 87)\">Фиброзно-кавернозна туберкулоза</h3><p>Хронична форма, резултат от неадекватно лечение.</p><ul><li><strong>Характеристика:</strong> Наличие на <strong>дебелостенни (фиброзни) каверни</strong>, масивна фиброза на паренхима и деформация на бронхиалното дърво.</li><li><strong>Епидемиология:</strong> Болните са постоянни или периодични <strong>бацилоотделители</strong> (често с резистентни щамове).</li><li><strong>Протичане:</strong> Вълнообразно (тласъци и ремисии). При тласък има <strong>бронхогенно разсейване</strong> (ацинозни огнища в здравите участъци).</li><li><strong>Физикална находка:</strong> Богата – <strong>„много се вижда и много се чува“</strong>.</li><li><strong>Усложнения:</strong> Хронично белодробно сърце (Cor pulmonale), масивни сраствания, изместване на медиастинума към засегнатата страна.</li></ul><h3 style=\"color: rgb(88, 129, 87)\">Циротична туберкулоза</h3><p>Краен етап на масивна фиброза (цироза на белия дроб).</p><ul><li><strong>Характеристика:</strong> Големи участъци от фиброзна тъкан, в която има активни туберкулозни грануломи, но те са изолирани/инкапсулирани.</li><li><strong>Бацилоотделяне:</strong> Болните обикновено <strong>не са бацилоотделители</strong>.</li><li><strong>Клиника:</strong> Водещи са симптомите на дихателна и сърдечна недостатъчност, деформация на гръдния кош.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"color: rgb(88, 129, 87)\">Туберкулозен плеврит</h2><p>Може да придружава други форми или да е изолиран.</p><ul><li><strong>Клиника:</strong> Интоксикация, бодежи в гърдите, суха кашлица, задух (при големи изливи).</li><li><strong>Плеврален излив (Ексудат):</strong></li><ul><li>Серозен, сламеножълт.</li><li><strong>Лимфоцитна плеоцитоза</strong>.</li><li>Малък брой или липсващи мезотелни клетки.</li></ul><li><strong>Диагностика:</strong></li><ul><li>Високи стойности на <strong>Аденозиндеаминаза (ADA &gt; 40 IU/L)</strong>.</li><li>Позитивни IGRA тестове.</li><li>Микробиологичното доказване е трудно (рядко позитивна микроскопия). Сигурна диагноза с плеврална биопсия.</li></ul></ul><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><br><br><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">8. Белодробна туберкулоза – принципи на лечение, тубелкулостатици и терапевтични режими</h1><p>Лечението на туберкулозната инфекция е <strong>комплексно</strong> и включва комбиниране на <strong>хигиенно-диетичен режим</strong> (пълноценно хранене, богато на белтъци и витамини), <strong>медикаменти</strong> в стандартизирани режими, курортолечение, кинезитерапия и, при необходимост, <strong>оперативни методи</strong>.</p><p>Освен специфичните средства, се прилагат още имуномодулатори, антиоксиданти, кортикостероиди (в ограничени случаи – напр. при туберкулозен менингит), хепатопротективни и симптоматични средства.</p><p>Лечението винаги се съобразява с <strong>формата и тежестта</strong> на заболяването, с <strong>придружаващите заболявания</strong> на конкретния пациент и наличието на <strong>противопоказания</strong> за прилагане на определени медикаменти. То се провежда под контрол на пневмофтизиатър.</p><h2>Стратегия DOTS (Directly Observed Treatment - Short course)</h2><p>Стандартизираното лечение е част от стратегията на СЗО за контрол на туберкулозата, известна като <strong>DOTS</strong>, възприета в глобален мащаб.</p><p><strong>Стратегията DOTS има 5 компонента:</strong></p><ol><li><strong>Постоянна подкрепа</strong> от страна на държавата.</li><li>Достъп до <strong>качествена директна микроскопия</strong>.</li><li><strong>Стандартизиран кратък курс на лечение</strong> на всички случаи с туберкулоза при съответен контрол, включително <strong>пряко наблюдаване на терапията</strong>.</li><li>Редовно осигуряване на <strong>качествени медикаменти</strong>.</li><li>Система за <strong>регистриране и отчет</strong>, даваща възможност за оценка на изхода от лечението на всеки пациент и на изпълнението на програмата като цяло.</li></ol><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Основни принципи на медикаментозното лечение</h2><ol><li><strong>Винаги се прилага комбинация от няколко противотуберкулозни медикамента:</strong></li><ul><li><strong></strong>Начална (интензивна) фаза:<strong> </strong>При новооткрити болни се започва с<strong> </strong>4 (по изключение с 3) препарата<strong>. </strong>Целта е бързо елиминиране на микроорганизмите и<strong> </strong>предотвратяване на лекарствена резистентност<em></em>.</li></ul></ol><ul><li><strong></strong>Продължителна (поддържаща) фаза:<strong> </strong>Използват се<strong> </strong>2 препарата<strong>. </strong>Целта е<strong> унищожаване на </strong>дремещите микроорганизми<em></em>.</li></ul><ul><li><strong>Рецидиви/Хронични форми:</strong> Използват се други режими, които включват <strong>повече на брой лекарства</strong> и курсът на лечение е <strong>значително по-дълъг</strong>.</li></ul><ol><li><strong>Оптимални дозировки и прием:</strong></li><ul><li>Лекарствата се назначават в <strong>оптимални дозировки</strong> (съобразно телесното тегло).</li><li>Цялата дневна доза се приема <strong>еднократно</strong> за 24 часа поради бавното делене на МТ.</li><li>Даването на субоптимални дозировки може да доведе до развитие на резистентни щамове.</li><li>Даването на по-големи дозировки на свой ред често води до по-изразени странични действия.</li></ul><li><strong>Стриктно проследяване за странични ефекти:</strong></li><ul><li>Необходимо е стриктно проследяване за изява на странични ефекти, най-често от страна на <strong>черен дроб, стомах, бъбреци, зрителен, слухов, вестибуларен апарат</strong>.</li><li>Някои (напр. медикаментозен хепатит) налагат <strong>спиране на лекарството</strong>, което го е причинило, докато други могат да бъдат купирани със симптоматични средства и терапията да не се прекъсва.</li></ul><li><strong>Безплатно осигуряване на лекарствата:</strong></li><ul><li>Осигуряването на противотуберкулозни лекарства трябва да бъде <strong>безплатно</strong> поради значимостта на туберкулозата за общественото здраве.</li><li><strong>Сътрудничеството</strong> на пациента е решаващо за успеха.</li></ul><li><strong>Директно наблюдение на приема на лекарствата (</strong><strong>Directly Observed Treatment</strong> - <strong>DOT):</strong></li><ul><li>Пациентът гълта лекарствата си в <strong>присъствието на наблюдател</strong> (здравен работник, роднина или друго обучено лице).</li><li>Медикаментите трябва да са у наблюдателя и да бъдат давани на пациента само в предвиденото време.</li><li>DOT се репоръчва в <strong>началната фаза</strong> (поне при позитивните на директна микроскопия) и в <strong>продължителната фаза</strong> при рифампицин-съдържащите режими с ежедневен или интермитентен (3 пъти седично) прием.</li><li>Този елемент е от съществено значение в случаите, при които пациентите са от <strong>проблемни социални групи</strong>.</li></ul></ol><h2>Лечебни режими и Медикаменти</h2><p>Лечебните режими зависят основно от това дали пациентът е <strong>новооткрит</strong> или е провеждано лечение в миналото, и дали щамът е <strong>чувствителен или резистентен</strong>. Значение имат и формата на заболяването, съпътстващата патология и поносимостта към лекарствата.</p><ul><li>За лечение на болни с новооткрита туберкулоза се използва комбинация от <strong>перорални основни противотуберкулозни лекарства (Лекарства от I ред)</strong>:</li><ul><li>Isoniazid (H)</li></ul></ul><ul><ul><li>Rifampicin (R)</li></ul></ul><ul><ul><li><strong>Pyrazinamide (Z)</strong></li><li><strong>Ethambutol (E)</strong></li></ul></ul><hr style=\"text-align: center; border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">9. Остър бронхит</h1>Няма текст<br><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><br><br><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">10. Хроничен бронхит- дефиниция, етиология, патогенеза, класификация, клиника и лечение</h1>Няма текст.<hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><br><br><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">11. ХОББ – дефиниция, патогенеза, клиника, диагноза и класификация</h1><h2>Дефиниция</h2><p><strong>ХОББ</strong> е предотвратима и лечима болест, характеризираща се с <strong>ограничение на въздушния поток</strong> в дихателните пътища, което обикновено е <strong>прогресивно</strong> и е свързано с <strong>възпалителна реакция</strong> на белите дробове към вредни частици или газове. Екзацербациите и коморбидността допринасят за общата тежест.</p><h3>Отделни понятия, които не се включват в дефиницията:</h3><ul><li><strong>Хроничен бронхит</strong>: Наличие на кашлица и продукция на храчки в продължение на най-малко 3 месеца през всяка от две последователни години. <strong>Не е свързано с ограничение на въздушния поток</strong>.</li><li><strong>Белодробен емфизем</strong>: <strong>Разрушаване на алвеолите</strong> (патоанатомичен термин), описващ само една от няколкото структурни аномалии при пациенти с ХОББ.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Епидемиология</h2><ul><li><strong>Третата по важност причина за смъртност</strong> след исхемичното сърдечно заболяване и мозъчния инсулт.</li><li>Честотата се увеличава пропорционално на <strong>възрастта</strong>, по-често е при <strong>мъжете</strong> и сред <strong>бедните социални слоеве</strong>.</li><li>Около <strong>40-50% от случаите не се диагностицират навреме</strong>.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Рискови Фактори за ХОББ</h2><ul><li><strong>Тютюнев дим</strong> от цигари, лула, пури и др.</li><li><strong>Битово замърсяване</strong> на въздуха от био-горива в помещения с лоша вентилация.</li><li><strong>Промишлен прах</strong> и химически агенти (пари, дразнители и дим), особено при интензивно и продължително излагане.</li><li><strong>Външно замърсяване</strong> на въздуха.</li><li><strong>Тежкият наследствен дефицит на алфа-1-антитрипсин</strong> (генетичен рисков фактор).</li><li>Фактори, засягащи развитието на белите дробове по време на бременността и в детска възраст (ниско тегло при раждане, респираторни инфекции и др.).</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Патогенеза</h2><h4>Възпаление</h4><ul><li><strong>Основна роля</strong> играят <strong>неутрофили, макрофаги, Т-лимфоцити (CD8+ Т-лимфоцити)</strong> и <strong>цитокини</strong>.</li><li>Възпалителните клетки освобождават цитокини и медиатори, като най-важните са <strong>левкотриен-4 (LT4)</strong>,<strong> интерлевкин-8 (IL-8)</strong> и<strong> тумор некротичен фактор-алфа (TNF алфа)</strong>.</li><li>Характерно е, че това възпаление <strong>персистира след прекратяване на тютюнопушенето</strong>.</li><li>При някои пациенти може да се повишат <strong>еозинофилите</strong> (по време на тежки екзацербации).</li></ul><h4>Нарушен баланс протеази/антипротеази</h4><ul><li><strong>Повишена продукция (или активност) на протеази</strong> или <strong>намалена продукция (или активност) на антипротеази</strong>.</li><li><strong>Основни протеази</strong>: отделените от неутрофилите протеази (<strong>еластаза</strong>, катепсин G и протеиназа-3). Неутрофилната еластаза предизвиква директна паренхимна деструкция, мукусна хиперсекреция и хиперплазия на мукозните жлези.&nbsp;Макрофагите освобождават катепсини В, L, S и различните матриксни металопротеинази (MMPs).</li><li><strong>Основни антипротеази</strong>: <strong>алфа-1-антитрипсин</strong> и тъканният инхибитор на металопротеазите (TiMMPs).</li></ul><h4>Оксидативен стрес</h4><ul><li><strong>Увеличена експозиция на оксиданти</strong> и/или <strong>намален антиоксидантен капацитет</strong>.</li><li>Оксидативният стрес се идентифицира чрез повишение на различни маркери в тъканите на белия дроб, издишания въздух и урината на болни с ХОББ (H2O2, NO и един продукт на липидното окисление - изопростан F2α-III).</li><li><strong>Ефекти</strong>: окисляване на биологични молекули, увреда на екстрацелуларния матрикс, инактивиране на антипротеази, активиране на протеази, усилване на генната експресия на проинфламаторни белтъци.</li><li>Реактивните съединения в цигарения дим причиняват <strong>екзогенен оксидативен стрес</strong>, който се наслагва върху <strong>ендогенния</strong>, възникнал от действието на реактивни кислородно молекули, освободени от клетки на възпалителния процес.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Патофизиология</h2><h4>Мукусна хиперсекреция и дисфункция на ресничките</h4><ul><li>Първите типични изменения при ХОББ.</li><li>Рисковите фактори повишават секрецията от мукусните жлези, появява се сквамозна метаплазия и цилиарна инсуфициенция и дисфункция.</li></ul><h4>Ограничение на въздушния поток и хиперинфлация</h4><ul><li>Ограничението на въздушния поток е основен патофизиологичен механизъм при ХОББ.</li><li><strong>Ограничението на въздушния поток</strong> е главно в <strong>бронхи и бронхиоли с вътрешен диаметър &lt; 2 mm</strong>.</li><li><strong>Причини</strong>: <strong>ремоделиране (фиброза и стесняване на лумена)</strong>, загуба на еластични сили (деструкция на алвеоларната стена), деструкция на съединително тъканните алвеоларни връзки, натрупване на мукус и възпалителен ексудат, гладкомускулен спазъм.</li><li>Прогресиращото ограничение води до <strong>белодробно свръхраздуване (хиперинфлация)</strong>, нарастване на функционалния остатъчен капацитет (ФОК), както и нарастване на отношението остатъчен обем към тотален белодробен капацитет (ОО/ТБК)<strong></strong>. Динамичната хиперинфлация е ключов фактор, свързан с ограниченията при физическо натоварване и диспнеята.</li></ul><h4>Патологични промени в кръвно-газовата обмяна</h4><ul><li>Наблюдават се при напреднало заболяване: <strong>артериална хипоксемия</strong> с или без <strong>хиперкапния</strong>.</li><li><strong>Основен механизъм</strong>: Несъответствие в отношението <strong>вентилация/перфузия (VA/Q)</strong>, причинено от анатомичните увреждания.</li><li><strong>Допълнителни фактори</strong>:</li><ul><li>Разрушаване на алвеоларната повърхност, свързано с развитието на белодробния емфизем, намалява трансфер фактора <strong>DLCO/VA</strong> и пречи на газовата обмяна.</li><li>За нарушението на газообмяна допринасят и различните патологични типове дишане и умора на дихателната мускулатура. Те могат да причинят допълнително влошаване на КГА с развитие на хиперкапния и дихателна ацидоза.</li></ul></ul><h4>Пулмонална хипертония</h4><ul><li>Наблюдава се <strong>късно</strong> в еволюцията, след развитие на тежки нарушения в газовата обмяна.</li><li><strong>Причини</strong>: вазоконстрикция (главно от хипоксия), ендотелна дисфункция, ремоделиране на пулмоналните артерии и разрушаване на белодробните капиляри (от емфизема).</li><li>Може да доведе до <strong>дясна вентрикуларна хипертрофия и дисфункция (cor pulmonale)</strong>.</li></ul><h4>Системни ефекти и съпътстващи заболявания</h4><ul><li>Резултат от системното възпаление: скелетно-мускулна слабост, <strong>кардиоваскуларни заболявания</strong>, ендотелната дисфункция, артериалното „втвърдяване” (stiffness), атеросклерозата, остеопорозата, захареният диабет II тип, метаболитният синдром, анемията, ГЕРБ, белодробният карцином, сънната апнея.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Клинична Картина</h2><ul><li><strong>Хронична кашлица:</strong> Интермитентно или ежедневно, често през целия ден, рядко нощем.</li><li><strong>Експекторация:</strong></li><ul><li>Вискозна, слузна и в малко количество.</li><li>Първоначално само сутрин.</li><li><strong>Хроничен бронхит</strong>: отделяне на храчки за 3 месеца в 2 последователни години.</li><li>Промяна в цвета (гнойна) или обема се свързва с инфекциозен причинител (най-често <strong>H. influenzae</strong>).</li></ul><li><strong>Диспнея (задух):</strong></li><ul><li>Прогресира и става постоянна.</li><li>В началото при физическо натоварване, с напредване - при минимално усилие или в покой.</li><li><strong>Количествена оценка</strong>: Modified Medical Research Council scale (<strong>mMRC</strong>).</li></ul><li><strong>Анамнеза:</strong></li><ul><li>Излагане на рискови фактори (тютюнопушене, био-горива, пари, дим и др.).</li></ul></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Физикално Изследване</h2><p>В ранните стадии на заболяването физикалната находка е нормална. </p><p>С напредване на заболяването се появяват признаци, в напреднал стадий те са патогномонични.</p><p>Физикалното изследване включва оценка на респираторните и системните прояви на ХОББ, а също така и изчисляване на индекса на телесната маса - Body Mass Index.</p><ul><li><strong>Оглед</strong></li><ul><li><strong>Централна </strong><strong>цианоза&nbsp;</strong>или промяна в цвета на лигавиците.</li><li>Патологични промени в гръдния кош от свръхраздуването: <strong>“бъчвовиден” гръден кош</strong>, хоризонтално разположение на ребрата, изпъкнал корем.</li><li>Изглаждането на диафрагмалните куполи може да бъде комбинирано с парадоксално хлътване на долната част на гръдната клетка при вдишване, намалено сърдечно притъпление и разширение на ъгъла между мечовидния израстък и тялото на гръдната кост.</li></ul><li><strong>Палпация и Перкусия</strong></li><ul><li>Намалена респираторна подвижност на диафрагмата.</li><li><strong>Хиперсонорен или тимпаничен перкуторен тон</strong> (резултат на свръхраздуване или були).</li><li>Откриването на сърдечния връх може да е трудно поради свръхраздуването на белите дробове.</li><li>Изместване на черния дроб надолу поради свръхраздуването.</li></ul><li><strong>Аускултация</strong></li><ul><li>Често <strong>отслабено дишане</strong>.</li><li>Наличие на <strong>свиркания</strong> при спокойно дишане (полезен показател за ограничение на въздушния поток).</li><li>Сърдечните тонове се чуват най-добре в областта на мечовидния израстък. Признаци на <strong>кор пулмонале</strong>: акцентуиран <strong>II</strong> тон на пулмоналната артерия, шумове на пулмонална или трикуспидална инсуфициенция.</li></ul></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Изследвания</h2><h4>1. Спирометрия</h4><ul><li><strong>Предпочитан метод</strong> за измерване на ограничението на въздушния поток.</li><li><strong>Характерно</strong>: Намаление на <strong>ФЕО1</strong>, <strong>ФВК</strong>, <strong>ФЕО1/ФВК</strong> (Индекс на Тифно).</li><li><strong>Диагностичен критерий</strong>: <strong>ФЕО1/ФВК</strong> <strong>след бронходилатация &lt; 0.7</strong>.</li><li><strong>Бронходилататорен тест</strong> (<strong>Salbutamol</strong> 400 мкг): Обикновено отрицателен, за разлика от асмата (повишение <strong>&lt; 12%</strong> спрямо предвидените стойности и <strong>&lt; 200 мл</strong> в абсолютна стойност).</li></ul><h4>Класификация на тежестта на ХОББ (GOLD)</h4><table><tbody><tr><td><strong><span style=\"color: rgb(88, 129, 87)\">GOLD</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Тежест</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">ФЕО1 (пост-бронходилататорно)</span></strong></td></tr><tr><td>1</td><td>Лека</td><td>≥80% от предвидения</td></tr><tr><td>2</td><td>Умерена</td><td>50% ≤ ФЕО1 &lt; 80%</td></tr><tr><td>3</td><td>Тежка</td><td>30% ≤ ФЕО1 &lt; 50%</td></tr><tr><td>4</td><td>Много тежка</td><td>ФЕО1 &lt; 30% от предвидения</td></tr></tbody></table><h4>2. Рентгенография на гръден кош - <a href=\"https://radiopaedia.org/articles/copd-summary?lang=us\">Radiopedia</a></h4><ul><li><strong>Не е диагностична</strong>, но изключва алтернативни диагнози.</li><li><strong>Рентгенови белези на емфизем</strong>: широки междуребрия, хоризонтален ход на ребрата, ниско разположени \"плоски\" диафрагми, капковидно сърце, повишена белодробна просветляемост.</li></ul><h4>3. Кръвно-газов анализ (КГА)</h4><ul><li>Извършва се при <strong>ФЕО1 &lt; 50%</strong> или при клиника, подсказваща дихателна/дясна сърдечна недостатъчност.</li><li>Клинично изявена дихателна недостатъчност: <strong>РаО2 &lt; 8.0 kPa (60 mmHg)</strong>, с или без <strong>РаСО2 &gt; 6.7 kPa (50 mmHg)</strong>.</li></ul><h4>4. ЕКГ</h4><ul><li>Електрокардиографски белег на <strong>белодробното сърце</strong>: <strong>p-pulmonale</strong> (висока (&gt; 2.5 mm), островърха <strong>p</strong> - вълна във <strong>II, III, aVF</strong> и бифазна в <strong>V1</strong>).</li><li><strong>Хронично белодробно сърце</strong>: завъртане на електрическата ос към патологична дясна позиция, пълен или непълен десен бедрен блок, дълбоки S зъбци в прекордиалните отвеждания срещу лява камера (V4 - V6) и др.</li></ul><h4>5. Тестове при селектирани пациенти</h4><ul><li><strong>Скрининг за алфа-1-антитрипсинов дефицит</strong>: когато при лица от бялата раса се диагностицира ХОББ под 40-годишна възраст или има фамилна анамнеза за ХОББ.</li><li><strong>Статични белодробни обеми</strong>:</li><ul><li>Включват тотален белодробен капацитет (ТБК), остатъчен обем (ОО), съотношението остатъчен обем към тоталния белодробен капацитет ОО/ТБК.</li><li>Те характеризират тежките форми на ХОББ, където са повишени.</li><li>Инспираторният капацитет (ИК) е намален и корелира с белодробната хиперинфлация.</li><li>Статичните белодробни обеми се изследват при пациенти с напреднало заболяване и при подготовката за хирургическа интервенция.</li></ul><li><strong>Трансферен фактор на белия дроб за CO (TLco)</strong>: обичайно намален (особено при емфизем).</li><li><strong>Тестове с физическо натоварване</strong>: Шестминутен тест с ходене (<strong>6MWT</strong>).&nbsp;Използва се при селекция за програми за пулмонална рехабилитация или хирургическо лечение.</li><li><strong>HRCT (Компютърна томография с висока разделителна способност)</strong>: за контрол на диагнозата, предоперативно при&nbsp;булектомия или обем-редуцираща хирургия. Установява ранните емфизематозни промени.</li><li><strong>Полисомнография</strong>: при съмнение за сънна апнея.</li><li><strong>Изследване функцията на респираторните мускули</strong> (Plmax и РЕтах): изследва се при пациенти с лошо хранене и съмнение за стероидна миопатия.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Комплексна Оценка на ХОББ</h2><p>Включва <strong>симптоми</strong>, <strong>белодробна функция (ФЕО1)</strong> и <strong>честота на екзацербации</strong>.</p><p><strong>Старата класификация на GOLD:</strong></p><table><tbody><tr><td><strong><span style=\"color: rgb(88, 129, 87)\">Симптоми</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Ограничение на ФЕО1</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Честота на екзацербации</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Група</span></strong></td></tr><tr><td><strong>Малко симптоми</strong> (<strong>mMRC 0-1</strong> или <strong>CAT &lt; 10</strong>)</td><td><strong>GOLD 1</strong> или <strong>2</strong></td><td><strong>0 или 1</strong> екзацербация, <strong>без</strong> хоспитализаци</td><td><strong>A</strong></td></tr><tr><td><strong>Повече симптоми</strong> (<strong>mMRC &gt; 2</strong> или <strong>CAT &gt; 10</strong>)</td><td><strong>GOLD 1</strong> или <strong>2</strong></td><td><strong>0 или 1</strong> екзацербация, <strong>без</strong> хоспитализаци</td><td><strong>B</strong></td></tr><tr><td><strong>Малко симптоми</strong> (<strong>mMRC 0-1</strong> или <strong>CAT &lt; 10</strong>)</td><td><strong>GOLD 3</strong> или <strong>4</strong></td><td><strong>&gt;= 2</strong> умерени екзацербации <strong>или</strong> <br> <strong>&gt;= 1</strong> екзацербация, изискваща <strong>хоспитализация</strong></td><td><strong>C</strong></td></tr><tr><td><strong>Повече симптоми</strong> (<strong>mMRC &gt; 2</strong> или <strong>CAT &gt; 10</strong>)</td><td><strong>GOLD 3</strong> или <strong>4</strong></td><td><strong>&gt;= 2</strong> умерени екзацербации <strong>или</strong> <br> <strong>&gt;= 1</strong> екзацербация, изискваща <strong>хоспитализация</strong></td><td><strong>D</strong></td></tr></tbody></table><p><strong>Новата класификация на GOLD:</strong></p><table><tbody><tr><td><strong><span style=\"color: rgb(88, 129, 87)\">Категория</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Симптоми</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Честота на екзацербации (за предходната година)</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Терапевтична цел</span></strong></td></tr><tr><td><strong>A</strong></td><td><strong>Малко симптоми</strong> (<strong>mMRC 0-1</strong> или <strong>CAT &lt; 10</strong>)</td><td><strong>0 или 1</strong> екзацербация, <strong>без</strong> хоспитализация</td><td>Намаляване на симптомите</td></tr><tr><td><strong>B</strong></td><td><strong>mMRC &gt;= 2</strong> или <strong>CAT &gt;= 10</strong></td><td><strong>Нисък риск</strong> (<strong>0 или 1</strong> екзацербация, <strong>без</strong> хоспитализация)</td><td>Намаляване на симптомите</td></tr><tr><td><strong>E</strong></td><td><strong>Малко или повече симптоми</strong> (mMRC/CAT)</td><td><strong>&gt;= 2</strong> умерени екзацербации <strong>или</strong> <br> <strong>&gt;= 1</strong> екзацербация, изискваща <strong>хоспитализация</strong></td><td>Намаляване на екзацербациите</td></tr></tbody></table><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Диференциална Диагноза</h2><table><tbody><tr><td><strong><span style=\"color: rgb(88, 129, 87)\">Характеристика</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">ХОББ</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Астма</span></strong></td></tr><tr><td><strong>Начало</strong></td><td>Средна възраст</td><td>Млада възраст (детство)</td></tr><tr><td><strong>Симптоми</strong></td><td>Развиват се бавно</td><td>Варират от ден на ден (нощем/рано сутрин)</td></tr><tr><td><strong>Анамнеза</strong></td><td>Продължително тютюнопушене</td><td>Алергия, ринит, екзема, фамилна анамнеза</td></tr><tr><td><strong>Ограничение на ВП</strong></td><td><strong>Подчертано необратимо</strong></td><td><strong>Подчертано обратимо</strong></td></tr></tbody></table><h4>Други заболявания:</h4><ul><li><strong>Застойна сърдечна недостатъчност</strong>: Дребни влажни хрипове. Рентгенът показва дилатирано сърце, белодробен едем. <strong>ФИД</strong> установява <strong>рестрикция</strong>, а не обструкция.</li><li><strong>Бронхиектазии</strong>: Голямо количество гнойни храчки. Груби, разнокалибрени хрипове. Рентгенография показва бронхиална деформация, задебеляване на бронхиалните стени.</li><li><strong>Туберкулоза</strong>: Може да започне по всяко време. Рентгенът показва белодробен инфилтрат/нодуларни лезии. Микробиологично потвърждение.</li><li><strong>Облитериращ бронхиолит</strong>: По-млада възраст, непушачи. Анамнеза за ревматоиден артрит. <strong>КАТ</strong> показва зони с намалена плътност.</li><li><strong>Дифузен панбронхиолит</strong>: Повечето мъже и непушачи. Хроничен синуит. <strong>КАТ</strong> показва дифузни, малки, центролобуларни, нодуларни затъмнения и свръхраздуване.</li></ul><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><br><br><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">12. Лечение на стабилна ХОББ</h1><h2>Лечение за Превенция и Поддържаща Терапия</h2><h4>Спиране на тютюнопушенето</h4><ul><li><strong>Медикаменти</strong>: varenicline, bupropion SR, никотинови заместители (дъвки, инхалери, спрейове, лепенки).</li><li><strong>Допълнително</strong>: психотерапевт, социални групи.</li></ul><h4>Основни групи медикаменти при стабилна ХОББ</h4><p><strong>1. Бронходилататори</strong></p><p>Медикаменти, които повишават <strong>ФЕО1</strong>, облекчават издишването, намаляват динамичната хиперинфлация и подобряват физическия капацитет. Прилагат се инхалаторно.</p><table><tbody><tr><td><strong><span style=\"color: rgb(88, 129, 87)\">Група</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Съкращение</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Примери</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Продължителност</span></strong></td></tr><tr><td>Кратко действащи бета-2-агонисти</td><td><strong>Б2АКД</strong></td><td><strong>Salbutamol</strong>, <strong>Fenoterol</strong></td><td>4-6 ч.</td></tr><tr><td>Дълго действащи бета-2-агонисти</td><td><strong>Б2АДД</strong></td><td><strong>Salmeterol</strong>, <strong>Formoterol</strong>, <strong>Indacaterol</strong>, <strong>Vilanterol</strong>, <strong>Olodaterol</strong></td><td>12-24 ч.</td></tr><tr><td>Кратко действащи антихолинергици</td><td><strong>АХКД</strong></td><td><strong>Ipratropium bromide</strong></td><td>6-8 ч.</td></tr><tr><td>Дълго действащи антихолинергици</td><td><strong>АХДД</strong></td><td><strong>Tiotropium bromide</strong>, <strong>Glycopyrronium bromide</strong>, <strong>Umeclidinium bromide</strong>, <strong>Aclidinium bromide</strong></td><td>12-24 ч.</td></tr></tbody></table><ul><li><strong>Б2АДД</strong> и <strong>АХДД</strong> са <strong>предпочитани</strong>.</li><li><strong>Странични ефекти на Б2АДД</strong>: тахикардия, тремор, рядко хипокалиемия/</li><li><strong>Странични ефекти на АХДД</strong>: сухота/метален вкус в устата. Избягват се при глаукома и простатна хиперплазия.</li></ul><p><strong>2. Метилксантини (Theophylline)</strong></p><ul><li>Действат като неселективни фосфодиестеразни инхибитори.</li><li><strong>Токсичност</strong>: дозозависима, с малка терапевтична ширина.</li></ul><p><strong>3. Комбинирани препарати</strong></p><ul><li><strong>Б2АДД + АХДД</strong></li><li><strong>Б2АДД + Инхалаторни кортикостероиди (ИКС)</strong>: По-ефективни поради синергичен ефект. Препоръчват се при <strong>еозинофили в кръвта &gt;= 300 клетки/микролитър</strong>.</li><li><strong>Тройни комбинации (ИКС + Б2АДД + АХДД)</strong></li></ul><p><strong>4. Системни (орални и парентерални) кортикостероиди (Methylprednisolone, Prednisone)</strong></p><ul><li><strong>Не са подходящи за продължително лечение</strong> (поради странични ефекти: стероидна миопатия, остеопороза, диабет, хипертония).</li></ul><p><strong>5. Фосфодиестераза-4-инхибитори (ФД4И) (Roflumilast)</strong></p><ul><li>Подтискат възпалението чрез инхибиране на разграждането на <strong>цАМФ</strong>.</li><li><strong>Странични ефекти</strong>: загуба на апетит, гадене, диария, загуба на тегло.</li></ul><p><strong>6. Ваксини</strong></p><ul><li><strong>Противогрипни ваксини</strong>: веднъж годишно.</li><li><strong>Пневмококова полизахаридна ваксина</strong>: при пациенти над 65 г. или <strong>ФЕО1 &lt; 40%</strong>.</li></ul><p><strong>7. Антибиотици</strong></p><ul><li><strong>Профилактично прилагане (азитромицин, моксифлоксацин)</strong> намалява честотата на екзацербациите.</li></ul><p><strong>8. Муколитични агенти (амброксол, ердостеин, карбоцистеин)</strong></p><ul><li>Намаляват честотата на екзацербациите.</li></ul><p><strong>9. Противокашлични медикаменти</strong></p><ul><li>Редовната употреба е <strong>противопоказана</strong> при стабилна ХОББ.</li></ul><h4>Рехабилитация</h4><ul><li>Физически тренировки.</li><li>Консултации за храненето.</li><li>Обучение.</li></ul><h4>Продължителна домашна кислородотерапия (LTOT)</h4><ul><li>Продължава <strong><u>поне 15 ч/24 ч</u></strong>.</li><li><strong>Показания</strong>: <strong>РаО2 &lt; 7.3 kPa (55 mmHg)</strong> или <strong>SaO2 &lt; 88%</strong>; или <strong>РаО2 &lt; 8.0 kPa (60 mmHg)</strong>, ако има белодробна хипертония, периферен едем или полицитемия (<strong>Hct &gt; 55%</strong>).</li></ul><h4>Неинвазивна вентилация (NIV)</h4><ul><li>Използва се при пациенти със стабилна много тежка ХОББ и изразена хиперкапния.</li></ul><h4>Хирургическа намеса</h4><ul><li><strong>Булектомия</strong> (отстраняване на були).</li><li><strong>Обем-редуциращи хирургични процедури (LVRS)</strong>: При изразен емфизем в горните лобове.</li><li><strong>Белодробна трансплантация</strong>.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Фармакологични Терапевтични Алгоритми</h2><p><strong>Начално Фармакологично Лечение -&nbsp;</strong>Бързодействащите бронходилататори<strong> </strong>трябва да се предписват на всички пациенти за незабавно облекчаване на симптомите.</p><table><tbody><tr><td><strong><span style=\"color: rgb(88, 129, 87)\">Група</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Препоръчвани медикаменти</span></strong></td></tr><tr><td><strong>A</strong></td><td>Бронходилататор (КД или ДД).<br>Продължава, ако има полза.</td></tr><tr><td><strong>B</strong></td><td><strong>Б2АДД или АХДД</strong>.<br>При тежък задух: <strong>Б2АДД/АХДД</strong>.</td></tr><tr><td><strong>C</strong></td><td><strong>АХДД</strong> (по-добри от <strong>Б2АДД</strong> за предотвратяване на екзацербации).</td></tr><tr><td><strong>D</strong></td><td><strong>АХДД</strong> (ефект върху задуха и екзацербациите).<br>При по-тежки симптоми: <strong>АХДД/Б2АДД</strong>. <br>При еозинофили <strong>&gt;= 300 клетки/микролитър</strong> или анамнеза за астма: <strong>Б2АДД/ИКС</strong>.</td></tr></tbody></table><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Прогноза на ХОББ</h2><p>Средната преживяемост при пациенти с <strong>ХОББ</strong> е около 10 години. </p><h4>Фактори за неблагоприятна прогноза (кратка преживяемост)</h4><ul><li><strong>Функционални показатели:</strong> Ниско <strong>ФЕО1</strong> и нисък дифузионен капацитет (<strong>DLCO</strong>).</li><li><strong>Клинични симптоми:</strong> Тежка <strong>диспнея</strong> и <strong>тахикардия</strong> в покой.</li><li><strong>Лабораторни и физикални промени:</strong></li><ul><li><strong>Хипоксемия</strong>.</li><li><strong>Анемия</strong>.</li><li>Значителна загуба на тегло.</li></ul><li><strong>Усложнения и прогресия:</strong></li><ul><li><strong>Cor pulmonale</strong> (белодробно сърце).</li><li>Чести <strong>екзацербации</strong>.</li></ul><li><strong>Рискови фактори и коморбидност:</strong></li><ul><li>Активно тютюнопушене.</li><li>Наличие на тежки съпътстващи заболявания.</li></ul></ul><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><br><br><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">13. Лечение на ХОББ в екзацербация</h1><h2>Дефиниция</h2><p><strong>Остро събитие</strong>, характеризиращо се с влошаване на респираторните симптоми, което надвишава нормалните дневни колебания и налага промяна в провежданата терапия.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Епидемиология</h2><ul><li><strong>Екзацербациите</strong> са основната причина за болестност и смъртност при пациенти с <strong>ХОББ</strong>.</li><li>Заболяването е икономически по-значимо от астмата, като между 50% и 75% от общите разходи за лечение се дължат именно на епизодите на обостряне.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Клинична картина</h2><h3>Големи симптоми</h3><ul><li>Влошаване на <strong>диспнеята.</strong></li><li>Повишаване на количеството на <strong>експекторацията</strong>.</li><li><strong>Гнойна експекторация</strong>.</li></ul><h4>Малки симптоми</h4><ul><li>Хриптене и кашлица.</li><li>Болки в гърлото и хрема.</li><li><strong>Фебрилитет</strong>.</li></ul><h3>Диагнозата екзецербация на ХОББ се поставя при наличие на:</h3><ul><li>Два големи симптома.</li><li>Един голям и един малък симптом в продължение на 48 часа.</li><li><strong>Важно:</strong> При болни в <strong>IV стадий</strong>, най-важният симптом за тежка екзацербация е <strong>промяна в съзнанието</strong>, което е индикация за спешна хоспитализация.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Оценка на тежестта</h2><h4>Според симптоматиката:</h4><ul><li><strong>Тип I (тежка):</strong> Наличие на 3-те големи симптома.</li><li><strong>Тип II (средно тежка):</strong> Наличие на 2 от 3-те големи симптома.</li><li><strong>Тип III (лека):</strong> Наличие на 1 от 3-те големи симптома.</li></ul><h4>Според нивото на използване на здравни ресурси:</h4><ul><li><strong>Лека:</strong> Изисква само промяна в поддържащото лечение.</li><li><strong>Умерено-тежка:</strong> Налага лечение с <strong>антибиотик</strong> и/или <strong>кортикостероид</strong>.</li><li><strong>Тежка:</strong> Налага посещение в спешно звено или <strong>хоспитализация</strong>.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Диагностични методи</h2><h3>1. Анамнеза</h3><h3>2. Белодробна функция</h3><ul><li><strong>ВЕД &lt; 100 L/min</strong> или <strong>ФЕО1 &lt; 1 L</strong> са показатели за тежка екзацербация (трудно изпълними при тежко състояние).</li></ul><h3>3. Артериални кръвни газове (АКР)</h3><ul><li><strong>PaO2 &lt; 8.0 kPa (60 mmHg)</strong>&nbsp;и/или <strong>SaO2 &lt; 90%</strong>&nbsp;с или без PaCO2 &gt; 6,7 kPa (50mmHg) при дишане на атмосферен въздух показват влошаване на <strong>дихателната недостатъчност</strong>.</li><li><strong>Ацидоза (pH &lt; 7.36)</strong> и <strong>хиперкапния (PaCO2 &gt; 6-8 kPa)</strong> при пациент с дихателна недостатъчност е показание за обсъждане на прилагане на подпомагане на дишането (неинвазивна или инвазивна вентилация).</li></ul><h3>4. Образна и инструментална диагностика</h3><ul><li><strong>Рентгенография на гръден кош:</strong> За изключване на алтернативни диагнози.</li><li><strong>Електрокардиография (ЕКГ):</strong> За диагностика на <strong>хипертрофия на дясната камера</strong>, аритмии или исхемия.</li></ul><h3>5. Лабораторни изследвания</h3><ul><li><strong>Бактериологично изследване на храчка:</strong> Идентифицира причинителя при липса на ефект от лечението.</li><li><strong>Биохимични тестове:</strong> За откриване на електролитни разстройства (<strong>хипонатриемия</strong>, <strong>хипокалиемия</strong>), диабетна криза или <strong>хипопротеинемия</strong>.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Диференциална диагноза</h2><ul><li>Пневмония</li><li>Пневмоторакс</li><li>Лява сърдечна недостатъчност / белодробен едем</li><li>Белодробна емболия</li><li>Белодробен рак</li><li>Обструкция на горните дихателни пътища</li><li>Плеврален излив</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Лечение</h2><h3>Бронходилататори</h3><ul><li>Увеличаване на дозата или честотата на инхалиране.</li><li>Добавяне на медикамент от друга група.</li><li>Използване на <strong>небулайзер</strong> за по-високи дози.</li></ul><h3>Глюкокортикостероиди</h3><ul><li>При <strong>ФЕО1 &lt; 50%</strong> се добавят 30-40 mg <strong>prednisolone</strong> за 7-10 дни.</li></ul><h3>Антибиотично лечение</h3><p>Препоръчва се при:</p><ul><li>Екзацербация <strong>Тип I</strong>.</li><li>Екзацербация <strong>Тип II</strong> с гнойни храчки.</li><li>Тежки състояния, изискващи <strong>механична вентилация</strong>.</li><li><strong>Основни групи:</strong>&nbsp;Аминопеницилини с бета-лактамазни инхибитори, макролиди, цефалоспорини (II/III поколение), респираторни флуороквинолони.</li></ul><p>Антибиотици не се препоръчват при тип III екзацербация.</p><h3>Кислородолечение</h3><p>Трябва да бъде:</p><ul><li><strong>Непрекъснато&nbsp;</strong></li><li><strong>Дозирано </strong>(ниско <strong>FiO2 0.24-0.28</strong>), особено при високостепенна хиперкапния</li><li><strong>Контролирано </strong>(с кръвно-газов анализ) - целта е да се постигне адекватно ниво на оксигенация РаО2 &gt; 8.0 kPa (60 mmHg) и/или SaO2 &gt; 90%.</li></ul><h3>Вентилация</h3><ul><li><strong>Неинвазивна механична вентилация (NIV):</strong> През назална или лицева маска.</li><li><strong>Инвазивна вентилация:</strong> Чрез ендотрахеална тръба.</li></ul><h3>Други лечебни мерки</h3><ul><li>Прилагане на течности и адекватно хранене.</li><li>Профилактика с <strong>нискомолекулен хепарин</strong>.</li><li><strong>Муколитични средства</strong>.</li><li>Мануална/механична перкусия и <strong>постурален дренаж</strong>.</li></ul><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><br><br><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">14. Бронхиална астма - дефиниция, патогенеза, клиника, диагноза и класификация</h1><h3>Дефиниция</h3><p>Астмата е <strong>хетерогенно заболяване</strong>, което обичайно се характеризира с <strong>хронично възпаление на дихателните пътища</strong>. Дефинира се с анамнеза за респираторни симптоми – <strong>хриптене, задух, стягане в гърдите и кашлица</strong>, които се променят във времето и по интензивност, заедно с <strong>вариабилно ограничение на въздушния поток</strong>, което по-късно може да стане персистиращо.</p><ul><li>Ограничението на въздушния поток може да се нормализира спонтанно или под влияние на лечението и понякога могат да липсват за седмици или месеци.</li><li>Астмата се асоциира с <strong>бронхиална хиперреактивност</strong> към директни и индиректни стимули.</li><li>Пациентите могат да получат <strong>животозастрашаващи екзацербации</strong>.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Фенотипи на Бронхиална Астма</h2><p>Астмата е хетерогенно заболяване с различни подлежащи болестни процеси. Фенотипите са разпознаваеми клъстери от демографски, клинични и/или патофизиологични характеристики. (Класификация според Wenzel)</p><h4>I. Th2 Астма (Еозинофилно Възпаление)<strong>&nbsp;</strong></h4><h4><strong>1. Ранно начало, Алергична Астма</strong></h4><ul><li><strong>Характеристики: </strong>Ранно начало, лека до тежка, алергични симптоми и други заболявания.</li><li><strong>Биомаркери:</strong> Специфични IgE, Th2 цитокини (IL-4/IL-13), задебелена базална мембрана.</li><li><strong>Терапевтичен отговор</strong>: Кортикостероид чувствителна, Th2 таргетирана терапия.</li></ul><p><strong>2. Късно начало, Еозинофилна Астма</strong></p><ul><li><strong>Характеристики: </strong>Късно начало, често тежка, по-малко алергична.</li><li><strong>Биомаркери: </strong>Кортикостероид-резистентна еозинофилия, IL-5.</li><li><strong>Терапевтичен отговор</strong>: Чувствителна към антитела срещу IL-5 и цистеинил левкотриенови модификатори, кортикостероид резистентна.</li></ul><p><strong>3. Астма, Индуцирана от Физическо Натоварване</strong></p><ul><li><strong>Характеристики: </strong>Лека, интермитентна при физическо натоварване.</li><li><strong>Биомаркери: </strong>Активирани мастни клетки, Th-2 цитокини (IL-9), цистеинил левкотриени.</li><li><strong>Терапевтичен отговор</strong>: Чувствителна към цистеинил левкотриенови модификатори, бета агонисти и антитела срещу IL-9.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h4>II. Не-Th2 Астма (Нееозинофилно Възпаление)</h4><h4><strong>1. Астма при Затлъстяване</strong></h4><ul><li><strong>Характеристики: </strong>Късно начало, предимно при жени, много симптоми, по-малко изразена бронхиална хиперреактивност, ниско ФЕО1, увеличен блокиран газ (air trapping).</li><li><strong>Биомаркери: </strong>Липса на Th2 биомаркери, оксидативен стрес, ADMA.</li><li><strong>Терапевтичен отговор</strong>: Чувствителна към отслабване, антиоксиданти и възможен отговор към хормонална терапия.</li></ul><p><strong>2. Неутрофилна Астма</strong></p><ul><li><strong>Характеристики: </strong>Ниско ФЕО1, повече блокиран газ (air trapping).</li><li><strong>Биомаркери: </strong>Неутрофилия в спутум, Th17 маркери, IL-8.</li><li><strong>Терапевтичен отговор</strong>: Възможен отговор към макролидни антибиотици.</li></ul><p><strong>3. Астма при Пушачи</strong></p><ul><li><strong>Характеристики: </strong>Пасивно или активно тютюнопушене, намаляващо ФЕО1, резистентна към стероиди.</li><li><strong>Биомаркери:</strong> Намалено FeNO.</li><li><strong>Терапевтичен отговор</strong>: Възможен отговор при спиране на тютюнопушенето.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h3>Епидемиология</h3><ul><li><strong>Честота</strong>: Едно от най-честите хронични заболявания в световен мащаб.</li><li>Засяга <strong>10-15%</strong> от децата и <strong>5-10%</strong> от възрастните.</li><li>Засегнати са <strong>339 милиона</strong> души по света (над 400 000 в България).</li><li><strong>Разпределение по пол</strong>: По-често при момчетата в детството (2:1). След пубертета преобладават жените.</li><li><strong>Нарастване на честотата</strong> е свързано със замърсяването на въздуха, пасивното тютюнопушене, урбанизацията и „западния\" стил на живот.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h3>Рискови Фактори</h3><ul><li><strong>Генетични</strong> (гени, предразполагащи към атопия и бронхиална хиперреактивност).</li><li><strong>Алергени</strong> (акари в домашния прах, животни и по-специално котка и куче, хлебарки, гъби, полени).</li><li><strong>Инфекции</strong> на респираторния тракт (предимно вирусни - РСВ, риновирус и други).</li><li><strong>Тютюнопушене</strong> (активно, пасивно).</li><li><strong>Замърсители</strong> на въздуха и промишлени дразнители.</li><li><strong>Физическо натоварване</strong>, хипервентилация.</li><li><strong>Лекарства</strong>: Аспирин или НПВС, бета-адренергични блокери (включително капки за очи).</li><li><strong>Коморбидни състояния</strong>: Гастро-езофагеална рефлуксна болест, хронични синузити или ринити.</li><li><strong>Затлъстяване</strong> (асоциация между астма и нарушен липиден и глюкозен метаболизъм).</li><li><strong>Диета</strong> (нисък прием на антиоксиданти и омега-3 мастни киселини).</li><li><strong>Емоционални фактори</strong> или <strong>стрес</strong>.</li><li><strong>Перинатални фактори</strong> (преждевременно раждане, напреднала възраст на майката, пренатална експозиция на тютюнев дим).</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h3>Патогенеза</h3><h4>1. Възпаление на Дихателните Пътища</h4><p>Астмата е възпалително заболяване, което ангажира големите и малките дихателни пътища.</p><ul><li><strong>Възпалителни клетки</strong>: Дендритни клетки, макрофаги, Т-лимфоцити (Th-0, Th-2, Th-1), мастни клетки, базофили, <strong>еозинофили</strong>, неутрофили.</li><ul><li>Възпалението при астма се дължи на дисбаланс между Th1 и Th2 лимфоцити.</li><li>Th-1 клетките продуцират IL-2 и IFN-a, важни за клетъчните защитни механизми.</li><li>Th-2 клетките генерират цитокини (IL-4, IL-5, IL-6, IL-9, IL-13), които медиират алергичното възпаление.</li><li>Според „хигиенната хипотеза“, прекарани инфекции в детството, по-рядка употреба на антибиотици и живот в провинцията стимулират Th1 отговор и намаляват честотата на астма.Липсата на тези фактори води до персистиращ Th2 отговор и по-висока заболеваемост.</li><li>Новите данни за не-Th2 фенотипове на астма показват, че хигиенната хипотеза обяснява само част от случаите.</li></ul><li><strong>Възпалителни медиатори</strong> (над 100): Хистамин, простагландини, левкотриени, ензими, хемокини, NO.</li><li>Отокът на дихателните пътища и мукусната хиперсекреция допринасят за бронхиалната хиперреактивност и ограничението на въздушния поток.</li></ul><h4>2. Ремоделиране</h4><p>Хроничното възпаление води до структурни промени:</p><ul><li><strong>Хипертрофия и хиперплазия</strong> на гладките мускули.</li><li><strong>Увеличаване</strong> на мукозните жлези.</li><li><strong>Задебеляване</strong> на базалната мембрана.</li><li>Количествени и качествени промени на съдовете на дихателните пътища.</li></ul><p>Ремоделирането може да доведе до <strong>необратимо ограничение на въздушния поток</strong>. </p><p>Астмата е заболяване на големите дихателни пътища, но могат да бъдат ангажирани и малките дихателни пътища.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h3>Патофизиология</h3><h4>1. Ограничение на Въздушния Поток</h4><p>Води до развитие на симптомите и е свързано с възпалението и ремоделирането. Причинява се от:</p><ul><li><strong>Контракция на гладката мускулатура</strong> в отговор на многобройни бронхоконстрикторни медиатори и невротрансмигери.</li><li><strong>Оток на стената</strong> на дихателните пътища, предизвикано от възпалителни медиатори.</li><li><strong>Задебеляване на стената</strong> вследствие на ремоделирането.</li><li><strong>Мукусна хиперсекреция</strong>.</li></ul><p>Бронхиалната обструкция увеличава резистанса към потока, намалява експираторния поток и може да предизвика <strong>хиперинфлация</strong>, поради намалена способност за \"изгонване\" на въздуха.</p><h4>2. Бронхиална Хиперреактивност (БХР)</h4><p>Води до стеснение на дихателните пътища в отговор на стимули, които са безвредни за здравия човек (напр. студен въздух).</p><p><strong>Степента на БХР корелира с клиничната тежест на астмата</strong>. </p><p>БХР е свързана както с възпалението, така и с ремоделирането.</p><p><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-11/text-editor-images/2026/03/1773250413292-image.png\" alt=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-11/text-editor-images/2026/03/1773250413292-image.png\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-11/text-editor-images/2026/03/1773250413292-image.png\" data-width=\"40\" style=\"width: 259.6px; max-width: 100%; height: auto; display: block\" data-broken-cleanup-bound=\"1\"></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h3>Клинична Картина</h3><ul><li>Анамнеза за някое от следващите:</li><ul><li><strong>Кашлица</strong>, влошаваща се най-вече през <strong>нощта</strong>.</li><li>Повтарящо се <strong>хриптене</strong>, <strong>затруднено дишане</strong>, <strong>стягане в гърдите</strong>.</li></ul><li>Симптомите <strong>варират по време и интензивност</strong> и се проявяват/влошават със <strong>сезонен характер</strong>.</li><li><strong>Тригери</strong>:</li><ul><li>Физическо натоварване</li><li>Вирусни инфекции</li><li>Инхалаторни алергени (в т.ч. животински, от акари в домашен прах, плесени, по лени и др.)</li><li>Дразнители (тютюнев дим)</li><li>Лекарства (аспирин, бета блокери)</li><li>Промени във времето (студен въздух)</li><li>Силни емоции/стрес</li><li>Ендокринни фактори</li></ul><li>Симптомите се появяват/влошават <strong>през нощта</strong> и събуждат пациента.</li><li>Симптомите се повлияват при лечение на астмата.</li><li>Пациентите имат анамнеза за <strong>алергичен ринит, алергичен конюктивит, екзема, уртикария</strong> или <strong>фамилна анамнеза</strong> за астма или друго атопично заболяваня.</li><li>Симптоми, които по-вероятно не са свързани с астма:</li><ul><li>Изолирана кашлица без други респираторни симптоми.</li><li>Хронична продукция на спутум.</li><li>Диспнея, индуцирана от физическо натоварване с шумна инспирация (стридор).</li><li>Гръдна болка.</li></ul></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p>Физикално Изследване</p><ul><li><strong>Горен респираторен тракт</strong>: Увеличена назална секреция, оток на мукозата, назален полип.</li><li><strong>Гръден кош</strong>:</li><ul><li>Може да бъде <strong>съвсем нормален </strong>(не изключва астма).</li><li><strong>Хриптене </strong>или <strong>удължено издишване</strong> при форсирано издишване.</li><li>При тежък живото-застрашаващ  пристъп може да няма хриптене - <strong>„тих\" бял дроб</strong>.</li><li>Свръхраздуване на гръдния кош, използване на допълнителните мускули, деформация на гръдния кош (при хронична астма).</li></ul><li><strong>Кожа</strong>: Атопични дерматити, екземи.</li><li><strong>Очи</strong>: Конюктивити.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h3>Екзацербация на Астмата</h3><ul><li><strong>Продроми (Предвестници)</strong></li><ul><li>Сърбеж в носа и носоглътката</li><li>Чувство на вътрешно напрежение</li><li>Сърбеж</li><li>Вегетативни промени (потене, често уриниране)</li><li>Суха дразнеща кашлица</li><li>Пристъпно кихане</li><li>Запушване на носа, Ринорея</li></ul><li><strong>Симптоми</strong></li><ul><li><strong>Кашлица</strong></li><li><strong>Задух</strong></li><li><strong>Хриптене</strong></li><li><strong>Стягане в гърдите</strong></li><li>Оскъдна експекторация</li></ul></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h3>Изследвания за астма</h3><p> <strong>1. Изследвания, необходими за поставяне на диагнозата астма и преценка на контрола на заболяването</strong></p><ul><li><strong>Спирометрия</strong>: Предпочитан метод за измерване на ограничението на въздушния поток и неговата обратимост.</li><ul><li><em></em>Диагностични критерии (Вариации):</li></ul></ul><ul><li>Ниска стойност на ФЕО₁/ФВК (нормално &gt;0.75-0.80 при възрастни).</li><li>Вариации на ФЕО₁ с &gt; <strong>12%</strong> и <strong>&gt; 200 mL</strong> между визитите (при липса на респираторни инфекции).</li></ul><ul><li><strong>Обратимост (Бронходилататорен тест)</strong>: Нарастване на ФЕО₁ с <strong>&gt; 12% и &gt; 200 mL</strong> 10-15 min след прием на 200 - 400 mcg Salbutamol. Увеличение &gt; 15% и &gt; 400 mL в по-голяма степен подкрепя диагнозата.</li></ul><ul><li><strong>Измерване на Върховия Експираторен Дебит (ВЕД)</strong>: Подпомага диагностицирането и проследяването.</li><ul><li><strong>Вариабилност</strong>: Вариабилност на ВЕД <strong>&gt; 10%</strong> между сутрешните и вечерните стойности (при серийни измервания в продължение на 15 дни) предполага диагноза астма.</li></ul><li><strong>Подобрение след Противовъзпалително лечение</strong>: Нарастване на ФЕО₁ с &gt; 12% и &gt; 200 mL (или на ВЕД е &gt;20%) след 4-седмично лечение подкрепя диагнозата.</li><li><strong>Бронхиална реактивност (Бронхопровокационен тест)</strong>: Измерва се при пациенти с нормална белодробна функция, но с характерни симптоми.</li><ul><li><strong>Положителен тест: </strong>Спад на ФЕО₁ с <strong>&gt; 20%</strong> със стандартизирани дози метахолин/хистамин, или <strong>&gt; 15%</strong> със стандартизирана хипервентилация/манитол.</li><li><strong>Значение</strong>: Негативният тест (при пациенти без инхалаторни стероиди) обикновено изключва диагнозата астма. Положителният тест може да се наблюдава и при други заболявания (алергични ринити, ХОББ).</li></ul><li><strong>Кожни тестове с алергени или специфични IgE в серума</strong>: Наличието на атопия увеличава вероятността за алергична астма, но не е задължително.</li><ul><li><strong>Общ серумен IgE</strong>: Нива над 100 IU често се наблюдават при алергични реакции, но не са специфични само за астма. Повишени нива се изискват при тежка астма за лечение с omalizumab.</li><li>Връзката между експозицията на алергена и симптомите трябва да бъде потвърдена чрез анамнезата на пациента.</li></ul><li><strong>Определяне на Еозинофилия в периферна кръв и спутум</strong>:</li><ul><li><strong>Кръв: </strong>Еозинофили над <strong>4% </strong>или <strong>300-400/μL</strong> поддържат диагнозата, но липсата не я отхвърля.</li><ul><li>Може да се наблюдава и при алергична бронхопулмонална аспергилоза, Churg-Strauss синдром и еозинофилна пневмония.</li></ul><li><strong>Спутум</strong>: Процентът на еозинофилите може да се използва за определяне и контролиране на терапията. Повишени стойности се изискват при тежка астма за лечение с моноклонални антитела.</li></ul><li><strong>Ниво на Издишания Азотен Окис (FeNO)</strong>: Увеличено при пациенти с еозинофилна астма, които не са получавали инхалаторни кортикостероиди.</li><ul><li>Стойностите на FeNO са увеличени и при атопия, еозинофилните бронхити и алергични ринити</li><li><strong>Значение</strong>: Не е утвърден за диагноза, но стойности <strong>&gt; 50 ppb</strong> при непушачи с неспецифични симптоми се асоциират с добър краткосрочен отговор към инхалаторни кортикостероиди.</li></ul><li><strong>Артериални кръвни газове (АКГ)</strong>: Осигуряват информация по време на пристъп.</li><ul><li><strong>Ранни стадии</strong>: Хипоксия, но не и хиперкапния (поради хипервентилация - респираторна алкалоза).</li><li><strong>Влошаване</strong>: По-късно, поради увеличе ната работа на дишането, увеличената кислородна консумация и увеличения сърдечен дебит настъпва метаболитна ацидоза. Респираторната недостатъчност води до развитие на респираторна ацидоза.</li><li>Кръвно-газовият анализ може да подпомогне решението за включване на пациента на механична вентилация</li><li>Препоръчва се да се изследва АКГ при пациенти, при които SaO₂ не се е възстановила до над 90% след кислородотерапия.</li></ul></ul><p><strong>2. Изследвания, необходими за диференциална диагноза</strong></p><ul><li><strong>Дифузионен капацитет (DLCO)</strong>: Нормален при астма, може да е намален при ХОББ\\text{ХОББ}ХОББ.</li><li><strong>Пулмография и други образни изследвания</strong>: За изключване на пневмоторакс, чуждо тяло, белодробен рак и др.</li><li><strong>Електрокардиограма (ЕКГ)</strong>: За изключване на сърдечно-съдови заболявания.</li><li><strong>Ларингоскопия</strong>: За изключване на обструкция на горни дихателни пътища и патология на гласните връзки.</li><li><strong>Фибробронхоскопия</strong>: Рядко е необходима (за изключване на ендобронхиален тумор).</li><li><strong>Белодробна биопсия</strong>: Много рядко е необходима за изключване на други причини (напр. бронхиолит).</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Диагноза</h2><p>Астмата често се диагностицира въз основа на <strong>анамнезата и симптомите</strong>. <strong>Измерването на белодробната функция</strong> (вариабилност и обратимост) потвърждава диагнозата. При нормална белодробна функция и симптоми се използва <strong>бронхопровокационният тест</strong>.</p><p>Кожните тестове с алергени допринасят за определяне на рисковите фактори, предизвикващи симптомите на астма при отделни пациенти.</p><p><strong>Оценка на ефекта от лечението</strong> се извършва чрез измерване на белодробната функция, бронхиалната хиперреактивност, еозинофилите в спутум и FeNO.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Диференциална Диагноза на Бронхиална Астма</h2><p>Диференциалната диагноза на астмата включва следните състояния:</p><ul><li><strong>Хронична обструктивна белодробна болест (ХОББ)</strong>:</li><ul><li><strong>Характеристики: </strong>Настъпва в средна възраст, симптоматиката бавно прогресира, анамнеза за продължително тютюнопушене, задух при физическо усилие.</li><li><strong>Функционално</strong>: В голяма степен <strong>необратимо ограничение</strong> на въздушния поток.</li></ul><li><strong>Сърдечна недостатъчност (СН)</strong>: Може да причини нощна кашлица и т.нар. <strong>кардиална астма</strong>.</li><ul><li><strong>Физикално: </strong>Дребни влажни хрипове при аускултация базално.</li><li><strong>Образно</strong>: Рентгенографията показва <strong>увеличено сърце</strong> и <strong>белодробен застой/едем</strong>.</li><li><strong>Функционално</strong>: Намаление на белодробния обем, а не ограничение на въздушния поток.</li></ul><li><strong>Исхемично сърдечно заболяване</strong>: Стягане в гърдите, особено при излагане на студен вятър, което може да се дължи както на астма, така и на стенокардия.</li><li><strong>Гастро-езофагеална рефлуксна болест (ГЕРБ)</strong>: Възможно е да причини нощна кашлица.</li><li><strong>Постназален дрип</strong>: Може да доведе до закашляне в лежащо положение.</li><li><strong>Лечение с АСЕ инхибитори</strong>: Може да предизвика кашлица.</li><li><strong>Други заболявания, които трябва да се имат предвид</strong>:</li><ul><li>Обструкция на горни дихателни пътища (чуждо тяло или рак)</li><li>Дисфункция на гласните връзки, трахеомалация</li><li><em></em>Бронхиектазии, Бронхиолити</li></ul></ul><ul><li>Белодробна фиброза, Саркоидоза, Кистична фиброза</li><li>Психогенна диспнея</li><li>Синдром на Churg-Strauss</li><li>Алергична бронхопулмонална аспергилоза (АБПА)</li><li>Спонтанeн пневмоторакс</li><li>Рецидивиращ белодробен тромбемболизъм</li></ul><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">15. Бронхиална астма – поддържаща терапия</h1><h2>Контрол на астмата</h2><p>Оценката на контрола е <strong>динамична</strong> и определя терапевтичния подход. Тя се базира на изразеността на симптомите, риска от бъдещи събития (екзацербации и белодробна функция), провежданото лечение и наличието на коморбидности (<strong>ринити</strong>, <strong>ГЕРБ</strong>, <strong>затлъстяване</strong>, <strong>депресия</strong>).</p><h3>Определяне на нива на астма контрол на симптомите.</h3><p>В последните 4 седмици пациентът имал ли е:</p><ul><li>Дневни симптоми &gt; 2 пъти седмично?</li><li>Събуждане през нощта поради астма?</li><li>Нужда от облекчаващ медикамент &gt; 2 пъти седмично?</li><li>Ограничена физическа активност поради астма?</li></ul><table><tbody><tr><td><strong><span style=\"color: rgb(88, 129, 87)\">Ниво на контрол</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Характеристика</span></strong></td></tr><tr><td><strong>Добре контролирана</strong></td><td>Липсват всички посочени характеристики (0 отговора „Да“)</td></tr><tr><td><strong>Частично контролирана</strong></td><td>Налице са 1–2 от посочените характеристики</td></tr><tr><td><strong>Неконтролирана</strong></td><td>Налице са 3–4 от посочените характеристики</td></tr></tbody></table><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Лечение на астмата</h2><h3>Дългосрочни терапевтични цели</h3><ul><li><strong>Контрол на симптомите:</strong> Поддържане на нормални нива на физическа активност.</li><li><strong>Редукция на риска:</strong> Намаляване на риска от екзацербации, фиксирана обструкция и странични ефекти.</li></ul><h3>Нефармакологично лечение</h3><ul><li>Избягване на експозиция на <strong>тютюнев дим</strong> и алергени (прах, полени, животни).</li><li>При професионална астма премахване на професионалните агенти.</li><li>Избягване на медикаменти, които влошават астмата: <strong>аспирин</strong>, <strong>НПВС</strong>, <strong>бета-блокери</strong>.</li><li>Окуражаване на пациента да бъде физически активен. Същевременно осигуряване на съвети относно бронхоконстрикцията, причинена от физическо натоварване.</li><li><strong>Имунотерапия:</strong> При ясна връзка между симптоми и специфичен алерген (субкутанна или сублингвална).</li><li><strong>Бронхиална термопластика:</strong> нова методика за лечение на астма, при която контролирана топлинна енергия се доставя до дихателните пътища чрез серия от бронхоскопски процедури.</li></ul><h3>Фармакологично лечение</h3><p>Инхалаторните медикаменти се предпочитат поради директна доставка и по-малко системни ефекти. Използват се <strong>pMDIs</strong>, <strong>DPIs</strong>, <strong>спейсъри</strong> и <strong>небулизатори</strong>.</p><h4>А. Медикаменти - Контролери (Поддържащо лечение)</h4><ol><li><strong>Глюкокортикостероиди:</strong></li><ul><li><strong>Инхалаторни (ИКС):</strong> Beclometasone, Budesonide, Fluticasone, Mometasone.</li><li><strong>Системни:</strong> Prednisone, Methylprednisolone.</li></ul><li><strong>Комбинация ИКС/ДДБА:</strong> Fluticasone/salmeterol, Budesonide/formoterol и др.</li><li><strong>Левкотриенови антагонисти:</strong> Montelucast, Zafirlucast.</li><li><strong>Теофилин</strong> с удължено действие.</li><li><strong>Антихолинергици:</strong> Ipratropium bromide, Tiotropium bromide (тип фина мъгла).</li><li><strong>Моноклонални антитела:</strong> <strong>Оmalizumab</strong> (анти-IgE), <strong>Mepolizumab</strong> (анти-IL-5).</li></ol><h4>Б. Медикаменти - Облекчаващи (При нужда)</h4><ol><li><strong>Краткодействащи бета2-агонисти (КДБА):</strong> Salbutamol, Fenoterol.</li><li><strong>Краткодействащи антихолинергици (КДАХ):</strong> Ipratropium bromide.</li><li><strong>Краткодействащ теофилин:</strong> Aminophylline.</li></ol><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Терапевтичен алгоритъм (Стъпки 1-5)</h2><ul><li><strong>Стъпка 1:</strong> Ниска доза <strong>ИКС/formoterol</strong> при нужда (предпочитана опция).</li><li><strong>Стъпка 2:</strong> Редовен прием на ниска доза <strong>ИКС</strong> или <strong>ИКС/formoterol</strong> при нужда.</li><li><strong>Стъпка 3:</strong> Ниска доза <strong>ИКС/ДДБА</strong>.</li><li><strong>Стъпка 4:</strong> Средна доза <strong>ИКС/ДДБА</strong>; добавяне на <strong>Tiotropium</strong> или <strong>ЛТРА</strong>.</li><li><strong>Стъпка 5:</strong> Насочване към специалист, биологична терапия или ниски дози перорални КС.</li></ul><h3>Динамика на лечението</h3><ul><li><strong>Стъпка нагоре:</strong> При неадекватен отговор (след проверка на техниката и придържането).</li><li><strong>Стъпка надолу:</strong> Когато симптомите са контролирани за <strong>&gt; 3 месеца</strong> (цел: най-ниска ефективна доза).</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Поведение при специални популации</h2><ul><li><strong>Бременни:</strong> По-безопасно е лечението, отколкото екзацербациите. <strong>Budesonide</strong> и <strong>Salbutamol</strong> са предпочитани.</li><li><strong>Професионална астма:</strong> Изисква бързо елиминиране на професионалните агенти.</li><li><strong>Aspirin-екзацербирано заболяване:</strong> Астма, назални полипи и свръхчувствителност към НПВС. Избягват се аспирин и НПВС (ползва се paracetamol).</li><li><strong>Хирургия:</strong> При прием на системни КС или високи дози ИКС се препоръчва <strong>100 mg hydrocortisone i.v.</strong> на всеки 8 часа периоперативно.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Усложнения и Прогноза</h2><h3>Усложнения</h3><ul><li><strong>От болестта:</strong> Пневмоторакс, дихателна недостатъчност, смърт.</li><li><strong>От лечението:</strong> Остеопороза, катаракта (при системни КС), аритмии (при свръхупотреба на КДБА).</li></ul><h3>Рискови фактори за смърт</h3><ul><li>Анамнеза за интубация/вентилация.</li><li>Хоспитализация в последните 12 месеца.</li><li>Свръхупотреба на <strong>КДБА</strong> (&gt; 1 опаковка/месец).</li><li>Психиатрични или психосоциални проблеми.</li></ul><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\">16. Бронхиална астма – лечение на пристъп<h2>Екзацербация на Астмата</h2><ul><li><strong>Продроми (Предвестници)</strong></li><ul><li>Сърбеж в носа и носоглътката</li><li>Чувство на вътрешно напрежение</li><li>Сърбеж</li><li>Вегетативни промени (потене, често уриниране)</li><li>Суха дразнеща кашлица</li><li>Пристъпно кихане</li><li>Запушване на носа, Ринорея</li></ul><li><strong>Симптоми</strong></li><ul><li><strong>Кашлица</strong></li><li><strong>Задух</strong></li><li><strong>Хриптене</strong></li><li><strong>Стягане в гърдите</strong></li><li>Оскъдна експекторация</li></ul></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Класификация на езецербацията на астмата по тежест:</h2><table><thead><tr><th><span style=\"color: rgb(88, 129, 87)\">Показател</span></th><th><span style=\"color: rgb(88, 129, 87)\">Лека</span></th><th><span style=\"color: rgb(88, 129, 87)\">Умерено-тежка</span></th><th><span style=\"color: rgb(88, 129, 87)\">Тежка</span></th><th><span style=\"color: rgb(88, 129, 87)\">Застрашаващ респираторен арест</span></th></tr></thead><tbody><tr><td><strong>Задух</strong></td><td>При ходене</td><td>При говорене</td><td>В покой</td><td></td></tr><tr><td><strong>Позиция</strong></td><td>Може да легне</td><td>Предпочита да седи</td><td>Седнал, приведен напред</td><td></td></tr><tr><td><strong>Разговор</strong></td><td>Изречения</td><td>Фрази</td><td>Думи</td><td></td></tr><tr><td><strong>Съзнание</strong></td><td>Може да е възбуден</td><td>Обикновено е възбуден</td><td>Обикновено е възбуден</td><td>Сънлив или объркан</td></tr><tr><td><strong>Дихателна честота</strong></td><td>Увеличена</td><td>Увеличена</td><td>Често &gt;30/min</td><td></td></tr><tr><td><strong>Допълнителни мускули и тираж</strong></td><td>Липсва обичайно</td><td>Обичайно</td><td>Обичайно</td><td>Парадоксално движение на гърдите и корема</td></tr><tr><td><strong>Хриптене</strong></td><td>Умерено, често само в експириум</td><td>Силно</td><td>Обикновено силно</td><td>Липса на хриптене</td></tr><tr><td><strong>Пулс</strong></td><td>&lt; 100</td><td>100 - 120</td><td>&gt; 120</td><td>Брадикардия</td></tr><tr><td><strong>Парадоксален пулс</strong> (Спадане на систолното кръвно налягане по време на инспирация)</td><td>Липсва (&lt; 10 mm Hg)</td><td>Може да се наблюдава (10 - 25 mm Hg)</td><td>Често се наблюдава (&gt; 25 mm Hg)</td><td>Липсата предполага умора на дихателните мускули</td></tr><tr><td><strong>ВЕД след прилагане на бронходилататор</strong>* (% от предвиденото или най-доброто лично постижение)</td><td>&gt; 80%</td><td>60 - 80%</td><td>&lt; 60% (&lt; 100 l/min) или отговорът трае &lt; 2 часа</td><td></td></tr><tr><td><strong>PaO₂ (атм. въздух)</strong></td><td>Нормално (&gt; 60 mm Hg)</td><td>&gt; 60 mm Hg</td><td>&lt; 60 mm Hg</td><td></td></tr><tr><td><strong>PaCO₂</strong></td><td>&lt; 45 mm Hg</td><td>&lt; 45 mm Hg</td><td>&gt; 45 mm Hg</td><td></td></tr><tr><td><strong>SaO₂%</strong></td><td>&gt; 95%</td><td>91 - 95%</td><td>&lt; 90%</td><td>Възможна е цианоза</td></tr></tbody></table><ul><li><strong>Парадоксален пулс</strong> - При тежък астматичен пристъп по време на вдишване въздухът трудно излиза от белите дробове и налягането в гръдния кош става силно отрицателно. Това „всмуква“ повече кръв към дясното сърце, което се разширява и притиска лявата камера. Така лявата камера се пълни по-малко и изтласква по-малък обем кръв – в резултат кръвното налягане рязко спада при вдъхновение.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Лечение на екзацербации</h2><ol><li><strong>КДБА (Salbutamol):</strong> 4-10 впръсквания на всеки 20 мин през първия час.</li><li><strong>Ipratropium bromide:</strong> Добавя се при тежки екзацербации.</li><li><strong>Перорални кортикостероиди:</strong> 1 mg/kg <strong>prednisolone</strong> (макс. 50 mg) за 5–7 дни.</li><li><strong>Кислород:</strong> За поддържане на сатурация <strong>93–95%</strong>.</li></ol><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><br><br><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">17. Пневмонии придобити в обществото</h1><h2>Дефиниция</h2><p>Остра инфекция на белодробния паренхим с:</p><ul><li>поне 2 от следните симптоми: температура, втрисане, остра кашлица (със или без експекторация) или хронична кашлица с промяна в цвета на храчките, плеврална болка, задух;</li><li>Аускултаторни данни за ппневмония (крепитации или късни инспираторни пукания на ограничен участък, бронхиално дишане);</li><li>Нови инфилтративни промени в рентгенограмата на гръдния кош, за които няма друго обяснение (белодробен оток или инфаркт).</li></ul><h3>Епидемиология</h3><ul><li>Най-честа инфекциозна причина за смърт.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Етиология</h2><ul><li><strong>Типични бактери - </strong>причинени от микроби, които се размножават <strong>извънклетъчно</strong>:</li><ul><li>Streptococcus pneumonia (най-чест),&nbsp;Haemophilus influenzae, Moraxella catarrhalis, Staphylococcus aureus, Klebsiella pneumoniae</li></ul><li><strong>Атипични бактерии</strong>- причинителите се размножават <strong>вътреклетъчно</strong>:</li><ul><li>Mycoplasma pneumoniae, Chlamydophila pneumoniae, Legionella spp.</li><li>Зоонозни атипични пневмонии - Coxiella burnetii (домашни животни), Chlamydophila psittaci (птици).</li><li>Атипичните причинители са резистентни на β-лактами.</li></ul><li><strong>Бактериални анаеробни пневмонии:</strong></li><ul><li>Обичайно след аспирация на орофарингеално съдържимо – алкохолици, ИМИ, епилепсия, лоша зъбна хигиена и др.</li><li>Често-смесена флора-анаероби, S.aureus, Грам (-) бактерии</li></ul><li><strong>Вируси:</strong> Influenza virus (грипен вирус), RSV (респираторен синцитиален вирус), Adenovirus, Parainfluenza virus, други вирусни патогени</li><li><strong>Особености и съвременни тенденции - нарастване на ролята на:</strong></li><ul><li><strong>Drug-resistant Streptococcus pneumoniae (DRSP)</strong></li><li><strong>Methicillin-resistant Staphylococcus aureus (MRSA)</strong></li><li>Вирусни патогени (H5N1, H2N1), които могат да предизвикат <strong>остър респираторен дистрес синдром при възрастни (ARDS)</strong></li></ul></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Рискови фактори</h2><p>Алкохолизъм, тютюнопушене, наркомани, сърдечно-съдови заболявания, ХОББ, диабет, хронични бъбречни заболявания, грипна епидемия, употреба на орални стероиди/имуносупресия, климатични системи (Legionella), контакт с птици (Chlamydophila psittaci) и животни (Coxiella burnetti).</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Патогенеза</h2><p><strong>Защитата на белия дроб при инфекциите се осъществява на няколко нива:</strong></p><p><strong>1. Механична защита</strong> </p><ul><li>Мукусна секреция с подходящи реологични свойства</li><li>Ефективно действие на цилиарния епител (мукоцилиарен клирънс)</li><li>Нормален пермеабилитет на бронхиалната лигавица</li><li>Кашличен рефлекс, подпомагащ изчистването на дихателните пътища</li></ul><p><strong>2. Клетъчни защитни механизми</strong></p><ul><li><strong>Алвеоларни макрофаги</strong> и <strong>неутрофили</strong> имат ключова роля</li><li>Основни функции:</li><ul><li>Хемотаксис</li><li>Фагоцитоза</li><li>Регулация на адхезионните молекули</li><li>Унищожаване на бактерии и гъби</li><li>Навлизане на антибиотици в неутрофилите</li><li>Приток на неутрофили към мястото на възпалението</li></ul></ul><p><strong>3. Хуморални защитни механизми</strong></p><ul><li><strong>IgA</strong> – основен в горните дихателни пътища (мукозен имунитет)</li><li><strong>IgG</strong> – доминира в долните дихателни пътища и осигурява опсонизация и неутрализация на патогени</li></ul><p><strong>Развитие на пневмонията</strong>  </p><p>За да се развие пневмония, инфекциозният агент трябва да <strong>преодолее защитните механизми</strong> на дихателните пътища.  </p><p>Патогенът достига до белия дроб по един от следните пътища:  </p><ul><li><strong>Микроаспирация</strong> на секрети от назофаринкса <em>(най-честият механизъм)</em></li><li><strong>Инхалация</strong> на инфекциозни аерозоли от външната среда</li><li><strong>Хематогенна дисеминация</strong> от извънбелодробни огнища</li><li><strong>Директно разпространение</strong> от съседни структури (напр. абсцес, емпием, хирургична рана)</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Патоанатомия</h2><ul><li><strong>Лобарна:</strong> Остър възпалителен процес, обхващащ цял белодробен лоб.&nbsp;Характеризира се с левкоцитна инфилтрация на алвеолите. Лобарната консолидация е резултат на бърза продукция на оточна течност (интраалвеоларно) с минимално клетъчно съдържимо. В началото се засяга периферията на белитедробове и след това се разпространява между ацините чрез порите на Kohn и каналите на Lambert.</li><li><strong>Бронхопневмония (мултиогнищна, лобуларна) - субсегментно и сегментно засягане:</strong> Характеризира се с гноен, богат на левкоцити ексудат в терминалните бронхиоли и прилежащите алвеоли.</li><li><strong>Интерстициална:</strong>&nbsp;Алвеоларната септа е задебелена и едематозна и обикновено е инфилтрирана от лимфоцити, хистиоцити и плазматични клетки.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Клинична картина</h2><ul><li><strong>Белодробни:</strong> кашлица с или без експекторация, диспнея, плеврална болка, хемоптиза.</li><li><strong>Извънбелодробни:</strong> фебрилитет, втрисане, лесна умора, ставни болки, главоболие, загуба на апетит, промяна в настроението, тахикардия, хипотония, гадене, повръщане.</li><li>При възрастни – може да е налице обърканост и липса на повишена температура.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Физикални находки</h2><p>Тахипнея, тахикардия, намалена респираторна подвижност на засегната страна, притъпен перкуторен тон, отслабено или липсващо дишане, бронхиално дишане, крепитации или късни инспираторни пукания, плеврално триене.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Типична vs Атипична пневмония</h2><table><tbody><tr><td><strong><span style=\"color: rgb(88, 129, 87)\">Типична (бактериална)</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Атипична (небактериална)</span></strong></td></tr><tr><td>Остро начало</td><td>По-плавно начало</td></tr><tr><td>По-изразена физикална находка</td><td>По-оскъдна физикална находка</td></tr><tr><td>Пропорционалност на рентгенологичната и физикалната находка</td><td>Непропорционалност на рентгенологичната и физикалната находка<br></td></tr><tr><td>По-изразени лабораторни промени</td><td>По-слабо изразени параклинични промени</td></tr><tr><td>По-тежко протичане и по-лоша прогноза</td><td>По-леко протичане и по-добра прогноза</td></tr></tbody></table><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Особености по причинител</h2><ul><li><strong>S. pneumoniae:</strong></li><ul><li>Патоанатомично 4 стадия:</li><ul><li>Фаза на конгестия – интраалвеоларен ексудат с малко неутрофили и много бактерии</li><li>Фаза на червена хепатизация – интраалвеоларен ексудат с много еритроцити, бактерии, фибрин, неутрофили</li><li>Фаза на сива хепатизация – алвеолите са безвъздушни, изпълнени с фибрин и неутрофили</li><li>Фаза на всмукване – нахлуване на макрофаги, активна фагоцитоза иразграждане на ексудата</li></ul><li>При благоприято развитие – restitution ad integrum</li><li>При непълно всмукване – оформяне на фиброза</li><li>Клинична картина: остро начало, кашлица с гнойни или ръждиви храчки, висока Т°, плеврални изливи, напреднала възраст, коморбидитет, лабиален Herpes simplex.</li><li>Физикална находка:</li><ul><li>Притъпен перкуторен тон</li><li>В началото - везикуларно дишане с <strong>crepitatio indux</strong>, впоследствие – бронхиално дишане, усилен гласовфремитус, бронхофония.</li><li>При всмукване- изчезване на бронхиалното дишане, наличие на <strong>crepitatio redux</strong>.</li></ul><li><span class=\"editor-note\" data-note=\"![Пневмонична рентген](/Стрепто.png)\" id=\"note-1773248844973-0\">Рентгенова находка</span>: лобарно ангажиране с характерни симптоми на въздушна бронхограма</li></ul></ul><p><img src=\"https://files.coursebook.lol/Coursebook%20Assets/2026-05-05/coursebook-assets/assets/%D0%A1%D1%82%D1%80%D0%B5%D0%BF%D1%82%D0%BE.png\" alt=\"Стрепто.png\" data-original-src=\"https://files.coursebook.lol/Coursebook%20Assets/2026-05-05/coursebook-assets/assets/%D0%A1%D1%82%D1%80%D0%B5%D0%BF%D1%82%D0%BE.png\" data-width=\"100\" style=\"width: 762px; max-width: 100%; height: auto; display: block\" data-broken-cleanup-bound=\"1\"></p><ul><li><strong>S. aureus:</strong></li><ul><li>След вирусна инфекция, най-често грип или вследствие сепсис от другогнойно огнище – кожа и др.</li><li>Често деца, често ВБП</li><li>Склонност към абсцедиране –често множествени абсцеси, пневматоцеле (наличие на тънкостенни кухини, изпълнени с въздух в белодробната тъкан)</li><li>Усложнения – пневмоторакс, емпием, пиопневмоторакс, метастатични абсцеси – мозък, бъбреци</li><li>MRSA - тежък терапевтичен проблем</li><li>При наркомани.</li><li>Рентгенова находка: двустранни инфилтрати с множество микроабсцеси, пневматоцеле</li></ul></ul><p><img src=\"https://files.coursebook.lol/Coursebook%20Assets/2026-05-05/coursebook-assets/assets/%D0%A1%D1%82%D0%B0%D1%84%D0%B8%D0%BB%D0%B8%D0%BA%D0%BE%D0%BA%D0%BE%D0%B2%D0%B0.png\" alt=\"Стафиликокова.png\" data-original-src=\"https://files.coursebook.lol/Coursebook%20Assets/2026-05-05/coursebook-assets/assets/%D0%A1%D1%82%D0%B0%D1%84%D0%B8%D0%BB%D0%B8%D0%BA%D0%BE%D0%BA%D0%BE%D0%B2%D0%B0.png\" data-width=\"100\" style=\"width: 1010px; max-width: 100%; height: auto; display: block\" data-broken-cleanup-bound=\"1\"></p><ul><li><strong>H. influenzae:</strong></li><ul><li>Остро начало, както пневмококовата пневмония - при алкохолици и имуносупресирани</li><li>Подостро начало - при придружаващи белодробни болести</li></ul><li><strong>Klebsiella - грам (-):</strong></li><ul><li>Често при алкохолици</li><li>Два типа на протичане</li><ul><li>Остро протичане – бурно начало,фебрилитет, гнойно-кървава експекторация</li><li>Подостро или хронично протичане - склонност към абсцедиране и оформяне на фиброза</li></ul></ul><li><strong>Pseudomodnas aeruginosa - грам (-)</strong>:</li><ul><li>Необичайна при здрави индивиди</li><li>По-често при структурни аномалии с колонизация – КФ, бронхиектазии, ХОББ</li><li>По-често – ВБП, особено в интензивни отделения</li></ul><li><strong>M. catarrhalis:</strong> ХОББ, захарен диабет, неопластични заболявания, продължително кортикостероидно лечение, обикновено протича по-леко.</li><li><strong>Legionella:</strong></li><ul><li>Широко разпространена във водни инсталации, климатици, застояли водоеми</li><li>Две форми на протичане:</li><ul><li><strong>Понтиак треска </strong>– неусложно грипоподобно заболяване</li><li><strong>Легионерска болест</strong> -тежка пневмония – нарушено съзнание, диария, бъбречно и чернодробно засягане, склонност към брадикардия, хипонатриемия</li></ul><li>Рентгенов образ:</li></ul></ul><p><img src=\"https://files.coursebook.lol/Coursebook%20Assets/2026-05-05/coursebook-assets/assets/%D0%9B%D0%B5%D0%B3%D0%B8%D0%BE%D0%BD%D0%B5%D0%BB%D0%BA%D0%B0.png\" alt=\"Легионелка.png\" data-original-src=\"https://files.coursebook.lol/Coursebook%20Assets/2026-05-05/coursebook-assets/assets/%D0%9B%D0%B5%D0%B3%D0%B8%D0%BE%D0%BD%D0%B5%D0%BB%D0%BA%D0%B0.png\" data-width=\"100\" style=\"width: 777px; max-width: 100%; height: auto; display: block\" data-broken-cleanup-bound=\"1\"></p><ul><li><strong>Mycoplasma pneumoniae:</strong></li><ul><li>Малка бактерия, без клетъчнастена-причина за резистентност към β-лактами</li><li>Чест причинител на инфекции при деца и млади хора, затворени колективи</li><li>Често самоограничаваща се инфекция, рядко –тежка инфекция</li><li>Чести извънбелодробни прояви</li><li>Бавен клирънс на очистване от бронхиалното дърво – честа причина за подостра (постинфекциозна кашлица)</li><li>Прояви от ЦНС – енцефалити, асептични менингити, полирадикулити, церебрална атаксия,миелит</li><li>Кардиоваскуларни прояви – перикардит, ендокардит, миокардит</li><li>Кожни прояви – Синдром на Steveans-Johnson, еритема мултиформе, еритема нодозум, анафилактоидна пурпура, активна уртикария</li><li>Хематологични прояви - автоимунна хемолитична анемия-(+) студови антитела, ДИК синдром, тромбоцитопенична пурпура</li><li>Очни прояви – конюнктивит, ирит, увеит</li><li>Ставни прояви- артрит</li><li>Рентгенов образ: двустранно предимнопериферно интерстициално ангажиране</li></ul></ul><p><img src=\"https://files.coursebook.lol/Coursebook%20Assets/2026-05-05/coursebook-assets/assets/%D0%9C%D0%B8%D0%BA%D0%BE%D0%BF%D0%BB%D0%B0%D0%B7%D0%BC%D0%B0.png\" alt=\"Микоплазма.png\" data-original-src=\"https://files.coursebook.lol/Coursebook%20Assets/2026-05-05/coursebook-assets/assets/%D0%9C%D0%B8%D0%BA%D0%BE%D0%BF%D0%BB%D0%B0%D0%B7%D0%BC%D0%B0.png\" data-width=\"100\" style=\"width: 555px; max-width: 100%; height: auto; display: block\" data-broken-cleanup-bound=\"1\"></p><ul><li><strong>Chlamydia psittaci:</strong></li><ul><li>Прояви – суха кашлица, фебрилитет, гърлобол, <strong>дрезгав глас</strong> – типична проява, артрит</li><li>Контакт с птици, анамнеза за симптоми дълго време преди хоспитализация.</li></ul><li><strong>Coxiella burnetii - ку-треска:</strong></li><ul><li>Зооантропоноза – резервоар на инфекцията – домашни животни-говеда, овце, кози, по-рядко коне, кучета, котки, домашни птици.</li></ul></ul><p>Причинителят се отделя чрез мляко, фекалии, урина, околоплодна течност</p><ul><li>Рискови професии - животновъди, работещи в месопреработвателна и млечна промишленост, ветеринари</li><li>Клинично протичане:</li><ul><li>Остра Ку-треска: грипоподобно заболяване, атипична пневмония, често усложнение – хепатит</li><li>Хронична Ку-треска: рядко – при &lt; 5% от пациентите с остра форма. Настъпва месеци и години след острата форма.</li></ul></ul><p>Класическа проява – Ку-ендокардит</p><ul><li>Средство на избор при лечението –тетрациклини!</li></ul><ul><li><strong>Вируси:</strong>  началните симптоми (първите 3-5 дни) носят характеристиката на съответната вироза, имуносупресия, коморбидитет, могат да предизвикат остър респираторен дистрес синдром при възрастни (ARSD).</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Изследвания</h2><ul><li><strong>Рентген:</strong> засенчаване по-често на долните лобове, <strong>интерстициални инфилтрати</strong>, кухини и плеврални изливи.</li><li><strong>Лаб:</strong> <strong>↑CRP</strong>, <strong>↑PCT</strong> (прокалцитонин), <strong>левкоцитоза с олевяване</strong>, ускорено СУЕ, електролитни нарушения (хипокалиемия, хипонатриемия).</li><li><strong>КГА:</strong> хипоксемия, хиперкапния и респираторна ацидоза. При по-тежки протичания може да се развие метаболитна ацидоза.</li><li><strong>Микробиология:</strong> спутум (Gram/култура), хемокултури, изследване на плеврална течност, бронхиален секрет (лаваж, протектирана четка), ендотрахеална аспирация, трансторакална иглена аспирация, имунологични тестове (РСК за М.Pneumoniae, С.Pneumoniae и Legionella, имунофлуоресценция, ELISA, уринен антигенен тест за L.Pneumophila и S.pneumoniae).</li><ul><li><strong>PCR:</strong> полезен е за откриване на <strong>S.pneumoniae</strong> (в спутум и кръв), когато антибиотичната терапия е вече започната. Препоръчва се се откриване на <strong>influenza и RSV</strong> през зимните месеци, а също така и за диагноза на <strong>„атипични патогени”</strong>.</li></ul><li><strong>CRP:</strong> &lt;20 mg/L → малко вероятна CAP; &gt;100 mg/L → силно вероятна.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Диагноза</h2><p><strong>(виж определение)</strong>   </p><p>Пневмония трябва да бъде подозирана при наличие на <strong>един или повече</strong> от следните признаци/симптоми:</p><ul><li>нови огнищни обективни находки в гръдния кош</li><li>диспнея</li><li>тахипнея</li><li>пулсова честота &gt; 100</li><li>фебрилитет &gt; 4 дни</li><li>При пациенти с подозирана пневмония е необходимо да се извърши тест за серумни нива на <strong>C-reactive protein (CRP)</strong>.</li><ul><li><strong>CRP &lt; 20 mg/L </strong>със симптоми &gt; 24 ч. — пневмонията е малко вероятна.</li><li><strong>CRP &gt; 100 mg/L</strong> — пневмонията е много вероятна.</li></ul><li>При съмнение е необходимо да се осъществи <strong>пулмография</strong> (рентгенография на гръден кош).</li></ul><table><tbody><tr><td><strong><span style=\"color: rgb(88, 129, 87)\">Рисков фактор</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Вероятен причинител</span></strong></td></tr><tr><td><strong>ХОББ и/или бронхиектазии</strong></td><td><em>N. influenzae</em>, <strong>Грам (-) ентеробактерии</strong>, <em>P. aeruginosa</em></td></tr><tr><td><strong>Скорошна хоспитализация</strong></td><td><strong>Грам (-) ентеробактерии</strong>, <em>P. aeruginosa</em></td></tr><tr><td><strong>Скорошно антимикробно лечение</strong></td><td><strong>Грам (-) ентеробактерии</strong>, <em>P. aeruginosa</em></td></tr><tr><td><strong>Аспирация</strong></td><td><strong>Смесена инфекция</strong>, <strong>анаероби</strong></td></tr><tr><td><strong>Грип</strong></td><td><em>S. aureus</em>, <em>S. pneumoniae</em>, <em>N. influenzae</em></td></tr><tr><td><strong>Контакт с животни</strong></td><td><em>C. burnetii</em></td></tr><tr><td><strong>Контакт с птици</strong></td><td><em>C. psittaci</em></td></tr><tr><td><strong>Венозни наркомани</strong></td><td><em>S. aureus</em> - MSSA, <strong>MRSA</strong></td></tr><tr><td><strong>Лечение с кортикостероиди</strong></td><td><em>P. aeruginosa</em>, <em>Aspergillus spp.</em></td></tr></tbody></table><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Оценка на тежестта (CURB-65)<br></h2><ul><li><strong>C</strong>onfusion&nbsp;– новопоявило се нарушение в съзнанието</li><li><strong>U</strong>rea&nbsp;&gt;7 mmol/L</li><li><strong>R</strong>espiratory rate&nbsp;≥ 30/мин</li><li><strong>B</strong>lood pressure&nbsp;&lt;90/60 mmHg</li><li><strong>65</strong> – възраст &gt;65 г.</li></ul><table><tbody><tr><td><strong><span style=\"color: rgb(88, 129, 87)\">Точки</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">30-дневна смъртност</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Препоръка</span></strong></td></tr><tr><td>0–1</td><td>~1%</td><td>Амбулаторно</td></tr><tr><td>2</td><td>~9%</td><td>Преценка за хоспитализация</td></tr><tr><td>≥3</td><td>15–57%</td><td>Задължителна спешна хоспитализация (при 4-5 точки - интензивно отделение)</td></tr></tbody></table><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Критерии за тежкo ППО</h2><p><strong>1 голям</strong> или <strong>≥3 малки</strong> критерия:</p><p><strong>Големи:</strong>  </p><ul><li>Септичен шок&nbsp;с необходимост от употреба на вазопресори</li><li>Дихателна недостатъчност, изискваща механична вентилация</li></ul><p><strong>Малки:</strong>  </p><ul><li>Нарушения в съзнанието</li><li>Урея ≥ 7 mmol/l</li><li>Дихателна честота ≥ 30/мин</li><li>Хипотония, изискваща агресивна обемзаместваща терапия</li><li>РаО2/FiO2 ≤ 250</li><li>мултилобални инфилтрати</li><li>левкопения &lt; 4k (при липса на друго обяснение като химиотерапия)</li><li>тромбоцитопения &lt; 100k</li><li>хипотермия &lt; 36°C</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Диференциална диагноза при съмнение за пневмония</h2><p><strong>Левокамерна сърдечна недостатъчност (ЛСН)</strong>  </p><ul><li>Подозира се при пациенти около или над 65 години с <strong>ортопнея</strong>, <strong>изместен сърдечен връх</strong>, анамнеза за <strong>миокарден инфаркт</strong>, <strong>хипертония</strong> или <strong>предсърдно мъждене</strong>.</li><li><strong>Ниски серумни нива на артриален натриуретичен пептид (BNP &lt; 40 pg/mL или NT-proBNP &lt; 150 pg/mL)</strong> правят диагнозата малко вероятна.</li><li>Типични находки: <strong>двустранни базални влажни хрипове</strong>, <strong>кардиомегалия</strong>, <strong>застой на пулмографията</strong>, <strong>абнормна ЕКГ</strong>, <strong>кардиомегалия</strong>.</li></ul><p><strong>Екзацербация на ХОББ</strong>  </p><ul><li>При пациенти с <strong>персистираща кашлица</strong> и ≥ 2 от следните:</li><ul><li>хриптене (признак или симптом)</li><li>предходни консултации за кашлица/хриптене</li><li>диспнея</li><li>удължено издишване</li><li>анамнеза за <strong>тютюнопушене</strong></li></ul><li>Лабораторни находки: <strong>хипоксемия</strong>, <strong>хиперкапния</strong>, <strong>повишен хематокрит</strong>, <strong>умерено повишен CRP</strong> при инфекциозна екзацербация.</li></ul><p><strong>Екзацербация на астма</strong>  </p><ul><li>Анамнеза за поставена в миналото диагноза астма.</li><li>Налице са <strong>хриптене</strong>, <strong>експираторна диспнея</strong>, <strong>хипоксемия</strong>, <strong>умерено повишен CRP</strong>, понякога <strong>еозинофилия</strong>.</li><li>Рентгенография: <strong>нормална</strong> или показва <strong>хиперинфлация</strong>.</li></ul><p><strong>Белодробна тромбоемболия (БТЕ)</strong>  </p><ul><li>Анамнеза за <strong>внезапна диспнея</strong> и/или <strong>плеврална болка</strong>, понякога <strong>хемоптиза</strong>.</li><li>Рискови фактори: <strong>ДВТ/БТЕ в анамнезата</strong>, <strong>имобилизация в предходните 4 седмици</strong> или <strong>малигнено заболяване</strong>.</li><li><strong>D-димер</strong>:</li><ul><li>&lt; 500 ng/mL (или възраст × 10 ng/mL при пациенти &gt; 50 г.) → <em></em>БТЕ е малко вероятна</li></ul></ul><ul><li>Повишен D-димер → <strong>CT пулмоангиография</strong> за потвърждение.</li></ul><ul><li>Допълнителни находки: <strong>тахикардия</strong>, <strong>хипоксемия</strong>, <strong>липса на инфилтрат</strong> на рентгенография.</li></ul><p><strong>Белодробна туберкулоза</strong>  </p><ul><li>Анамнеза за хронична кашлица, субфебрилитет, нощно изпотяване, загуба на тегло.</li><li>По-честа в региони с <strong>висока заболеваемост</strong>.</li><li>Рентгенография: <strong>инфилтрати или нодуларни лезии</strong>, често в <strong>горните дялове</strong>.</li><li>Диагнозата се потвърждава <strong>микробиологично</strong> – <strong>храчка (Ziehl-Neelsen, PCR, култура)</strong>.</li><li><strong>Интерферон-гама тестове (IGRA)</strong> – положителни при <strong>активна или латентна инфекция</strong>, подпомагат диференциацията от бактериална пневмония.</li><li>CRP и СУЕ – <strong>умерено повишени</strong>.</li><li><strong>ADA:</strong> може да бъде повишена, но не е специфична при белодробна форма, а за туберкулозен плеврит.</li></ul><p><strong>Белодробен карцином</strong>  </p><ul><li>Анамнеза за <strong>хронична кашлица</strong>, <strong>хемоптиза</strong>, <strong>загуба на тегло</strong>, <strong>тютюнопушене</strong>.</li><li>Рентгенография: <strong>солитарна маса</strong>, <strong>ателектаза</strong> или <strong>нодуларни промени</strong>.</li><li>Маркери: <strong>повишен LDH</strong>, <strong>анемия</strong>, <strong>хиперкалциемия</strong>.</li><li>Диагнозата се потвърждава <strong>цитологично или хистологично</strong>.</li></ul><p><strong>Бронхиектазии</strong>  </p><ul><li>Анамнеза за <strong>хронична продуктивна кашлица с гнойна експекторация</strong>, <strong>рецидивиращи инфекции</strong>, <strong>разнокалибрени влажни хрипове</strong> в определен участък.</li><li><strong>CRP повишен</strong> при екзацербация.</li><li><strong>HRCT</strong> показва <strong>дилатирани бронхи</strong> с <strong>удебелени стени</strong>.</li></ul><p><strong>Аспирация на чуждо тяло</strong>  </p><ul><li>Анамнеза за <strong>аспирация или кашлица по време на хранене</strong>, особено при деца или възрастни с неврологични нарушения.</li><li>Обективно: <strong>едностранно намален вход на въздух</strong> или <strong>локални хрипове</strong>.</li><li>Рентгенография: <strong>ателектаза</strong> или <strong>хиперинфлация</strong> на засегнатия дял.</li></ul><p><strong>Фиброзиращ алвеолит (идиопатична белодробна фиброза)</strong>  </p><ul><li>Анамнеза за <strong>хронична кашлица</strong>, <strong>прогресивна диспнея</strong>, <strong>дребни инспираторни влажни хрипове</strong>.</li><li><strong>HRCT</strong>: <strong>ретикуларни промени</strong>, „<strong>пчелна пита</strong>“ модел.</li><li><strong>Спирометрия</strong>: рестриктивен тип с <strong>намален DLCO</strong>.</li><li>Възможни <strong>положителни антинуклеарни антитела</strong> (системно автоимунно заболяване) или <strong>анти-топоизомераза I антитела</strong> (системна склеродермия) при автоимунни форми.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Усложнения</h2><ul><li><strong>Белодробни усложнения:</strong></li><ul><li>Белодробен абсцес</li><li>Белодробен кръвохрак</li><li>Остра дихателна недостатъчност, ARDS (остър респираторен дистрес синдром при възрастни)</li><li>Пневмоторакс</li></ul><li><strong>Извънбелодробни усложнения:</strong></li><ul><li>Сепсис с мултиорганна недостатъчност</li><li>Сърдечно-съдови усложнения: ендокардити, миокардити, перикардити, ритъмни нарушения, остър коронарен синдром</li><li>Чернодробни усложнения – токсичен хепатит</li><li>Бъбречни усложнения – ОБН</li><li>Неврологични –менингити, енцефалити, полиневрити</li></ul></ul><h3>Повишен риск за усложнения на пневмониите</h3><ul><li><strong>При пациенти над 65 г. възраст:</strong> наличие на ХОББ, диабет, сърдечна недостатъчност, хоспитализации в предходната година, прием на кортикостероиди, употреба на антибиотици, обща слабост/изтощение, липса на симптоми от горните дихателни пътища обърканост, пулс&gt;100, температура&gt;38°C, RR&gt;30, АН &lt;90/60 mmHg.</li><li><strong>При пациенти под 65 г. възраст:</strong> наличие на диабет и астма.</li><li><strong>И за двете групи:</strong> активно малигненоп заболяване, чернодробна и бъбречна недостатъчност, нарушения, водещи до имунен дефицит.</li></ul><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><br><br><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">18. Вътреболнични пневмонии</h1><h2>Дефиниция</h2><p>Вътреболничната пневмония (НАР) се дефинира като появата на <strong>нови рентгенографски инфилтрати</strong> при наличие или доказателства за инфекция (висока температура, гнойна експекторация, левкоцитоза), <strong>поне 48–72 часа след прием в болница</strong>.  </p><p>Пациентите с висок риск са тези на <strong>механична вентилация</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Етиология</h2><ul><li>Около <strong>50% са смесени инфекции</strong>.</li><li>Основни причинители:</li><ul><li><i>Pseudomonas aeruginosa</i></li></ul></ul><ul><ul><li>Staphylococcus aureus (включително MRSA)</li></ul></ul><ul><ul><li><em>Peptostreptococcus</em></li><li><em>Fusobacteroides</em></li><li><em>Bacteroides</em></li><li><em>Enterobacter spp.</em></li><li><em>E. coli</em></li><li><em>S. marcescens</em></li><li><em>Klebsiella</em></li><li><em>Proteus spp.</em></li><li><em>Acinetobacter</em></li><li><em>Escherichia coli</em></li><li>Вируси</li></ul></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Патогенеза</h2><p>Основна роля играе <strong>аспирацията на орофарингеално съдържимо</strong>.  </p><p>При хоспитализирани болни орофаринксът се колонизира с аеробни грам-отрицателни бактерии или <em>S. aureus</em> няколко дни след постъпване в болницата.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Предразполагащи фактори</h2><ul><li>Възраст &gt; 70 г.</li><li>Хронични белодробни заболявания или други съпътстващи заболявания</li><li>Промени в съзнанието</li><li>Механична вентилация</li><li>Хирургична интервенция</li><li>Назогастрално хранене</li><li>Лоша зъбна хигиена</li><li>Предшестващо антибиотично лечение</li><li>Дългосрочна употреба на стероиди, цитостатично или биологично лечение</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Клинична картина</h2><ul><li>Висока температура</li><li>Продуктивна кашлица</li><li>Повишени лабораторни показатели за възпаление</li><li>Нови рентгенови инфилтрати</li><li>Влошаване на кръвно-газовите показатели</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Усложнения</h2><ul><li>Белодробен абсцес и емпием</li><li>Сепсис с мултиорганна недостатъчност</li><li>Белодробна емболия с вторична инфекция (по-чести при нозокомиална пневмония)</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Прогноза</h2><ul><li>Висока смъртност: <strong>20–50%</strong></li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Профилактика</h2><ul><li>Спазване на вътреболнична хигиена</li><li>Контрол при отчитането на инфекции</li><li>Ваксинация: противогрипна, пневмококова, хемофилусна</li></ul><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><br><br><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">19. Лечение на пневмониите</h1><h2>Лечение на пневмония придобита в обществото</h2><h3>I. Постелен режим, постепенно разширяване на диетата<br>II. Антимикробна терапия (АМТ)</h3><h4><strong>1. Видове АМТ</strong></h4><p><strong>а) Емпирична АМТ</strong></p><ul><li>Цели да покрие най-вероятния причинител при конкретния болен</li><li>Използват се най-често антибиотици от <strong>β-лактамната</strong> и <strong>макролидната</strong> група</li><li><strong>Начална терапия:</strong></li><ul><li>Широкоспектърна</li><li>В достатъчно висока дозировка</li><li>Съобразена с <strong>чернодробна</strong> и <strong>бъбречна</strong> функция</li></ul><li><strong>Начало:</strong> незабавно след поставяне на диагнозата</li><ul><li>В рамките на <strong>първия час</strong> при пациенти със <strong>септичен шок</strong></li></ul></ul><p><strong>б) Етиологична АМТ</strong></p><ul><li>Назначава се при доказан микробиологичен причинител</li></ul><h4>2. Критерии за избор на антибиотик</h4><ul><li>Вероятни причинители според <strong>тежестта на пневмонията</strong> и <strong>допълнителните рискови фактори</strong></li><li><strong>Локална резистентност</strong> и предходна употреба на АМП</li><li><strong>Поносимост</strong> и <strong>токсичност</strong> на медикамента</li><li><strong>Ранен правилен избор</strong> → критичен за успеха на лечението</li></ul><h4>Препоръки за начална емпирична АМТ при ППО</h4><table><tbody><tr><td><strong>Място</strong></td><td><strong>Тежест/Подгрупа</strong></td><td><strong>Препоръчително лечение</strong></td><td><strong>Алтернативно лечение</strong></td></tr><tr><td><strong>Амбулаторно</strong></td><td>Всички</td><td>beta-лактам и/или макролид</td><td>levofloxacin, moxifloxacin</td></tr><tr><td><strong>Болница</strong></td><td>Лека/средно тежка</td><td>пеницилин ± макролид<br>beta-лактам ± макролид<br>co-amoxiclav ± макролид<br>цефалоспорин II-III ± макролид</td><td>levofloxacin, moxifloxacin</td></tr><tr><td><strong>Болница</strong></td><td>Тежка</td><td>цефалоспорин ± макролид</td><td>цефалоспорин III генерация ± levofloxacin, moxifloxacin</td></tr><tr><td><strong>Болница</strong></td><td>Тежка и риск за <em>P. aeruginosa</em></td><td>антипсевдомонасен цефалоспорин + ciprofloxacin</td><td>цилуреидопеницилин + beta-лактамазен инхибитор + ciprofloxacin или <br>карбапенем + ciprofloxacin</td></tr></tbody></table><h3>III. Секвенциална терапия</h3><ul><li><strong>Преминаване към перорално лечение</strong> след <strong>3–7 дни парентерална терапия</strong></li><li>Подходяща при хоспитализирани болни с <strong>лека или средно тежка пневмония</strong></li><li>Намалява цената на лечението, увеличава комфорта и мобилността на пациента, минимизира риска от странични ефекти (флебити, инфекции, натоварване с течности).</li></ul><p><strong>Критерии за преминаване към секвенциална терапия:</strong></p><ul><li>Без фебрилитет &gt; 24 ч</li><li>Пулс &lt; 100 уд./мин</li><li>Без тахипнея и хипотония</li><li>Подобрение на левкоцитозата</li><li>Без бактериемия</li><li>Без инфекция с <em>Legionella</em>, <em>Staphylococcus</em> или Грам (-) ентеробацили</li><li>Добре функциониращ ГИТ</li><li>Подобрение на основните клинични белези (фебрилитет, ОДН, промени в съзнанието и др.)</li></ul><h3>IV. Допълнителна терапия</h3><ul><li>При пациенти със суха и дразнеща кашлица се назначават:</li><ul><li><strong>Dextromethorphan </strong>– потиска кашличния рефлекс на централно ниво, без да предизвиква зависимост.</li><li><strong>Codeine</strong> – опиоиден антитусивен агент, прилага се при тежка, мъчителна кашлица, но <strong>само краткосрочно</strong> поради риск от зависимост и потискане на дишането.</li></ul><li><strong>Кислородотерапия при нужда:</strong> за постигане на сатурация &gt; 92%</li><li><strong>Нискомолекулярен хепарин:</strong> при пациенти с <strong>остра дихателна недостатъчност</strong></li><li><strong>Неинвазивна вентилация:</strong> при болни със съпътстващ <strong>ХОББ</strong></li><li><strong>Кортикостероиди:</strong> нямат място, освен при <strong>септичен шок</strong></li></ul><h3>V. Хоспитализация – кога?</h3><ul><li>Тежко състояние: тахипнея, тахикардия, хипотензия, обърканост</li><li>Липса на отговор на антибиотично лечение</li><li>Възрастни болни с повишен риск от усложнения</li><li>Подозрение за <strong>белодробен емболизъм</strong> или <strong>малигнено заболяване</strong></li></ul><h3>VI. Индикации за механична вентилация</h3><ul><li><strong>По-добре рано, отколкото късно</strong></li><li>Тежка дихателна недостатъчност (PaO2/FiO2 &lt; 250) въпреки кислородна терапия</li><li>Умора с нарастваща хиперкапния (PaCO2 ↑)</li><li>Влошаваща се метаболитна ацидоза въпреки оптимално лечение</li><li>Хипотензия, неповлияваща се от адекватна инфузионна терапия</li></ul><h3>VII. Продължителност на лечението</h3><ul><li>обикновено <strong>7–10 дни</strong>, по-дълго при Legionella, S. aureus, Грам(-).</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Лечение на вътреболнична пневмония</h2><p><strong>1. </strong><strong>Емпирично антибиотично лечение за </strong><strong>пациенти без рискови фактори за мултирезистентни патогени (ранна поява до 4-ти ден)</strong></p><table><tbody><tr><td><strong><span style=\"color: rgb(88, 129, 87)\">Потенциални патогени</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Препоръчителна терапия</span></strong></td></tr><tr><td><em>Streptococcus pneumoniae</em><br><em>Haemophilus influenzae</em><br>Метицил-чувствителен <em>Staphylococcus aureus</em><br><em>Escherichia coli</em><br><em>Klebsiella pneumoniae</em><br><em>Enterobacter</em> species<br><em>Serratia marcescens</em></td><td>Ceftriaxone <br>или<br> Levofloxacin, Moxifloxacin, Ciprofloxacin<br>или<br>Ampicillin/sulbactam<br>или<br>Ertapenem</td></tr></tbody></table><p><strong>2. </strong><strong>Емпирично антибиотично лечение за </strong><strong>пациенти с късна поява на болестта (&gt;4-ти ден) или рискови фактори за MDR (мултирезистентни патогени)</strong></p><table><tbody><tr><td><strong><span style=\"color: rgb(88, 129, 87)\">Потенциални патогени</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Препоръчителна терапия</span></strong></td></tr><tr><td>Патогените от таблица 1 + MDR патогени:<br><em>Pseudomonas aeruginosa</em><br><em>Klebsiella pneumoniae</em><br><em>Acinetobacter</em><br>MRSA<br><em>Legionella pneumophila</em></td><td>Антипсевдомонасен цефалоспорин (Cefepime, Ceftazidime)<br>или<br>Антипсевдомонасен карбапенем (Imipenem, Meropenem)<br>или<br>b-лактам/b-лактамен инхибитор (Piperacillin-tazobactam)<br><strong>+</strong><br>Антипсевдомонасен флуорохинолон (Ciprofloxacin, Levofloxacin)<br><strong>или</strong><br>Аминогликозиди (Amikacin, Gentamicin, Tobramycin)<br><strong>+\n</strong>Linezolid или Vancomycin</td></tr></tbody></table><ul><li>Съпътстващо лечение: кислород, инфузии, механична вентилация при необходимост</li></ul><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><br><br><hr style=\"text-align: center; border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">20. Дихателна недостатъчност – дефиниция, етиология, класификаци, клиника и диагноза</h1><h2>Дефиниция</h2><p>Дихателната недостатъчност (ДН) е клиничен синдром, при който е нарушен белодробният кислороден трансфер. Дихателната система не е в състояние да изпълнява своята основна функция - газообменната, в резултат на което се стига до <strong>хипоксия</strong> (рО2 &lt; 80 mm Hg) с или без <strong>хиперкапния</strong> (рСО2 &gt; 45 mm Hg).</p><p>Механизмите за възникване на артериалната хипоксия и хиперкапния са следните:</p><ul><li><em>Намалено отношение вентилация/перфузия</em> (функционални или анатомични шънтове);</li><li><em>Обща алвеоларна хиповентилация</em>;</li><li><em>Нарушена дифузия на О2</em> през алвеоло-капилярната бариера;</li><li><em>Понижено парциално налягане на О2 </em>в алвеолите поради вдишване на въздух с по-ниска концентрация на кислород (има значение при високопланинската болест).</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Форми на дихателната недостатъчност</h2><p>От етиологична гледна точка ДН се дели на <strong>пулмонална</strong> и <strong>екстрапулмонална</strong>. </p><p>В зависимост от клиничното протичане, ДН бива <strong>остра, хронична и обострена</strong>.</p><h3>I. Остра дихателна недостатъчност (ОДН)</h3><p><strong>Характеристика:</strong></p><ul><li>ОДН е критична ситуация, която настъпва <strong>остро (инцидентно)</strong> на базата на <strong>неувредени бели дробове</strong>.</li><li>Белодробният газообмен внезапно се блокира, потиска или силно затруднява.</li><li>Той не е в състояние да артериализира оттичащата се кръв и става неадекватен на кислородните нужди на организма.</li><li>При ОДН <strong>артериалната хипоксия</strong> (pО2<strong>↓</strong>) по принцип, се съчетава с <strong>артериална хипоксемия</strong> (ctО2<strong>↓</strong>).</li></ul><p>Причините за възникване на ОДН са многобройни:</p><ul><li>Потискане на дихателния център от различни нокси</li><li>Остри травми и увреждане на гръдната клетка и плеврата</li><li>Парези и парализи на дихателната мускулатура</li><li>Остра обструкция на дихателните пътища</li><li>Остър белодробен оток от токсично, възпалително или механично естество</li></ul><p>Изброените причини по механизмите на липсващата дихателна команда или критично повишен дихателен импеданс (остра обструкция или рестрикция), бързо довеждат до остра хипоксия с животоопасни последици.</p><p><strong>Разграничават се два типа ОДН:</strong></p><ol><li><strong>Хипоксемичната ОДН</strong> се представя с <strong>хипоксия</strong> и с <strong>хипо- или нормокапния</strong>.</li><ul><li>Хипоксемичната ОДН се нарича още „белодробна“, „паренхимна\" или „частична\".</li><li>Тя се развива най-често след латентен период от 24 до 72 часа.</li><li>Основен патогенетичен фактор при нея е силно увеличеният <strong>транспулмонален </strong><strong>дясно-ляв шънт</strong>, който довежда до остър оксигенационен дефицит.</li><li>Шънтът може да бъде последица от прогресиращ <strong>белодробен оток</strong>, <strong>генерализиран пулмонит</strong> или <strong>масивни ателектази</strong>.</li><li>Хипоксемичен тип ОДН са острите респираторни дистрес синдроми у новородени и възрастни.</li></ul><li><strong>Хиперкапничната ОДН</strong> се представя с <strong>хипоксия</strong> и <strong>хиперкапния</strong>.</li><ul><li>Хиперкапничната ОДН се нарича още „помпена” или „тотална”.</li><li>Тя се развива непосредствено след действието на причината.</li><li>Основен патогенетичен фактор при нея е остро настъпващата <strong>хиповентилация</strong>.</li><li>Типични примери са:&nbsp;<strong>механична асфиксия</strong>, <strong>депресия на дихателния център</strong>, <strong>невромускулни заболявания</strong>.</li><li>Тотално нарушената газообмяна довежда за кратко време до тежък срив в кислородния режим, придружен с остра респираторна и метаболитна ацидоза.</li><li>Хиперкапничната ОДН се диагностицира при стойности на <strong>рО2 &lt; 8.00 kPa</strong> (60 mmHg) и на <strong>рСО2&nbsp;&gt; 6.7 kPa</strong> (50 mmHg).</li></ul></ol><p><img src=\"https://files.coursebook.lol/Coursebook%20Assets/2026-05-05/coursebook-assets/assets/%D0%94%D0%9D.png\" alt=\"ДН.png\" data-original-src=\"https://files.coursebook.lol/Coursebook%20Assets/2026-05-05/coursebook-assets/assets/%D0%94%D0%9D.png\" data-width=\"50\" style=\"width: 595.5px; max-width: 100%; height: auto; display: block\" data-broken-cleanup-bound=\"1\"><br><strong>Лечението </strong>на ОДН налага спешно отстраняване на причината, довела до ОДН, осигуряване на проходими дихателни пътища, адекватно вентилиране и кислородотерапия.</p><h3>II. Хронична дихателна недостатъчност (ХДН)</h3><p>Хроничната дихателна недостатъчност се развива постепенно, което дава възможност за компенсаторни механизми. Тези адаптации определят дали ХДН е:</p><p><strong>1. Компенсирана ХДН.</strong> </p><ul><li>При състояние на покой няма артериална хипоксия и клинични симптоми, защото са налице ефективни адаптации.</li><li>Артериалната хипоксия, диспнеята и другите клинични признаци се появяват при <strong>физическо натоварване</strong>.</li><li>Редица патогенетични фактори могат да превърнат една компенсирана ХДН в декомпенсирана (манифестна):</li><ul><li>Активна бронхо-пулмонална инфекция (най-честата причина)</li><li>Депресивни въздействия върху дихателния център (седативни средства или неправилна кислородотерапия)</li><li>Левостранна сърдечна декомпенсация, ритъмни нарушения</li><li>Засилени метаболитни процеси (физическа работа, хипертермия)</li><li>Намалена торако-пулмонална подвижност (травма, плеврит).</li></ul></ul><p><strong>2. Манифестна ХДН.</strong> </p><ul><li>Характеризира се с наличието на артериална хипоксия и клинични симптоми и <strong>при покой</strong>.</li><li>Поради наличието на полиглобулия може&nbsp;общото количество пренесен кислород (ctO2) може да е нормално (нормоксемия), въпреки че pO2 е ниско.</li><li>При физическо натоварване клиничните признаци се засилват.</li><li>Според тежестта манифестната дихателна недостатъчност, има <strong>три степени:</strong></li><ul><li><strong>Първа степен</strong> - рО2 от <strong>8.0 kPa до 9.3 kPa (60-70 mmHg)</strong>;</li><ul><li>Без<strong> хиперкапния</strong>.</li><li>В клиниката <u>доминира респираторният синдром</u> (кашлица, храчки, задух).</li></ul><li><strong>Втора степан</strong> - рО2 от <strong>6.7 kPa до 8.0 kPa (50-60 mmHg)</strong>;</li><ul><li><strong>Нормо-, хипо и по-рядко хиперкапния</strong>.</li><li>Появите на респираторния синдром се задълбочават (цианоза, инспираторен тираж, барабанни пръсти)</li><li>Поради развитието на пулмонална хипертензия, в клиниката се появяват и <strong>симптомите на кардиоциркулаторния синдром</strong> (пулсации в епигастриума, подути шийни вени, тахикардия/брадикардия, аритмия, десен галоп, увеличен черен дроб, отоци, лесна уморяемост).</li><li>Поради компенсаторната полуглобулия и повишения хематокрит, <strong>нараства рискът от белодробен тромбоемболизъм</strong>.</li></ul><li><strong>Трета степен</strong> - рО2 <strong>&lt; 6.7 kPa (&lt; 50 mm Hg)</strong>;</li><ul><li>С <strong>хиперкапния - респираторна ацидоза</strong>.</li><li>Появява се&nbsp;<strong>респираторна енцефалопатия</strong> (главоболие, виене на свят, обърканост, агресивност, депресия, сомнолентност, наушения в паметта, дезориентация за време и място, Flaping тремор).</li><li>Общото състояние е силно увредено, поради наличието на <strong>тотална кардиореспираторна недостатъчност</strong>.</li><li><strong>Цианозата е изразена и има смесен характер</strong> - централна (белодробна) и периферна (циркулаторна).</li></ul></ul></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Усложнения при болни с ОДН</h2><ul><li><strong>Белодробни:</strong> БТЕ, фиброза</li><li><strong>Усложнения, свързани с поставянето на централен венозен път:</strong> пневмоторакс, въздушна емболия, аритмии, инфекции, тромбози, руптура на венозен съд.</li><li><strong>Усложнения, свързани с трахеална интубация:</strong> хипоксемична мозъчна увреда, инсулт, сърдечен арест, хиповентилация, пневмоторакс, ателектаза, изпадане на интубационата тръба, дислокация на ендотрахеалната тръба, увреждане на горни дихателни пътища.</li><li><strong>Усложнения от механичната вентилация:</strong> инфекции, артериална десатурация, хипотония, баро-травма.</li><li><strong>Усложнения, свързани с трахеостомата:</strong> пневмоторакс, кръвоизливи, фисури, фистули, стенози.</li><li><strong>Гастроинтестинални:</strong> хеморагии, илеус, диария.</li><li><strong>Кардиоваскуларни:</strong> хипотония, аритмия, сърдечна недостатъчност, остър миокарден инфаркт.</li><li><strong>Бъбречни:</strong> остра бъбречна недостатъчност, задръжка на течности.</li><li><strong>Инфекциозни:</strong> нозокомиални, бактериални, сепсис.</li><li><strong>Хранене:</strong></li><ul><li><strong>Свързани с лошо хранене</strong> - спадане на силата на респираторните мускули, имунна супресия;</li><li><strong>Свързани с ентерално хранене</strong> - пневмоторакс, плеврален излив, аспирация, диария;</li><li><strong>Свързани с парентерално хранене</strong> - пневмоторакс, сепсис, хипергликемия, хиперосмоларна кома.</li></ul><li><strong>Други:</strong></li><ul><li>Психотични-депресия, нарушения в съня, безпокойство;</li><li>Хематологични - анемия, тромбоцитопения.</li></ul></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Диагноза</h2><ul><li><strong>Кръвно-газов анализ</strong></li><li><strong>Йонограма</strong> (хипокалиемия, хипофосфатемия - задълбочават умората на дихателната мускулатура)</li><li><strong>Кръвна картина</strong> (анемията задълбочава хипоксемията)</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Диференциална диагноза</h2><ul><li>Сърдечна недостатъчност с кардиална астма или белодробен оток</li><li>Мозъчен тумор</li><li>Бъбречна недостатъчност</li><li>Психоза, невроза</li></ul><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><br><br><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">21. Дихателна недостатъчност - приниципи на лечение</h1><h3>1. Кислородно лечение.</h3><p>Задължително е спазването на принципите па кислородолечението:</p><ul><li><strong>непрекъснато</strong></li><li><strong>дозирано</strong></li><ul><li>при <strong>ОДН:</strong></li><ul><li>FiO2 <strong>0.40 - 0.60</strong> с маска тип Venturi.</li><li>Когато корекцията на хипоксемията (SaO2&gt;90%) по този начин е невъзможна, се пристъпва към подпомагане на дишането - неинвазивна вентилация с позитивно налягане или инвазивна вентилация.</li></ul><li>при <strong>ХДН:</strong></li><ul><li>FiO2 <strong>0.20 - 0.28</strong>, особено при високостепенна хиперкапния, с назален катетър тип „очила“ или маски тип <span class=\"editor-note\" data-note=\"![Venturi Mask](https://external-content.duckduckgo.com/iu/?u=https%3A%2F%2Fgeekymedics.com%2Fwp-content%2Fuploads%2F2023%2F01%2FVenturi-masks.jpeg&amp;f=1&amp;nofb=1&amp;ipt=e6bc4803ecf3fa512ed9b3ea1bee64d1cfdf16029a48c5f77f17f79dde552d01)\" id=\"note-1773249254785-1\">Venturi</span>.</li><li>Изборът на подаваната кислородна концентрация се определя от причината за ХДН, тежестта на хипоксемията и степента на хиперкапния, когато е налице.</li><li>Кислородотерапията трябва да се титрира внимателно при налична задръжка на въглероден диоксид за постигане на SaO2 от <strong>88% до 92%</strong>.</li></ul></ul><li><strong>Контролирано</strong> (с кръвно-газов анализ)</li></ul><h3>2. Дезобструктивна терапия</h3><p>а) <strong>Бронходилататори</strong></p><ul><li><strong>В2-агонистит:</strong></li><ul><li>Имат най-мощен бронходилататорен ефект и инхалаторното прилагане е за предпочитане.</li><li>Приемът е съпроводен с малко странични ефекти - тахикардия и тремор.</li></ul><li><strong>Aнтихолинергици</strong> - могат да се комбинират е В2-агонистите.</li><li><strong>Mетилксантини:</strong></li><ul><li>Теофилинът води до бронходилатация при серумно ниво над 5мг/мл.</li><li>При серумно ниво над 20мг/мл се проявяват значими странични ефекти - гадене, повръщане, тремор, тахикардия, аритмии и гърчове.</li><li>Пероралната доза на аминофилина при хроничната дихателна недостатъчност е 600-800 mg/24 часа.</li><li>Натоварващата доза при i.v. приложение е 5 mg/kg за 30 минути, а поддържащата доза при възрастни е 0.5 mg/kg/час.</li><li>Освен бронходилататори, метилксантините са стимуланти на диафрагмата и подпомагат дишането.</li></ul></ul><table><tbody><tr><td><span style=\"color: rgb(88, 129, 87)\"><strong>Препарат</strong></span></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Начин на приложение</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Единична доза (денонощна)</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Времетраене на ефектта</span></strong></td></tr><tr><td><strong>Бета 2- агонист:</strong><br>Salbumatol</td><td>дозир-аерозол - 0.1 mg/впръскванеразтвор - 0.5% (5mg/ml)<br></td><td>2 вдишване (4-6 пъти)0.5 ml (4-6 пъти)<br></td><td>4-6 часа</td></tr><tr><td><strong>Антихолинергици:</strong><br>Ipatropium bromide</td><td>дозир-аерозол - 0.02 mg/dose<br>разтвор - 0.025% (0.25 Mg/ml)<br><br></td><td>2-6 вдишване (4-6 пъти)<br>0.25-0.5 mg (4 пъти)<br><br></td><td>4-6 часа</td></tr></tbody></table><p>б) <strong>Kортикостероидите</strong> се дават рано в лечението в дози 0.5 mg/kg/24чaca<strong> </strong>метилпреднизолон i.v. за 3-5 дни, с редуциране и спиране до 7-10 дни.</p><p>в) <strong>Секретолитични средства:</strong></p><table><tbody><tr><td><strong><span style=\"color: rgb(88, 129, 87)\">Препарат</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Инхалации на 4 - 6 ч.</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">i.v. прилагане</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Per os</span></strong><br></td></tr><tr><td>Ambroxol</td><td>2 ml 0.75% в 2 ml 0.9% NaCI</td><td>15-30 mg/8 ч.</td><td>30 mg/8 ч.</td></tr><tr><td>Bromhexin</td><td>2 ml 0.2% в 2 ml 0.9% NaCI</td><td>4 mg/8 ч.</td><td>Несигурен ефект<br></td></tr><tr><td>N-Acetylcystein</td><td>2-5ml 10% p-p</td><td>-</td><td>Несигурен ефект<br></td></tr></tbody></table><h3>3. Овладяване на хиперкапнията</h3><ul><li>Средства, повлияващи дихателния център и общомозъчната функция (piracetam, centrophenoxin и coffein). Включват се в лечението при нарастваща хиперкапния (<strong>РаСО2&gt;60-65 mmHg</strong>).</li><li>Spironolacton - стимулира отделянето на рСО2.</li></ul><h3>4. Антибиотична терапия&nbsp;(парентерална, широкоспектърна)<br>5. Лечение на дясната сърдечна недостатъчност</h3><ul><li>диуретици</li><li>вазодилататори</li></ul><h3>6. Антикоагулантна терапия -&nbsp;за профилактика на БТЕ</h3><ul><li>хепарин</li><li>нискомолекуларни хепарини</li></ul><h3>7. Кръвопускане при</h3><ul><li>хемоглобин &gt; 180 g/L</li><li>хематокрит &gt; 0.55</li><li>стабилна хемодинамика</li></ul><h3>8. Неинвазивна механична вентилация с <u>назална или лицева маска</u></h3><p>Прилага се при подходяща диагноза с потенциална обратимост и следните показания:</p><ul><li>умерен до тежък респираторен дистрес</li><li>тахипнея (ДЧ &gt; 24/min)</li><li>употреба на спомагателни мускули или абдоминален парадокс</li><li>тежки отклонения в КГА: pH &lt;7.35, РаСО2 &gt;45 mmHg, или PaO2/FiO2 &lt;200</li></ul><p><strong>Противопоказани за неинвазивна маханична вентилация са пациенти със:</strong></p><ul><li>спиране на дишането</li><li>нестабилно състояние (шок, неконтролирано кърване от гастроинтестиналния тракт, неконтролирана аритмия)</li><li>невъзможност за предпазване на дихателни пътища (склонен към аспирация), обилна експекторация</li><li>невъзможност за сътрудничество или възбуда, не може да се адаптира към маската</li><li>скорошна операция - горни дихателни пътища, гастроинтестинална</li></ul><h3>9. Инвазивна (конвенционална механична вентилация) с <u>ендотрахеална тръба</u></h3><p>Прилага се при болни със:</p><ul><li>спиране на дишането или сърдечната дейност</li><li>не толерира неинвазивната механична вентилация или неуспех от нея</li><li>белези на прогресираща дихателна недостатъчност</li><ul><li>честота на дишането над 35/min</li><li>влошаваща се тахикардия или брадикардия &lt;50/min</li><li>тежка диспнея с продължаваща употреба на спомагателната мускулатура</li><li>животозастрашаваща хипоксемия (РаО2 &lt; 40 mmHg или PaO2/FiO2 &lt;200)</li><li>тежка ацидоза (pH &lt;7.25) и хиперкапния (РаСО2 &gt;60 mmHg)</li></ul><li>КГА не е от първостепенно значение при вземане на решението и обичайно само потвърждава клиничната оценка</li><li>влошаване на менталния статус, загуба на съзнание</li><li>придружаваща хемодинамична нестабилност или невъзможност за протекция на дихателните пътища</li></ul><h3>10. Дихателна рехабилитация</h3><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><br><br><hr style=\"text-align: center; border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">22. Саркоидоза</h1><h2>Дефиниция</h2><p>Саркоидозата е <strong>мултисистемно възпалително заболяване с неизвестна етиология</strong>, което засяга предимно <strong>белите дробове</strong> и <strong>интраторакалните лимфни възли</strong>. Манифестира се с наличие на <strong>неказеифициращи грануломи</strong> в засегнатите органи.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2> Епидемиология</h2><ul><li><strong>Възраст и пол</strong>:</li><ul><li>Обикновено се наблюдава във<em></em> възрастта между 20 и 40 години.</li></ul></ul><ul><li><strong>Жените</strong> са по-склонни да развият заболяването, отколкото мъжете.</li><li>При жените е налице <strong>втори пик</strong> между 65- и 69 г.</li></ul><ul><li><strong>Раса</strong>: <strong>Афро-американците</strong> боледуват по-често в сравнение с белите американци.</li><li><strong>Етнос</strong>: Най-висока честота се наблюдава в <strong>Северна Европа</strong> (Скандинавските страни и Великобритания).</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2> Етиология и Патогенеза</h2><ul><li><strong>Етиологията</strong> е <strong>неизвестна</strong>. Смята се, че саркоидозата е резултат на <strong>имунен отговор</strong> към различни <strong>тригери</strong> (напр. <strong>Микобактерии</strong> - <em>Mycobacterium tuberculosis</em>, атипични патогени - <em>Mycoplasma</em>, <em>Chlamydia</em>, гъби, вируси - <em>Epstein-Barr virus</em>, прах и химикали и др.).</li><li>От значение е и <strong>генетичната предиспозиция</strong>.</li><li><strong>Патогенеза</strong>: Тригерите се свързват с антиген представящите клетки и главна роля играят <strong>CD4+ Т клетките</strong>, които взаимодействат с тях и инициират образуването на <strong>саркоидни грануломи</strong>. Те могат да персистират, да се разнесат или да доведат до <strong>фиброза</strong>. Клиничните прояви са резултат от въздействието на грануломите върху органите.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Патоанатомия</h2><p>Саркоидните грануломи са <strong>компактни, централно-организирани колекции от макрофаги и епителоидни клетки</strong>, заобиколени от лимфоцити. </p><p>За разлика от туберкулозните грануломи, <strong>липсва казеозна некроза</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Симптоми и Признаци</h2><p>Симптомите са разнообразни и зависят от засегнатия орган и продължителността на заболяването. Може да протича постепенно, да започне внезапно и да изчезне бързо, да протича и <strong>безсимптомно</strong> (открива се случайно при пулмография).</p><h3>Генерализирани симптоми</h3><ul><li>Умора</li><li>Фебрилитет</li><li>Подути лимфни възли</li><li>Загуба на тегло</li></ul><h3>Белодробни симптоми</h3><ul><li><strong>Персистираща суха кашлица</strong></li><li><strong>Диспнея</strong> при усилие</li><li>Хриптене</li><li>Гръдна болка</li></ul><h3>Кожни симптоми</h3><ul><li><strong>Обрив</strong> - червеникав или морав, най-често по подбедриците и глезените, може да бъде топъл и мековат при палпиране.</li><li>Лезии в областта на носа, бузите и ушите.</li><li>Промени в цвета - участъци от кожата могат да бъдат по-тъмни или по-светли.</li><li>Подкожни възли - в областта на белези и татуировки.</li></ul><h3>Очни симптоми</h3><ul><li>Нарушено зрение</li><li>Болка</li><li>Сърбеж</li><li>Зачервяване</li><li>Чувствителност към светлина</li></ul><h3>Други органи и системи</h3><p>Възможно е да се изявят симптоми и признаци от други органи и системи: увеличен <strong>хепар</strong>, <strong>слезка</strong> или <strong>слюнчени жлези</strong>. По-рядко се засягат <strong>сърцето</strong> и <strong>мозъкът</strong>.</p><h3>Lofgren's Syndrome (Синдром на Льофгрен)</h3><p>Класическа комбинация от признаци и симптоми, която се наблюдава при дебюта на саркоидозата при някои от болните:</p><ul><li><strong>Фебрилитет</strong></li><li><strong>Увеличени лимфни възли</strong> (от пулмографията)</li><li><strong>Артрит</strong> (глезенни стави)</li><li><strong>Erythema nodosum</strong> (червеникав или морав обрив по подбедриците, топъл и мековат при палпация).</li><ul><li><em>Забележка: Erythema nodosum се наблюдава повече при жените, а артрити - при мъжете.</em></li></ul></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Диагноза</h2><p>Диагнозата е трудна поради малкото признаци в ранните стадии и вариращата симптоматика в зависимост от засегнатите органи.</p><p>  Поради отсъствието на патогномоничен диагностичен тест, диагнозата саркоидоза остава диагноза на изключването.</p><h3>1. Рентгенови изследвания - <a href=\"https://radiopaedia.org/articles/sarcoidosis-1?lang=us\">Radiopedia</a></h3><ul><li><strong>Пулмография</strong> (базисна за стадиране):</li><ul><li><strong>0 стадий </strong>- нормална торакална рентгенограма</li><li><strong>I стадий</strong> - двустранна хилусна лимфаденопатия (<strong>ДХЛ</strong>)</li><li><strong>II стадий</strong> - ДХЛ <strong>+</strong> белодробна инфилтрация</li><li><strong>III стадий</strong> - белодробна инфилтрация (без ДХЛ)</li><li><strong>IV стадий</strong> - <strong>белодробна фиброза</strong></li></ul><li><strong>HRCT</strong> (high-resolution computed tomography) - за оценка на вътрегръдните лимфни възли и разграничаване на активен алвеолит от фиброза.</li><li><strong>18 FDG PET</strong> - полезна за оценка на органната ангажираност и избор на орган за биопсия.</li><li><strong>MRI</strong> - за преценка за засягане на мозъка и сърцето.</li></ul><h3>2. Лабораторни изследвания</h3><ul><li><strong>Хиперкалциемия</strong> и <strong>хиперкалциурия</strong>.</li><li>Увеличени стойности на <strong>АСЕ</strong> (angiotensin-converting enzyme) - продуцира се от саркоидните грануломи.</li><li>Увеличени стойности на <strong>алкалната фосфатаза</strong> и други чернодробни ензими при засягане на хепара.</li></ul><h3>3. Функционално изследване на дишането</h3><ul><li><strong>Спирометрия</strong> и <strong>дифузия (DLCO)</strong> - рутинни за оценка и проследяване.</li><li>Най-често се установява изолирано <strong>намаление на DLCO</strong>.</li><li><strong>Рестриктивен вентилаторен дефект</strong> - при по-напреднали заболявания.</li><li>10-15% от болните имат <strong>обструктивен вентилаторен дефект</strong>.</li></ul><h3>4. Биопсия</h3><ul><li><strong>Белодробна тъкан</strong> и <strong>вътрегръдни лимфни възли</strong>:</li><ul><li>Бронхиална и трансбронхиална биопсия с фибробронхоскоп</li><li>VATS (видео-асистирана торакоскопия)</li><li>Отворена белодробна биопсия</li></ul><li>Биопсия на други засегнати органи (кожа, черен дроб, мускули, конюнктива, малки слюнчени жлези, слъзни жлези).</li><li><strong><em>Безполезно е да се биопсира еритема нодозум, тъй като лезията не е грануломатозна.</em></strong></li></ul><h3>5. Допълнителни изследвания</h3><ul><li><strong>ЕКГ и Holter мониториране</strong> при пациенти със сърцебиене.</li><li><strong>Офталмологична оценка</strong> при засягане на очите.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Диференциална Диагноза</h2><p>Диференциалната диагноза е широка. Най-важните заболявания са:</p><ul><li>Белодробен карцином</li><li>Лимфоми</li><li><strong>Туберкулоза</strong></li><li>Фунгеални инфекции</li><li>Вегенерова грануломатоза</li><li>Хистиоцитоза X</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Лечение</h2><ul><li><strong>Кортикостероиди</strong>:</li><ul><li><strong>Prednisolone</strong>&nbsp;дневно</li><li>След 1-3 месеца, ако има подобрение, дозата се редуцира и терапията продължава още 9-12 месеца</li></ul><li><strong>Имуносупресивни и цитотоксични агенти</strong>:</li><ul><li><strong>Metotrexate </strong>седмично</li><li><strong>Azathioprine </strong>дневно</li><li>Могат да направят организма по-уязвим за инфекции.</li></ul><li><strong>Противомаларийни средства</strong>:</li><ul><li><strong>Hydroxychloroquine </strong>дневно</li><li>Полезен при засягане на кожата, нервната система и увеличени серумни нива на калция.</li><li><strong><em>Изисква редовни офталмологични прегледи поради риск от увреда на очите.</em></strong></li></ul><li><strong>TNF-alpha инхибитори</strong>:</li><ul><li>Обикновено се използват за лечение на ревматоиден артрит.</li><li>Има данни, че <strong>Infliximab</strong> може да бъде полезен.</li></ul></ul><h4> Проследяване на Пациентите</h4><ul><li><strong>Белодробна функция</strong>: на всеки 6-12 месеца.</li><li><strong>Пулмография</strong>: на всеки 6-12 месеца.</li><li><strong>ЕКГ</strong>: веднъж годишно.</li><li><strong>Офталмологичен преглед</strong>: веднъж годишно.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Прогноза</h2><p>Функционални увреждания се наблюдават при 15-20% от пациентите. Заболяването често търпи <strong>спонтанно обратно развитие</strong>. Общата смъртност е <strong>под 5%</strong> за нелекуваните болни. Причините за смърт най-често са <strong>дихателна недостатъчност</strong> и <strong>дясна сърдечна недостатъчност</strong>.</p><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><br><br><hr style=\"text-align: center; border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">23. Функционално изследване на дишането - определяне на белодробни обеми и капацитети. Вентилаторни нарушения.</h1><p style=\"text-align: left\">Няма текст.</p><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">24. Кръвно-газов анализ – клинична интерпретация.</h1><h2>Дефиниция</h2><p>КГА е диагностичен метод за оценка на газовия обмен и киселинно-алкалното равновесие (КАР) чрез измерване на:</p><ul><li>парциалното налягане на кислорода (PaO2)</li><li>парциалното налягане на въглеродния диоксид (PaCO2)</li><li>концентрацията на бикарбонат (HCO3-)</li><li>pH на кръвта</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Вземане на проба</h2><ul><li>Първи избор: артериална пункция на a. radialis</li><li>Алтернатива: проба от ушна висулка след подготовка с ревулзивна паста</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Нормални референтни стойности (здрави индивиди, стайна среда, ниво на морето)</h2><table><tbody><tr><td><strong><span style=\"color: rgb(88, 129, 87)\">Параметър</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Норма</span></strong></td></tr><tr><td>PaO2</td><td>90–95 mmHg</td></tr><tr><td>PaCO2</td><td>36–44 mmHg</td></tr><tr><td>pH</td><td>7.36–7.44</td></tr><tr><td>HCO3-</td><td>22–26 mmol/L</td></tr></tbody></table><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Хипоксемия (↓ PaO2)</h2><p><strong>Определение:</strong>  </p><p>Хипоксемията представлява понижение на парциалното налягане на кислорода в артериалната кръв (PaO2).  </p><p>Може да доведе до хипоксия — намалено снабдяване на тъканите с кислород.</p><p><strong>Причини за хипоксемия</strong></p><p><strong>1. Намалено парциално налягане на вдишания кислород</strong></p><ul><li>Обструкция на дихателните пътища</li><li>Престой на голяма надморска височина (височинна болест)</li></ul><p><strong>2. Смутена алвеоло-капилярна дифузия</strong></p><ul><li>Емфизем</li><li>Белодробна фиброза</li></ul><p><strong>3. Хиповентилация</strong></p><ul><li>Потискане на дихателния център (ЦНС)</li><li>Невро-мускулни заболявания</li><li>Пневмоторакс</li><li>Плеврален излив</li></ul><p><strong>4. Артерио-венозен шънт (смесване на венозна и артериална кръв)</strong></p><ul><li>Атектелаза</li><li>Белодробен инфаркт</li><li>Пневмония</li><li>Вродени сърдечни пороци</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Влияние на компонентите върху pH</h2><ul><li><strong>Респираторна (PaCO2)</strong> – бързо променящ се компонент:</li><ul><li>Хиперкапния (повишен PaCO2) → респираторна ацидоза (↓ pH)</li><li>Хипокапния (понижен PaCO2) → респираторна алкалоза (↑ pH)</li></ul><li><strong>Метаболитна (HCO3-)</strong> – регулира се чрез бъбреците; задържане или загуба на HCO3- води до метаболитна алкалоза или ацидоза</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Основни респираторно-метаболитни състояния</h2><table><tbody><tr><td><strong><span style=\"color: rgb(88, 129, 87)\">Състояние</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">pH</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">PaCO2</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">HCO3-</span></strong></td></tr><tr><td>Респираторна ацидоза</td><td>↓</td><td>↑</td><td>↔ (↑ при хронична)</td></tr><tr><td>Респираторна алкалоза</td><td>↑</td><td>↓</td><td>↔ (↓ при хронична)</td></tr><tr><td>Метаболитна ацидоза</td><td>↓</td><td>↓ компенсаторно</td><td>↓</td></tr><tr><td>Метаболитна алкалоза</td><td>↑</td><td>↑ компенсаторно</td><td>↑</td></tr></tbody></table><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Причини / клинични ситуации</h2><p><strong>Респираторна ацидозa (↑PaCO2) -  при хронични респираторни заболявания с хиповентилация се стига до развитието на хиперкапния с респираторна ацидоза:</strong></p><ul><li>ХОББ</li><li>Заболявания на гръдната стена и белия дроб</li><li>Заболявания на ЦНС</li></ul><p><strong>Респираторна алкалоза (↓ PaCO2) - при състояния с хипервентилация се стига до развитието на хипокапния с респираторна алкалоза:</strong></p><ul><li>Хипервентилация (психогенна, болка, хипоксемия)</li><li>Бронхиална астма</li><li>Кардиална астма</li><li>Заболявания на ЦНС</li><li>Лечение с хормони - катехоламини, прогестерон, хипертиеродизъм</li><li>Интоксиакция със салицилати</li><li>Артериална хипоксия</li><li>Чернодробни заболявания</li><li>Фебрилитет</li></ul><p><strong>Метаболитна ацидоза (↓ HCO3-):</strong></p><ul><li>Кетоацидоза</li><li>Лактатна ацидоза</li><li>Остра и хронична бъбречна недостатъчност</li><li>Интоксикации (метанол, етилен гликол, салицилати)</li><li>Диарии, чревни фистули</li><li>Гладуване</li></ul><p><strong>Метаболитна алкалоза (↑ HCO3-):</strong></p><ul><li>Загуба на стомашни сокове (повръщане, дренажи)</li><li>Лечение с диуретици</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Смесени и комплексни нарушения (често в клиниката)</h2><p>Смесените нарушения могат да дават нормален pH, но с отклонения в PaCO2 и HCO3-.</p><p>Смесените форми са <strong>често срещани в клиничната практика</strong> и изискват внимателен анализ на всички показатели (pH, PaCO2, HCO3-, PaO2).</p><h4>Основни видове и примери</h4><table><tbody><tr><td><strong><span style=\"color: rgb(88, 129, 87)\">Нарушение</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Характеристика</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Примери (клинични ситуации)</span></strong></td></tr><tr><td><strong>Респираторна ацидоза +<br>метаболитна ацидоза</strong></td><td>↓ pH<br>↑ PaCO2<br>↓ HCO3-</td><td>Сърдечен арест<br>Мултиорганна недостатъчност<br>Интоксикации</td></tr><tr><td><strong>Респираторна aкалоза + <br>метаболитна алкалоза</strong></td><td>↑ pH<br>↓  PaCO2<br>↑ HCO3-</td><td>Цироза с диуретици <br>Бременност с повръщане <br>Хипервентилация при ХОББ</td></tr><tr><td><strong>Респираторна ацидоза +<br>метаболитна алкалоза</strong></td><td>pH в нормални стойности<br>↑ PaCO2<br>↑ HCO3-</td><td>ХОББ с диуретици<br>Повръщане<br>Тежка хипокалиемия</td></tr><tr><td><strong>Респираторна алкалоза +<br>метаболитна ацидоза</strong></td><td>pH в нормални стойности<br>↓ PaCO2<br>↓ HCO3-</td><td>Сепсис<br>Чернодробна недостатъчност<br>Интоксикация със салицилати<br>Бъбречна недостатъчност с ХСН или пневмония</td></tr><tr><td><strong>Метаболитна ацидоза +<br>метаболитна алкалоза</strong></td><td>pH в нормални стойности<br>HCO3- в нормални стойности</td><td>Уремия или повръщане кетоацидоза с повръщане <br>Диуретици</td></tr></tbody></table><h4>Практически бележки</h4><ul><li>Анализирай PaO2, PaCO2, HCO3- и pH заедно.</li><li>Оцени дали промяната е остра или хронична (компенсация).</li><li>При съмнение за смесени нарушения – търси клиничната причина.</li></ul><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><br><br><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">25. Белодробен абсцес</h1><h2>Дефиниция</h2><p>Белодробният абсцес се дефинира като некроза на белодробната тъкан, причинена от инфекция и формиране на кухина, съдържаща некротични тъкани и течности.</p><ul><li>Формирането на многобройни, малки (&lt;2 см) абсцеси се асоциира с <strong>некротизираща пневмония</strong> или <strong>белодробна гангрена</strong>.</li><li>Кухина се образува, когато паренхимната некроза доведе до комуникация с бронх, последващо нахлуване на въздух и експекторация на некротичния материал. Образува се <strong>хидро-аерично ниво</strong>.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Класификация</h2><p><strong>По Давност:</strong></p><ol><li>Остър - абсцес с давност 4-6 седмици</li><li>Хроничен - абсцес с давност над 6 седмици</li></ol><p><strong>По Произход:</strong></p><ol><li>Първичен - развива се при неувредени бели дробове (резултат на аспирация или пневмония).</li><li>Вторичен - при пациенти с подлежащо белодробно заболяване (бронхиектазии, кистична фиброза, нарушен имунен статус).</li></ol><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Епидемиология</h2><ul><li>Днес е рядък в развитите страни.</li><li><strong>Рискови групи</strong>:</li><ul><li>Хора с напреднала възраст.</li><li>С подтиснат имунитет (захарен диабет, неоплазми, кортикостероидно, имуносупресивно и биологично лечение, СПИН, предхождащо антимикробно лечение, оперативни интервенции).</li><li>С аспирация при нарушено съзнание (припадъци, мозъчно съдови заболявания, анестезирани с обща наркоза, нарушен гълтателен рефлекс, алкохолици).</li></ul></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Етиология</h2><ul><li><strong>Анаероби:&nbsp;</strong>Peptostreptococcus, Bacteroides, Fusobacterium и microaerophilic streptococci.</li><li><strong>Аеробни Бактерии:</strong>&nbsp;Staphylococcus aureus, Streptococcus pyogenes, Streptococcus pneumoniae (рядко), Klebsiella pneumoniae, Pseudomonas spp, Proteus spp. Haemophilus influenzae, Actinomyces, Nocardia, и Грам (-) негативни бацили.</li><li><strong>Небактериални и Атипични Патогени </strong>(При Имунокомпрометирани Болни):</li><ul><li><strong>Паразити</strong>: Paragonimus и Entamoeba.</li><li><strong>Гъби</strong>: Aspergillus, Cryptococcus, Histoplasma, Blastomyces и Coccidioides.</li><li>Mycobacterium.</li></ul></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Патогенеза и Рискови Фактори</h2><ul><li><strong>Аспирация на орофарингеално съдържимо</strong>: Най-висок риск при пациенти с нарушения в съзнанието (алкохол, антидепресанти, обща анестезия или енцефалопатия), инсулт, епилепсия, дисфагия, заболявания на периодонта.</li><li>Прогресия на пневмонията до паренхимна некроза.</li><li>Инфекциозно усложнение на съществуваща отпреди була или киста.</li><li><strong>Бронхиална обструкция</strong> (в резултат на карцином или чуждо тяло) причинява обструктивен пневмонит, който може да доведе до абсцес.</li><li>Септична емболизация (при интравенозни наркомани с ендокардит, предизвикан от Staphylococcus aureus).</li><li>Болни с <strong>диабет</strong> са с повишен риск.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Патоанатомия</h2><p>Абсцесът започва като малка зона на некроза сред уплътнен пневмоничен участък. При достигане до бронх некротичната тъкан се изхрачва, формира се кухина с ниво на течност. Може да се развие фиброза, ограничаваща некрозата.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Клинична Картина</h2><p>Началото е <strong>постепенно</strong> (по-остро, ако се развива след пневмония).</p><ul><li><strong>Общи/Системни симптоми</strong>: втрисане, фебрилитет, изпотявания, неспецифични белези на хронична инфекция (анемия, загуба на тегло, общо неразположение).</li><li><strong>Респираторни симптоми</strong>: кашлица с <strong>обилна експекторация</strong>, която е зловонна и гнойна, задух, плеврална болка.</li><ul><li>Вомик = внезапно изкашляне на голямо количество зловонна гной при пробив на белодробен абсцес в бронх, последвано от временно подобрение на състоянието.</li></ul></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Физикално Изследване</h2><p>Находката е вариабилна (зависи от големината, разположението, връзката с бронх, наличието на емпием/пневмоторакс).</p><ul><li><strong>Общи признаци</strong>: фебрилитет, тахипнея, тахикардия, дехидратация, <strong>барабанни пръсти</strong> (при хронично протичане).</li><li><strong>Локални белези</strong>: локално притъпление, отслабено дишане, бронхиално дишане, амфорично дишане (рядко), разнокалибрени влажни хрипове.</li><li><strong>Други</strong>: клинични белези за изменения на периодонта и инфекциозен ендокардит.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Диагноза</h2><h4>1. Образни Изследвания - <a href=\"https://radiopaedia.org/articles/lung-abscess?embed_domain=airvcc.com&amp;lang=us\">Radiopedia</a></h4><ul><li><strong>Пулмография</strong>: <strong>консолидация, неправилна по форма кухина, хидро-аерично ниво</strong>.</li><ul><li>Абсцесът от аспирация обикновено е в <strong>задните сегменти на горните лобове</strong> или <strong>горните сегменти на долните лобове</strong> <strong>на десния лоб </strong>(поради по-стръмния стой на десния бронх).</li><li>Често е налице плеврален излив/емпием.</li></ul><li><strong>Компютърна Томография (КТ)</strong>:</li><ul><li>Определяне на точната позиция на абсцеса (важно за физиотерапия и хирургично лечение).</li><li>Диференциална диагноза с <strong>инкапсулиран плеврален емпием</strong> при периферно разположен абсцес в контакт с гръдната стена:</li><ul><li><strong>Абсцес</strong>: сянката сключва <strong>остър ъгъл</strong> с гръдната стена и <strong>не компремира</strong> белодробната тъкан.</li><li><strong>Емпием</strong>: оформя <strong>тъп ъгъл</strong> с гръдната стена и <strong>компремира</strong> белодробния паренхим.</li></ul><li>Уточнява наличието на обструктивно ендобронхиално заболяване (рак или чуждо тяло).</li></ul></ul><h4>2. Микробиологични Изследвания</h4><ul><li>Спутум, хемокултура, плеврална течност (при емпием).</li><li>Фибробронхоскопия с протектирана четка, бронхоалвеоларен лаваж.</li><li>Транстрахеален аспират, трансторакален белодробен аспират, открита белодробна биопсия.</li></ul><h4>3. Други данни:</h4><ul><li>Може да добавиш, че левкоцитозата е изразена с олевяване, ускорено СУЕ, ↑CRP.</li><li>При хроничен абсцес — може да има анемия и хипоалбуминемия.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Диференциална Диагноза</h2><ul><li>Разпаднал се карцином (първичен или вторичен)</li><li>Туберкулозна каверна</li><li>Инфектирана киста (ехинокок) или була</li><li>Белодробен инфаркт</li><li>Бронхиектазии</li><li>Васкулити (грануломатоза на Wegener)</li><li>Аспергилом, саркоидоза, микобактериози</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Усложнения (Общи)</h2><p><strong>E</strong><strong>мпием</strong>, кръвохрак <strong>(дори животозастрашаващ)</strong>, <strong>дисеминация на гнойния процес</strong>, <strong>сепсис</strong>, пневматоцеле, гноен медиастинит, бронхо-плеврална фистула, дихателна недостатъчност, амилоидоза.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Лечение</h2><h4>1. Антибиотично Лечение</h4><ul><li><strong>Инфекцията е обикновено смесена</strong> (аеробна и анаеробна), изискваща покритие и за продуциращи β-лактамази.</li><li><strong>Терапия от първа линия</strong>: <strong>β-лактам/β-лактамазен инхибитор</strong> (Amoxicillin/clavulanic acid; Ampicillin/sulbactam) или <strong>цефалоспорин </strong>(II/III поколение) + <strong>clyndamycin</strong>.</li><li><strong>Metronidazol</strong> като антианаеробен препарат, но <strong>не самостоятелно</strong>.</li><li>При хоспитализирани пациенти с аспирация, терапията трябва да покрие и <strong>S. aureus, Enterobacter и Pseudomonas</strong>.</li><li>Moxifloxacin.</li><li>При доказан микробиологичен причинител - съобразяване с чувствителността на патогена.</li><li><strong>Продължителност на лечението</strong>: <strong>4-6 седмици</strong>.</li></ul><h4>2. Дренаж</h4><ul><li>Постурален дренаж и физиотерапия.</li><li>Бронхоскопски дренаж (при комуникация с бронх).</li><li>Перкутанен дренаж (при периферно разположен абсцес).</li></ul><h4>3. Хирургично Лечение</h4><ul><li>Прибягва се след <strong>неуспех от стандартното лечение, проведено за поне 6 седмици</strong>.</li><li>Осъществява се <strong>лобектомия</strong> или <strong>пулмонектомия</strong>.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Прогноза</h2><ul><li>Над 90% от абсцесите се повлияват от адекватна медикаментозна терапия.</li><li><strong>Влошена прогноза</strong> при:</li><ul><li>Имунокомпрометирани пациенти (смъртност до 75%).</li><li>Наличие на подлежащо белодробно заболяване.</li><li>Напреднала възраст.</li><li>Голяма кухина (&gt; 6 см).</li><li>Инфекция със Staphylococcus aureus.</li></ul></ul><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><br><br><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">26. Бронхиектазна болест. Кистична фиброза</h1><h2>Определение</h2><p>Бронхиектазиите представляват <strong>необратимо абнормно разширение</strong> на един или повече бронхи. Те са краен стадий на патологични процеси, причиняващи деструкция на бронхиалната стена и прилежащите й тъкани. Заболяването се асоциира с <strong>хронична продукция на спутум</strong>, <strong>рекурентни белодробни инфекции</strong> и <strong>бронхиална обструкция</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Класификация</h2><ul><li><strong>Вродени бронхиектазии</strong>: Наблюдават се при деца, резултат от нарушено развитие на бронхиалното дърво.</li><li><strong>Придобити бронхиектазии</strong>: Откриват се при всички възрасти, резултат на инфекция.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Етиология</h2><p>Бронхиектазиите могат да се развият при:</p><ol><li><strong>Прекарани и не напълно излекувани инфекции</strong>:</li><ul><li><strong>Причинители</strong><strong>: </strong>Klebsiella species, S. aureus, M. pneumoniae, M. tuberculosis, морбили, пертусис, грип, херпес симплекс, някои аденовируси, M. avium<strong>.</strong></li><li><strong></strong>Различни бактерии се колонизират в дихателните пътища на различни етапи от развитието на бронхиектазната болест: S. aureus, H. influenzae, M. catarrhalis, Pseudomonas species.</li></ul><li><strong>Имунен дефицит</strong>: Първичен (хипогамаглобулинемия) или вторичен (СПИН).</li><li><strong>Кистична фиброза (муковисцидоза)</strong>:</li><ul><li>Автозомно рецесивно заболяване с мутация на CF гена, кодиращ CF трансмембранния регулаторен протеин, който служи като хлориден канал на секреторните епителни клетки на екзокринните жлези.</li><li>Абнормно се увеличава абсорбцията на натрий и течности и в лумена на жлезите се отделя <u>гъст</u> <u>мукозен секрет, причиняващ обструкция и възпаление</u>.</li><li>Протича с бронхиална хиперреактивност, кръвохрачене, пансинуит и назална полипоза и панкреасна недостатъчност (захарен диабет).</li><li>При възрастни основната патологична находка може да са само бронхиектазиите.</li></ul><li><strong>След обструкция</strong>:</li><ul><li>Наблюдава се при ендобронхиални тумори, стенотични участъци, чуждо тяло, външна компресия от увеличени лимфни възли.</li><li><strong>Особен тип - синдром на средния дял</strong>: Поради ъгъла на отделяне на средния бронх вдясно се нарушава дренажът, задържат се секрети и се създават условия за хронично възпаление.</li></ul><li><strong>Нарушения на мукоцилиарния клирънс</strong>:</li><ul><li><strong>Първична цилиарна дискинезия</strong>: Наследствени състояния с нарушена подвижност на цилиите на ресничестия респираторен епител и на сперматозоидите. Това уврежда мукоцилиарния клирънс, води до задръжка на секрети и рецидивиращи белодробни инфекции.</li><ul><li><strong>Клиничен вариант - синдром на Kartagener</strong>: situs viscerum inversus, назална полипоза/синузит и бронхиектазии.</li></ul><li><strong>Синдром на Young:</strong> Бронхиектазии, синузит, обструктивна азоспермия.</li></ul><li><strong>Алергична бронхопулмонална аспергилоза</strong>: Реакция на свръхчувствителност към Aspergillus species. Протича с бронхоспазъм, бронхиектазии и положителна кожна проба към Aspergillus антигена.</li><li><strong>Системни заболявания</strong>: Ревматоиден артрит, синдром на Sjogren, системен лупус еритематозус.</li><li><strong>Други синдроми</strong>: Улцерозен колит, болест на Crohn's.Хроничен синузит, синдрома на жълтите нокти, Marfan's syndrome.</li><li><strong>Тракционни бронхиектазии</strong>: Представляват патологично и необратимо разширение на бронхите и бронхиолите, което се дължи на външно „теглене“ (тракция) от страна на заобикалящата ги белодробна тъкан - вторичен процес, свързан с белодробната <strong>фиброза</strong>.</li></ol><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Патогенеза</h2><p>Необходима е <strong>първоначална увреда</strong> (обикновено инфекциозна) на дихателните пътища. Създава се <strong>порочен кръг на възпалението при хронична инфекция</strong>:</p><ul><li><strong>Първоначална увреда</strong> -&gt; <strong>Възпалителен процес</strong> (с инфилтрация от неутрофили → освобождаване на ензими (еластаза, протеази)) -&gt; <strong>Развитие на бронхиектазии</strong> -&gt; <strong>Застой на секрецията</strong> -&gt; <strong>Вторична бактериална инфекция</strong> -&gt; <strong>Поддържано хронично възпаление и допълнително увреждане</strong>.</li></ul><p>Хроничният възпалителен отговор включва образуване на свободни радикали и производство на <strong>неутрофилна еластаза</strong>, което допълнително допринася за възпалителния процес. Наблюдава се <strong>бронхиална неоваскуларизация</strong> на бронхиалните артерии (може да доведе до хемоптизи).</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Патоанатомия:</h2><p>Според класификацията на Reid, бронхиектазиите биват:</p><ul><li><strong>Цилиндрични</strong>: Минимална дилатация.</li><li><strong>Кистични (сакуларни)</strong>: Разязвявания, обилна неоваскуларизация, балоноподобни разширения и ниво на течност.</li><li><strong>Варикозни</strong>: Наподобяват разширени повърхностни вени.</li><li>Най-често засягат долните лобове, особено базалните сегменти.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Клинична Картина</h2><ul><li><strong>Хронична кашлица</strong> с характерни  <strong>гъсти слузно-гнойни храчки</strong> през продължителни периоди.</li><li>Периодични <strong>хемоптизи</strong> (кръвохрачене).</li><li><strong>Диспнея</strong>, плеврална болка, отпадналост, загуба на тегло.</li><li><strong>Анамнеза за рецидивиращи инфекции</strong> с лечение от АБ.</li><li>В единични случаи се установяват обилни кръвоизливи, завършващи с асфиксия и смърт.</li><li>Вариант <strong>\"сухи бронхиектазии\"</strong> - протича с епизодично кръвохрачене.</li><li>Клинични критерии за екзацербация: &gt; 72 часа усилена кашлица, промяна в храчките (обем, вискозитет, гнойност), задух, хемоптиза и/или общо неразположение/умора.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Физикално Изследване</h2><ul><li><strong>Белодробна находка</strong>: Неспецифична - сухи свиркащи и хъркащи хрипове, разнокалибрени влажни инспираторни и експираторни хрипове.</li><li><strong>Други</strong>: Цианоза, <strong>барабанни пръсти</strong>, назална полипоза, хроничен синузит, данни за хронично белодробно сърце.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Диагноза</h2><p>Въз основа на типичната анамнеза за епизоди на кашлица и гнойни храчки.</p><h3>Изследвания от Първа Линия</h3><ul><li><strong>Образни изследвания - <a href=\"https://radiopaedia.org/articles/bronchiectasis\">Radiopedia</a>:</strong></li><ul><li><strong>Пулмография</strong>:</li><ul><li>Чувствителност ~50%.</li><li>Находки: ивицести повлекла, линеарни сенки, излизащи от хилуса (\"трамвайни линии\"), кисти, ателектатични участъци, фиброзни изменения тип \"пчелна пита\", плеврални сраствания.</li><li>При инфекция се засягат долните дяловс, средният дял вдясно и лингула вляво.</li><li>При кистична фиброза, микобактериоза, хронична гъбична инфекция, алергична бронхопулмонална аспергилоза - горни дялове.</li></ul><li><strong>Високоразделителната Компютърна Томография</strong>:</li><ul><li>Установява <strong>дилатация на бронхите към периферията</strong>, удебеляване на бронхиалната стена, бронхите изглеждат по-големи от съпътстващите ги съдове (<a href=\"https://radiopaedia.org/articles/signet-ring-sign-bronchiectasis?embed_domain=wP9E1&amp;lang=us\">signet-ring sign</a>).</li><li>Ако диаметърът на бронхиалния лумен спрямо прилежащия съд е <strong>&gt; 1,5 пъти по-голям</strong>, диагнозата \"бронхиектазии\" е вероятна.</li></ul></ul><li><strong>Микробиологично изследване</strong> на храчка (за бактерии, гъби и микобактерии).</li><li><strong>Функционално изследване на дишането</strong>: Снижение на ФЕО1 и на ВК. При част от болните обструкцията е обратима.</li><li><strong>Имуноглобулини</strong> A, M, E, G.</li></ul><h3>Изследвания от Втора Линия</h3><ul><li><strong>Потен и ДНК тест -&nbsp;</strong>за кистична фиброза.</li><li><strong>Автоантитела</strong> (ANA, RhF, dsDNA) - при съмнение за заболяване на съединителната тъкан.</li><li><strong>Серология за Aspergillus</strong>.</li><li><strong>Електронно микроскопско изследване</strong> на сперматозоиди и респираторен епител - за първична цилиарна дискинезия.</li><li><strong>Бронхоскопия&nbsp;</strong>- при търсене на тумори, за изключване на чуждо тяло при наличие на съмнение за такова от компютъртомографското изследване, бронхоалвеоларен лаваж за микробиологична и цитологична диагностика.</li><li><strong>Ехокардиография&nbsp;</strong>- при съмнение за пулмонална хипертония.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Диференциална Диагноза</h2><p>Белодробна туберкулоза, ХОББ, пневмокониози, пневмония, саркоидоза и др.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Усложнения</h2><p>Инфекциозна екзацербация, хемоптиза с малък обем, <strong>хемоптое (може да е животозастрашаващо)</strong>, пневмоторакс, дихателна недостатъчност и амилоидоза.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Лечение</h2><h4>1. Общи Мероприятия</h4><ul><li><strong>Спиране на тютюнопушенето</strong>, лечение на основното заболяване.</li><li><strong>Предотвратяване на екзацербации</strong> чрез физиотерапия (постурален дренаж, перкусионен масаж, дихателна гимнастика), имунизации (противогрипна, пневмококова, хемофилусна ваксини), имуностимулация (Респивакс, Бронховаксом).</li><li><strong>Бронхиален тоалет</strong>: за изчистване на бронхите от гъстите секрети.</li><li><strong>Втечняване на секретите</strong>: Небулизация на физиологичен серум и муколитици (ацетилцистеин), адекватно оводняване.</li><li><strong>Бронходилататори</strong>: за повлияване на ограничението на въздушния поток.</li><li><strong>Имуноглобулин заместваща терапия</strong> (при пациенти с имуноглубулинове дефицит).</li></ul><h4>2. Антибиотично Лечение (При Екзацербации)</h4><ul><li>Пациентите с бронхиектазии продуцират плътна секреция в мястото на микробната колонизация - механична бариера при дифузията на медикаментите, затова се нуждаят от по-дълъг период на лечение (<strong>най-малко 2 седмици</strong>) в сравнение с останалите болни</li><li><strong>Инхалаторно</strong>: Гентамицин, Тобрамицин (особено при кистична фиброза).</li></ul><table><tbody><tr><td><strong><span style=\"color: rgb(88, 129, 87)\">Насоки за лечение (Европейско респираторно дружество)</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Перорално лечение</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Парентерално лечение</span></strong></td></tr><tr><td><strong>Без риск за инфектиране с P. aeruginosa</strong></td><td>co-amoxiclav, levofloxacin, moxifloxacin</td><td>amoxicillin-clavulanat, cefotaxim, moxifloxacin, levofloxacin</td></tr><tr><td><strong>С риск за инфектиране с P. aeruginosa</strong></td><td>Ципрофлоксацин</td><td>ciprofloxacin/levofloxacin + антипсевдомонасен бета-лактам* или аминоглюкозид</td></tr></tbody></table><p><em></em>Анти-псевдомонасни бета-лактами: ceftazidim, cefepim, карбапенеми, piperacillin-tazobactam.* </p><h4>3. Белодробна Рехабилитация</h4><ul><li>Включва тренировка, самоуправление, психосоциална и хранителна интервенция.</li></ul><h4>4. Хирургично Лечение</h4><ul><li><strong>Резекция</strong>: Когато консервативният контрол на симптомите е неуспешен.</li><li><strong>Емболизация на бронхиалната артерия</strong>: При масивни кръвоизливи.</li></ul><h4>5. Трансплантация на Бял Дроб</h4><ul><li>Обсъжда се при кистична фиброза.</li></ul><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">27. Белодробна хипертония</h1><p>Няма текст.</p><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><br><br><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">28. Хронично белодробно сърце</h1><p>Няма текст.</p><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><br><br><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">29. Диагностичен алгоритъм при плеврални изливи</h1><h2>Дефиниция</h2><p>Плевралните изливи са резултат от събиране на <strong>абнормно количество (&gt; 10-20 ml) течност в плевралното пространство</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Етиология</h2><p>Най-чести причини:</p><ul><li><strong>Застойна сърдечна недостатъчност</strong> (най-често)</li><li><strong>Пневмонии</strong></li><li><strong>Неопластични заболявания</strong></li><ul><li><strong>Мезотелиом - </strong>единственото първично заболяване на плеврата</li></ul><li>Белодробен тромбоемболизъм</li><li>Вирусни заболявания</li><li>Цироза с асцит</li><li>Гастро-интестинални заболявания</li><li>Туберкулоза, колагенози, медикаменти.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Патогенеза</h2><p>Нормалното количество плеврална течност е около <strong>1 ml</strong>, определено от баланса между:</p><ol><li>Хидростатичното и онкотичното налягане в съдовете на висцералната и париеталната плеври.</li><li>Лимфния дренаж.</li></ol><p>Плевралните изливи са резултат от нарушения в този баланс:</p><ul><li><strong>Възпаление (Ексудат)</strong>: Пневмония, туберкулоза, карцином, системни заболявания (ревматоиден артрит, СЛЕ) причиняват възпаление на белите дробове и <strong>плеврата</strong>.</li><li><strong>Повишено венозно налягане (Трансудат)</strong>: Сърдечната недостатъчност повишава белодробното и системното венозно налягане и причинява повишена филтрация на течност в плевралното пространство.</li><li><strong>Намалено онкотично налягане (Трансудат)</strong>: Предизвиква преминаване на течност от съдовете в плевралното пространство (Чернодробна цироза, нефротичен синдром).</li></ul><p><img src=\"https://files.coursebook.lol/Coursebook%20Assets/2026-05-05/coursebook-assets/assets/%D0%9F%D0%BB%D0%B5%D0%B2%D1%80%D0%B0%D0%BB%D0%B5%D0%BD%D0%98%D0%B7%D0%BB%D0%B8%D0%B2.png\" alt=\"ПлевраленИзлив.png\" data-original-src=\"https://files.coursebook.lol/Coursebook%20Assets/2026-05-05/coursebook-assets/assets/%D0%9F%D0%BB%D0%B5%D0%B2%D1%80%D0%B0%D0%BB%D0%B5%D0%BD%D0%98%D0%B7%D0%BB%D0%B8%D0%B2.png\" data-width=\"50\" style=\"width: 828.5px; max-width: 100%; height: auto; display: block\" data-broken-cleanup-bound=\"1\"></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Видове плеврален излив:</h2><ul><li><strong>Хидроторакс</strong> - трансудат, обикновено поради сърдечна или чернодробна недостатъчност.</li><li><strong>Пиоторакс</strong> - емпием, натрупване на гной в плевралната кухина, най-често вследствие на бактериална инфекция.</li><li><strong>Хемоторакс</strong> - кръв, резултат от травма, оперативни интервенции или тумор.</li><li><strong>Хилоторакс</strong> - лимфа, често поради нарушена лимфна дренажна система (например травма на хилус или туморна обструкция).</li></ul><h2>Клинична Картина</h2><ul><li>Може да протече <strong>асимптомно</strong>.</li><li><strong>Задух </strong>-&nbsp;в резултат на разширяване на плевралното пространство с последователен натиск върху диафрагмата и гръдната стена по време на дишане.</li><li><strong>Суха кашлица </strong>-&nbsp;развива се вторично на базата на нарушен мукоцилиарен клирънс поради компресия или поради основното заболяване.</li><li><strong>Гръдна болка</strong>&nbsp;-&nbsp;в гърдите в резултат на дразнене на сетивната инервация от париеталната плевра с характеристика на пробождаща болка, често зависима от дишането.</li><ul><li>Болката може да отмине при нарастване на излива, тъй като отдалечава двата листа на плеврата и не позволява триене - болка.</li></ul><li>Симптоми на интоксикация.</li><li>Наблюдават се и симптоми на подлежащото заболяване.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Обективно Изследване</h2><ul><li>Обективни признаци се установяват при излив <strong>&gt; 300 ml</strong>.</li><li><strong>Намалена респираторна подвижност </strong>на засегнатата половина.</li><li><strong>Отслабен гласов фремитус </strong>върху зоната на излива.</li><li><strong>Притъпен (скъсен) перкуторен тон</strong>.</li><li><strong>Отслабено или липсващо везикуларно дишане </strong>върху нивото на течността.</li><li><strong>Плеврално триене </strong>-&nbsp;чува се в двете фази на дишането и се усилва при натиск върху стетоскопа; напомня стъпване върху твърд, замръзнал сняг.</li><li>Контралатерално изместване на медиастинума при изливи <strong>&gt; </strong><strong>1000 ml</strong>.</li><li>Над нивото на течността – <strong>по линията на Damoiseau</strong> – се чува <strong>бронхиално дишане</strong>, често с влажни хрипове – <strong>феномен на Шкодизъм</strong>.</li><li>Признаци, насочващи към подлежащата причина:</li><ul><li>периферни отоци при перикардити;</li><li>подути шийни вени при застойна сърдечна недостатъчност;</li><li>кожни промени и асцит при чернодробни заболявания;</li><li>увеличени лимфни възли при неоплазии.</li></ul></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Диференциална диагноза:</h2><ul><li>Само с ателектаза, защото физикалните находки са еднакви.</li><li>Различават се на рентген.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Изследвания</h2><p><strong>1. Образни Изследвания - <a href=\"https://radiopaedia.org/articles/pleural-effusion?lang=us\">Radiopedia</a>, <a href=\"https://radiopaedia.org/articles/pleural-effusion-summary?lang=us\">Radiopedia Summary</a></strong></p><ul><li><strong>Локализация</strong>:</li><ul><li><strong>Свободни</strong>&nbsp;- в голямата плеврална кухина)</li><li><strong>Инкапсулирани</strong>&nbsp;- костален, медиастинален, диафрагмален, интерлобарен.</li></ul><li><strong>Пулмография (Рентгенография)</strong>:</li><ul><li>Диагностицира изливи над 200 ml (фасова графия) или над 50 ml (профилна графия).</li><li><strong>Класическа картина</strong>: течността първо се събира в <strong>базалните зони</strong> и дава <strong>хомогенно засенчване</strong> на <strong>латералния косто-диафрагмален синус</strong> с <strong>конкавна горна граница (линия на Damoiseau/Meniscus sign</strong>).</li><li>При масивен плеврален излив <strong>може да се измести медиастинума</strong>.</li><li>При <strong>легнало положение</strong>: <strong>лентовидна сянка</strong>, поради разливане на излива. Ако дебелината на тази сянка е над 1 см, е налице излив &gt; 200 ml, това е показание за пункция. Неразливането на излива в легнало положение показва, че той е инкапсулиран.</li><li><strong>Двустранен излив с кардиомегалия</strong> най-често е <strong>застойна сърдечна недостатъчност</strong>.</li><li>Плеврален излив и калцификати - азбестова експозиция.</li><li>Масивни са изливите при неопластични заболявания, туберкулоза и др.</li><ul><li><strong>Диференциация от ателектаза</strong> – при ателектаза сянката е с обемна загуба и медиастинално изместване към страната на колабиралия бял дроб; при излив – сянката е за сметка на плевралното пространство и медиастинумът се изтласква в обратната посока.</li></ul></ul><li><strong>Торакална ултрасонография (Ехография)</strong>: Чувствителна при излив <strong>над 100 ml</strong>. Полезна за маркиране на мястото за пункция, особено при инкапсулирани изливи.</li><li><strong>Компютърна томография (КТ)</strong>: Може да диагностицира изливи около <strong>10 ml</strong>. <u>Установява специфични за неоплазмите \"задебелявания\" по плеврата</u>. Могат да се открият и екстраплеврални заболявания (лимфаденопатия, паренхимни промени или такива в съдовото русло), които насочват към рак, туберкулоза или БТЕ.</li></ul><p><strong>2. Торакоцентеза (Плеврална Пункция)</strong></p><p>Торакоцентеза е процедурата, чрез която се вземa плеврална течност с диагностична или терапевтична цел.</p><p>След това взетата течност се изследва, за да се определи: </p><p><strong>А. Макроскопски вид</strong></p><ul><li><strong>Гноен:&nbsp;</strong>емпием.</li><li><strong>Млекоподобен, опалесциращ</strong>: хилоторакс (обикновено при запушване на лимфните съдове от неоплазми или увреждане на торакалния дуктус от травма или други хирургични процедури).</li><li><strong>Хеморагичен:&nbsp;</strong>стойности на хематокрит на излива <strong>&gt; 50%</strong> от хематокрита в периферната кръв означава хемоторакс и е показание за поставяне на дрен.</li></ul><p><strong>Б. Биохимична Характеристика (Критерии на Light)</strong></p><ul><li>Ексудат е налице, ако е изпълнено <strong>поне едно</strong> от следните условия:</li><ul><li>Плеврален/серумен белтък &gt;<em></em> 0.5</li></ul></ul><ul><li>Плеврална/серумна LDH &gt; <em></em>0.6</li></ul><ul><li>Плевралната LDH е <strong>&gt; две трети от горния лимит на нормата</strong> на серумната LDH</li></ul><ul><li><strong>Трансудати се наблюдават при</strong>: застойна сърдечна недостатъчност (най-често), цироза с хидроторакс, нефротичен синдром, хипопротеинемия.</li><li><strong>Ексудати се наблюдават при</strong>: неоплазии, пневмония, туберкулоза, гъбичкови инфекции,  перикардни заболявания, белодробен емболизъм, панкреатити, колагенози (ревматоиден артрит, лупус), азбезстоза, лекарствено-индуцирани, хилоторакс, остър респираторен дистрес синдром.</li></ul><p><strong>В. Допълнителни лабораторни изследвания на плевралната течност</strong></p><ul><li><strong>Глюкоза</strong>: Ниски стойности <strong>&lt; 60 mg/dl</strong> насочват към <strong>усложнен парапневмоничен</strong> или <strong>неопластичен излив</strong>. Други възможни причина са хемоторакс, туберкулоза, ревматоиден плеврит.</li><li><strong>pH</strong>: Стойността на рН корелира с нивото на захарта в излива. Ниски стойности при парапневмоничен и неопластичен излив. <strong>pH &lt; 7.2</strong> при парапневмоничен излив е <strong>показание за дренаж</strong>.</li><li><strong>Аденозиндезаминаза (ADA)</strong>: Стойности <strong>&gt; 40 IU/l</strong> поддържат диагнозата <strong>туберкулоза</strong>.</li><li><strong>Интерферон-гама тестове</strong>: Положителните IGRA тестове, заедно с високите стойности на Аденозиндезаминаза (ADA), силно подкрепят диагнозата на <strong>туберкулозен плеврит</strong>.</li><li><strong>NT-proBNP</strong>: Стойности <strong>&gt; 4000 ng/L</strong> насочват към излив в резултат на <strong>застойна сърдечна недостатъчност</strong>.</li><li><strong>Амилаза</strong>: Увеличени стойности при заболявания на панкреаса и руптура на хранопровода.</li><li><strong>Триглицериди и холестерол</strong>: Изследват се при <strong>хилоторакс</strong>.</li><li><strong>Туморни маркери (CEA, Leu-1)</strong>: Увеличени стойности при <strong>неопластични изливи</strong>.</li><li><strong>Клетъчна цитология на плеврални изливи</strong>:</li><ul><li><strong>Лимфоцитарни (&gt; 85% лимфоцити)</strong>: насочва към <strong>хроничен процес</strong>, предполагат <strong>туберкулоза</strong>, лимфом, саркоидоза, хроничен ревматоиден артрит, хилоторакс и синдрома на жълтите нокти.</li><li><strong>Еозинофилни клетки</strong>: паразитни заболявания, гъбичкови инфекции, бенигнена азбестоза, медикаменти.</li><li><strong>Туморни клетки</strong>: диагностична стойност 60-90% при неоплазми - най-често <strong>метастатичен карцином </strong>(на белия дроб, гърдата, яйчниците) или <strong>мезотелиом.</strong></li><li><strong>Мезотелни клетки</strong>: белодробен тромбемболизъм. Наличие на мезотелни клетки &gt; 5% правят диагнозата туберкулоза малко вероятна.</li></ul><li><strong>Бактериологично изследване</strong>: За патогенна флора, туберкулоза, патогенни гъби.</li></ul><p><strong>3. Инвазивни методи за изследване на плеврата</strong></p><p>Осъществяват се при подозрение за неоплазма или туберкулоза:</p><ul><li>Сляпа перкутанна плеврална биопсия</li><li>Перкутанна плеврална биопсия под образен контрол</li><li><strong>Видеоасистирана торакоскопия (VATS)</strong> - позволява оглед и целенасочено взимане на материал.</li><li>Открита плеврална биопсия - прилага се при диагностичен неуспех от предходните интерванции.</li><li>Бронхоскопия - при пациенти с хемоптиза или засягане на белодробния паренхим.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Лечение</h2><p><strong>Нехирургично Лечение</strong></p><ul><li><strong>Трансудати</strong>: лечение на подлежащото заболяване (напр. диуретици при СН).</li><li><strong>Ексудати</strong>: третират се в зависимост от етиологията (антибиотици при пневмония, химиотерапия при неоплазми).</li><li><strong>Терапевтична Торакоцентеза</strong>:</li><ul><li><strong>Цел: </strong>предотвратяване на възпаление и фиброза при парапневмонични изливи и/или евакуация на голям излив за намаляване на диспнеята.</li><li><strong>Ограничение</strong>: <u>евакуираното количество не трябва да надхвърля <strong>1500 ml</strong></u>.</li></ul></ul><p><strong>Хирургично Лечение</strong></p><ul><li><strong>Поставяне на дрен</strong>: при големи, инкапсулирани изливи или при <strong>емпием</strong>.</li><li><strong>Плевродеза</strong>:</li><ul><li>Съзнателно предизвикване на <strong>срастване между висцералната и париеталната плевра</strong>, за да се <strong>предотврати повторно натрупване на течност</strong>.</li><li><strong>Показан е при рецидивиращи малигнени изливи</strong>, особено при карцином на белия дроб, гърда или яйчник.</li><li>Извършва се като в плевралната кухина се въвежда склерозиращ агент → локално възпаление → срастване.</li><li><strong>Използвани агенти:</strong></li><ul><li><strong>Талк</strong> (най-ефективен)</li><li>Доксициклин, блеомицин, йодни препарати<em></em></li></ul><li><strong>Целта е палиативна</strong> – <strong>намаляване на диспнеята и нуждата от повторни пункции</strong>, съкращава болничния престой и подобрява качеството на живот.</li></ul><li><strong>Декортикация</strong>:</li><ul><li><strong>Хирургично отстраняване на фиброзни, нееластични плеврални плаки</strong> (“кора”), които ограничават разширението на белия дроб.</li><li>Най-често при хроничен емпием или <strong>организиран фиброзен излив</strong>.</li></ul><li><strong>Поставяне на шънт</strong> - имплант, който позволява <strong>преминаване на течност от плевралната кухина към перитонеалната</strong>.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Специфични видове изливи</h2><h4><strong>1. Парапневмонични изливи и емпием</strong></h4><p>Наблюдават се до 40% при пациенти с пневмония.</p><p><strong>Еволюция (Стадии)</strong>:</p><ol><li><strong>Ексудативен стадий: </strong>бистра, стерилна течност, нормално pH, глюкоза, LDH, често се резорбира с антибиотично лечение&nbsp;и не се налага дренаж.</li><li><strong>Фибринопурулентен стадий: </strong>отлагане на фибрин и се наблюдава септиране (инкапсулиран излив). Плевралната течност е инфектирана, но още не е гнойна, изглежда бистра или мътна, pH &lt; 7.2, глюкоза &lt; 2.2 mmol/l, LDH &gt; 1000 IU/l. Посявката по Gram може да бъде положителна. <strong>Обикновено е необходим дренаж</strong>.</li><li><strong>Емпием</strong>: наличие на <strong>гной</strong> в плевралното пространство. Може да е свободен или инкапсулиран. <strong>Задължително изисква дренаж</strong>. Развитие на фибробласти води до развитието на масивни плеврални сраствания (<strong>стадий на организация</strong>). Лечението в този стадий е трудно и често се налага осъществяването на хирургическа декортикация.</li></ol><h4>2. Плеврални изливи при неопластични заболявания (малигнени)</h4><ul><li><strong>Етиология</strong>: най-често метастатични (белодробен карцином, рак на гърдата, тумори на яйчника, левкемии и лимфоми).</li><li><strong>Симптоми</strong>: задух, гръдна болка, кашлица, загуба на тегло и анорексия. Малка част от пациентите са асимптоматични.</li><li><strong>Характеристики</strong>: едностранни или двустранни, често <strong>големи по обем</strong>.</li><li><strong>Диагноза</strong>: цитологично изследване на плевралната течност, КТ, биопсия на плеврата, туморни маркери.</li><li><strong>Прогноза</strong>: лоша (средно преживяване 3-12 мес. след поставяне на диагноза).</li><li><strong>Лечение</strong>: <strong>палиативно</strong> (евакуация на течността,облекчаване на задуха на пациента, плевродеза).</li></ul><h4>3. Плеврални изливи при туберкулоза</h4><ul><li><strong>Патогенеза</strong>: в резултат на обща токсоалергична реакция, перифокална реакция около туберкулозни изменения или директно ангажиране на плеврата.</li><li><strong>Симптоми</strong>: фебрилитет, изпотяване, загуба на тегло, <strong>гръдна болка</strong>.</li><li><strong>Характеристики</strong>: малки и средни по обем, но може и масивни.</li><li><strong>Излив</strong>: <strong>ексудат</strong>, предимно <strong>лимфоцитарен</strong>, с <strong>ниски pH и глюкоза,</strong> <strong>редки мезотелни клетки</strong>.</li><li><strong>Диагностика</strong>: кожни тестове (проба на Mantoux), ADA&gt; 40 IU/l, IGRA тестове (QuantiFERON), PCR за DNA на M. Tuberculosis,&nbsp;посявка на плеврална течност върху хранителни среди, биопсия на плеврата.</li><li><strong>Лечение</strong>: идентично с това на белодробната туберкулоза.&nbsp;Често се налага осъществяването на дренаж.</li><li>Чести усложнения са <strong>плеврални сраствания и петрификати по плеврата</strong>.</li></ul><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><br><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">30. Белодробни кръвоизливи – етиология, диференциална диагноза и терапевтично поведение</h1><p>Няма текст.</p><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><br><br><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">31. Болести на медиастинума. Медиастинален синдром</h1><p>Няма текст.</p><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><br><br><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">32. Дифузни интерстициални фибрози</h1><h2>Дефиниция</h2><p><strong>„Дифузна интерстициална фиброза“</strong> не е самостоятелна нозологична единица, а <em>група заболявания</em>, при които доминират промени в интерстициума на белите дробове.   </p><p>Алвеоларните пространства се засягат вторично от клетки, произхождащи от интерстициума.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Етиология</h2><p>Дифузната интерстициална фиброза може да се развие при грануломатозни процеси, но и при негрануломатозни увреждания на интерстициума.  </p><p>При част от заболяванията процесът е локализиран само в белия дроб, а при други промените са част от общо заболяване.</p><p>Заболяванията се класифицират в две групи:</p><p><strong>1. Заболявания с неизвестна етиология</strong></p><ul><li>Идиопатична белодробна фиброза</li><li>Колагено-васкуларни болести:</li><ul><li>Ревматоиден артрит</li><li>Системен лупус еритематозус</li><li>Склеродермия и др.</li></ul><li>Хемосидероза</li><li>Саркоидоза</li><li>Амилоидоза и др.</li></ul><p><strong>2. Заболявания с известна етиология</strong></p><ul><li>Инхалиране на газове, пари, аерозоли</li><li><strong>Увреди от лекарства</strong>, отрови, радиация</li><li>Хронични сърдечни заболявания – лявостранна недостатъчност, ляво-десен шънт</li><li>Хронични бъбречни заболявания с уремия и др.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Хистологична картина</h2><p>Характеризира се с:</p><ul><li>Алвеолит</li><li>Нарушение на алвеоларните структури</li><li>Интерстициална фиброза</li></ul><p>В крайния стадий алвеоларните структури са заместени от кистозни образувания, чиито стени представляват снопове съединителна тъкан.  </p><p>Получава се характерна картина на <strong>„пчелна пита“</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Клинична картина</h2><ul><li><strong>Начало:</strong> Постепенно, с бавно развитие на симптомите.</li><li><strong>Задух (диспнея):</strong> първоначално лек и при физическо усилие, впоследствие прогресиращ и инспираторен по характер.</li><li><strong>Кашлица:</strong> суха, мъчителна, по-често през нощта.</li><li><strong>Аускултация:</strong> отслабено везикуларно дишане, често с <strong>дребни влажни хрипове тип \"велкро\"</strong>.</li><li><strong>Промени по крайниците:</strong> нокти като часовниково стъкло и <strong>барабанни пръсти</strong>.</li><li><strong>Напреднал стадий:</strong> развитие на дихателна и сърдечно-съдова недостатъчност.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Рентгеново изследване - <a href=\"https://radiopaedia.org/articles/pulmonary-fibrosis?lang=us\">Radiopedia</a></h2><p>Най-характерни изменения:</p><ul><li><strong>Линии на Kerley</strong></li><ul><li>тип А (2–4 см) – централно разположени</li><li>тип B (1–2 см) – субплеврално разположени</li></ul><li><strong>Картината на „пчелна пита“</strong> – петнисто-ивичести сенки с множество окръглени просветления до 10 мм</li><li><strong>Tракционни бронхиектазии</strong></li></ul><p>Може да се наблюдават също:</p><ul><li>Картината на <strong>„матово стъкло“</strong></li><li><strong>Нодуларни</strong> и <strong>ретикуларни</strong> изменения</li></ul><p>Тези находки са <strong>неспецифични</strong> за заболяването.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Функционално изследване на дишането</h2><ul><li>Изразен <strong><u>рестриктивен синдром</u></strong></li><li><strong>Алвеоларна хипервентилация</strong></li><li><strong><u>Намален дифузионен капацитет</u></strong></li><li><strong>Увредена механика на дишането</strong></li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Протичане</h2><p>Протича <strong>вълнообразно</strong>, с прогресия в течение на <strong>месеци или години</strong>.  </p><p>Краен изход – <strong>дихателна и сърдечна недостатъчност</strong>, често летален.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Лечение</h2><ul><li><strong>Кортикостероидна терапия</strong> – начално 40–60 mg дневно, с постепенно намаляване до минимална поддържаща доза</li><li><strong>Имуносупресори</strong></li><li><strong>Антибиотици</strong> – само при наличие на възпалителен тласък</li><li><strong>Кислородолечение</strong></li><li><strong>Дихателна рехабилитация</strong></li><li><strong>Поддържане на правилен дневен режим и дозирано физическо натоварване.</strong></li></ul><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><strong><br><br></strong><hr style=\"text-align: center; font-weight: bold; border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">33. Нарушения на дишането по време на сън</h1><p>Няма текст.</p><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><br><br><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">34. Антибиотици и клиничното им приложение при респираторни инфекции.</h1><p>Няма текст.</p><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><br><br><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">35. Бронходилататори при лечение на бронхообструктивните заболявания.</h1><h2>Основни групи</h2><p>Съвременната фармакология подразделя <strong>БДТ</strong> на три основни групи:</p><ul><li>Селективни <strong>Бета-2 - адреномиметици</strong></li><li><strong>М - холинолитици</strong> (Антихолинергични медикаменти)</li><li><strong>Метилксантини</strong> (Теофилини)</li></ul><h2>Фармакологични ефекти на БДТ</h2><ul><li><strong>Релаксация на бронхиалната гладка мускулатура</strong> чрез повлияване нивото на <strong>цАМФ</strong>.</li><li><strong>Инхибиране освобождаването на медиатори</strong> от клетките на възпалението (предимно <strong>хистамин</strong>).</li><li>Инхибиране на <strong>холинергичната невротрансмисия</strong>.</li><li>Потискане на <strong>съдовия пермеабилитет</strong> и намаляване на <strong>отока на бронхиалната лигавица</strong>.</li><li>Модулиране на <strong>мукусната продукция</strong> и <strong>мукоцилиарния транспорт</strong> в дихателните пътища.</li></ul><h2>Показания за използване на БДТ</h2><p>Бронхоспазъм провокиран от:- Бронхиална астма</p><ul><li>ХОББ</li><li>Пневмония</li><li>Бронхит</li><li>Остри алергични реакции</li><li>Анафилаксия</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Бета-2 – Адреномиметици</h2><h3>Структура на Бета-2 адренергичния рецептор</h3><ul><li>Бета-2 адренергичният рецептор е обект на финна регулация.</li><li><strong>Тахифилаксия</strong>: Намалена способност за активиране при постоянно стимулиране, проявяваща се при злоупотреба със <strong>Бета-2-агонисти</strong><strong> с кратко действие</strong>.</li><li>Ефектът на <strong>тахифилаксия</strong> е обратим след прилагането на високи дози <strong>ИКС</strong> или постоянна употреба на <strong>ИКС</strong> в ниски или средни дози.</li></ul><h3>Клинични ефекти</h3><ul><li>Повлияват благоприятно всички патофизиологични механизми на <strong>бронхиалната обструкция</strong> – \"<strong>идеални</strong>\" бронходилататори с дозозависим ефект.</li><li><strong>Бронхопротективен ефект</strong> срещу различни неспецифични бронхоконстрикторни стимули:</li><ul><li>Хистамин</li><li>Метахолин</li><li>Физическо натоварване</li><li>Студен въздух</li></ul><li>Повлияват тъй наречения \"<strong>ранен отговор на алерген-индуцираната бронхообструкция</strong>\".</li></ul><h3>Селективни бета2-агонисти с кратко действие (SABA)</h3><ul><li><strong>Представители</strong>: Орципреналин, <strong>салбутамол</strong>, <strong>тербуталин</strong>, <strong>фенотерол</strong>, карбутерол.</li><li><strong>Начало на действие</strong>: Бърза начална бронходилатация – след 1-2 мин.</li><li><strong>Продължителност на ефекта</strong>: 4-6 часа (бронходилататорен и бронхопротективен).</li></ul><table><tbody><tr><td><strong><span style=\"color: rgb(88, 129, 87)\">Представител</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Търговско име</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Доза/Форма</span></strong></td></tr><tr><td><strong>Fenoterol</strong></td><td>Berotec</td><td>PMDI-100 µg</td></tr><tr><td><strong>Salbutamol</strong></td><td>Salbutamol, Ventolin, Buto-asma, Ecosal</td><td>PMDI-100 µg</td></tr><tr><td><strong>Terbutalin</strong></td><td>Bricanyl</td><td>Turbohaler/TBH/-100 µg</td></tr></tbody></table><h3>Селективни бета-2 агонисти с пролонгирано действие (LABA) </h3><ul><li><strong>Представители</strong>: <strong>Салметерол</strong>, <strong>формотерол</strong>, <strong>индакатерол</strong>.</li><li><strong>Начало на действие</strong>: Бавна начална бронходилатация – след 30 мин (за салметерола).</li><li><strong>Продължителност на ефекта</strong>:</li><ul><li>12-18 часа (за салметерол, формотерол).</li><li>До 24 часа (за индакатерол).</li></ul><li>Повлияват \"<strong>късната</strong>\" фаза на алерген – индуцираната бронхообструкция (до 34 час).</li></ul><table><tbody><tr><td><strong><span style=\"color: rgb(88, 129, 87)\">Представител</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Търговско име</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Доза/Форма</span></strong></td></tr><tr><td><strong>Salmeterol</strong></td><td>Serevent</td><td>pMDI-25 µg, Discus-50 µg</td></tr><tr><td><strong>Formoterol</strong></td><td>Oxis</td><td>Turbohaler /TBH/-12 µg</td></tr><tr><td><strong>Indacaterol</strong></td><td>Onbrez</td><td>Breezhaler–150 µg</td></tr></tbody></table><h3>Странични ефекти на Бета-2 агонисти</h3><ul><li><strong>Свързани с директната стимулация на Бета-1 и Бета-2 рецептори</strong>:</li><ul><li><strong>Тремор</strong></li><li><strong>Хипокалиемия</strong></li><li><strong>Кардио-васкуларни ефекти</strong></li></ul><li><strong>Парадоксален бронхоспазъм</strong>.</li><li>Развитие на <strong>толерантност</strong> и загуба на ефект.</li><li>Нарастване на <strong>бронхиалната реактивност</strong>.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Антихолинергични медикаменти</h2><h3>Типове мускаринови рецептори</h3><ul><li><strong>M1 рецептори</strong>:</li><ul><li>Улесняват <strong>ганглийното предаване</strong> и увеличават <strong>секрецията на мукус</strong>.</li><li>Октриват се в парасимпатиковите ганглии, субмокузните и алвеоларните жлези.</li></ul><li><strong>M2 рецептори</strong>:</li><ul><li>Потискат освобождаването на <strong>ацетилхолин</strong>.</li><li>Октрити са в постганглиорните холинергични нерви.</li></ul><li><strong>M3 рецептори</strong>:</li><ul><li>Опосредстват <strong>бронхоспазъма</strong> и отговора на <strong>мукусна секреция</strong>.</li><li>Разположени са в гладките мускули на дихателните пътища, субмукозните жлези, ендотелни клетки и епител.</li></ul></ul><h3>Механизъм и клинични ефекти</h3><ul><li>Блокирането на <strong>М3 рецепторите</strong>&nbsp;от атроппина води до <strong>релаксация на бронхиалната мускулатура</strong>.</li><li>Инхибират <strong>бронхоконстрикцията</strong>, блокирайки парасимпатиковите рефлекторни реакции, възникнали под въздействие на антигени и неантигенни стимули (физическо натоварване, хипервентилация със студен въздух).</li><li>Намаляват нивото на вътреклетъчния цГМФ и увеличават съотношение цАМФ/цГМФ.</li></ul><p><strong>Клиничен ефект:&nbsp;</strong></p><ul><li>Значителната гъстота на мускариновите рецептори (М1, М2 и М3) в трахеята и големтие бронхи обуславя по-значим бронходилататорен ефект върху <strong>големите дихателни пътища</strong>.</li><li>По-слаб и по-бавен бронходилататорен ефект от β2 агонистите.</li><li>По-слабо изразен бронхопротективен ефект спрямо различните бронхоконстрикторни стимули.</li><li>По-добър клиничен ефект при <strong>ХОББ</strong>.</li><li>Адитивен клиничен ефект с β2 агонистите.</li></ul><table><tbody><tr><td><strong><span style=\"color: rgb(88, 129, 87)\">Представител</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Търговско име</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Доза/Форма</span></strong></td></tr><tr><td><strong>Ipratropium bromid<br></strong></td><td>Atrovent</td><td>pMDI- 0.020 mg</td></tr><tr><td><strong>Oxitropium bromid</strong></td><td>Ventilat</td><td>pMDI- 0.100 mg</td></tr><tr><td><strong>Tiotropium</strong></td><td>Spiriva</td><td>Handihaler 18 µg, Respimat 18 µg</td></tr><tr><td><strong>Glicopironium</strong></td><td>Seebri</td><td>Breezhaler 44 µg</td></tr><tr><td><strong>Aclidinium</strong></td><td>Bretaris</td><td>Genuair 322 µg</td></tr><tr><td><strong>Umeklidinium</strong></td><td>Incruse</td><td>Elipta 62.5 µg</td></tr></tbody></table><h3>Нежелани странични ефекти</h3><ul><li>При повишено <strong>вътреочно налягане</strong> (<strong>глаукома</strong>).</li><li>При нарушения в <strong>микцията</strong>.</li><li>Влияние върху <strong>сърдечния ритъм</strong> и <strong>мукоцилиарния клирънс</strong>.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Метилксантини (Теофилини)</h2><h3>Фармакологични и извънбелодробни ефекти</h3><ul><li><strong>Бронхо-пулмонални</strong>:</li><ul><li><strong>Бронходилатация</strong>, намаляват <strong>отока на бронхиалната лигавица</strong>, подобряват <strong>мукоцилиарния клирънс</strong>.</li><li>Намаляват <strong>бронхиалната хиперреактивност</strong>.</li></ul><li><strong>Извън белодробни</strong>:</li><ul><li>Засилват активността на <strong>дихателната мускулатура</strong>, особено на диафрагмата.</li><li>Чрез вазодилатация намаляват <strong>пулмоналната хипертония.</strong></li><li>Стимулират <strong>ЦНС.</strong></li><li>Имат положителен <strong>инотропен ефект</strong> върху <strong>сърдечния мускул</strong>.</li></ul></ul><h3>Механизъм на действие и особености</h3><ul><li>Повишават нивото на <strong>цАМФ</strong> чрез инхибиране на <strong>циклична фосфодиестераза III</strong>&nbsp;в гладкомускулните клетки&nbsp;и<strong> фосфодиестераза IV</strong>&nbsp;във възпалителните клетки.</li><li>Намаляват <strong>аденозина</strong> чрез въздействие на <strong>аденозиновите рецептори</strong>.(Аденозинът потенцира IgE-зависимата дегранулация на мастоцитите)</li><li><strong>Антиалергично и противовъзпалително действие</strong>:</li><ul><li>Потискат освобождаването на <strong>О2-радикали</strong>&nbsp;от неутрофилите и медиатори от мастоцити и макрофаги.</li><li>Намаляват секрецията на цитокини (IL-2)</li><li>Потискат синтезата на LT B4</li></ul><li>Стимулират адренергичната нервна система</li><li>Имат имуномодулиращ ефект.</li><li><strong>Особености</strong>:</li><ul><li>Терапевтичният ефект е свързан с <strong>плазмената им концентрация,</strong>&nbsp;която зависи от вида на препарата, от резорбцията му и от метаболизма в черния дроб.</li><li>Комбинацията му с други медикаменти, засилващи (фенобарбитал, рифампицин, римицид) или забавящи (макролиди, тетрациклини, линкомицин, бета-блокери, орално контрацептиви) метаболизма в черния дроб.</li><li>Необходимост от <strong>мониториране на плазменото ниво</strong> поради близки <strong>терапевтични</strong> и <strong>токсични</strong> концентрации.</li></ul></ul><table><tbody><tr><td><strong><span style=\"color: rgb(88, 129, 87)\">Представител</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Търговско име</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Доза/Форма</span></strong></td></tr><tr><td><strong>Теофилини с бързо действие</strong></td><td>Novphyllin</td><td>табл. 0,100 g (МДД – 0,600 g), амп. 0,240 g/0,480 g</td></tr><tr><td><strong>Теофилини със удължено действие</strong></td><td>Theotard</td><td>табл. 0,300 g (МДД – 0,600 g)</td></tr><tr><td><strong>Селективни FDЕ4 инхибитори</strong></td><td>Roflumilast (Daxas)</td><td>табл. 500 mg</td></tr></tbody></table><h3>Нежелани странични ефекти</h3><ul><li><strong>Сърдечно-съдова система</strong>:</li><ul><li><strong>Тахикардия</strong> до <strong>политопна екстрасистолия.</strong></li><li><strong>Хипотония, колапс</strong>.</li></ul><li><strong>Стомашно-чревна система</strong>:</li><ul><li>Повишена <strong>стомашна секреция.</strong></li><li><strong>ГЕР.</strong></li><li>Повръщане.</li><li>Хематемеза или мелена.</li></ul><li><strong>Нервна система</strong>:</li><ul><li><strong>Напрегнатост</strong> до <strong>делири</strong> и <strong>гърчове</strong>.</li><li>Сънливост до кома.</li><li>Повишена съдова резистентност.</li></ul><li><strong>Диуретичен ефект</strong>:</li><ul><li>Дехидратация</li><li>Повишен вискозитет на храчките</li><li>Периферен колапс</li></ul><li><strong>Метаболитни прояви</strong>:</li><ul><li><strong>Хипокалиемия.</strong></li><li><strong>Хипофосфатемия</strong>.</li><li>Хипомагнезиемия.</li></ul><li><strong>Други ефекти</strong>:</li><ul><li>Зачервяване на кожата с повишена температура</li><li>Хипервентилация</li></ul></ul><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><br><br><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">36. Кортикостероиди при лечението на бронхообструктивни заболявания.</h1><h2>Фармакологични ефекти на КС</h2><ul><li><strong>Инхибират синтеза на цитокинни гени</strong> в <strong>лимфоцитите, макрофагите</strong> и други възпалителни клетки, участващи в алергичното възпаление:</li><ul><li>Намаляват <strong>миграцията на еозинофилите</strong>&nbsp;и адхезията им към ендотелните клетки.</li><li>Намаляват експресията на <strong>адхезионните молекули</strong> в дихателните пътища (<strong>ДП</strong>).</li><li>Инхибират генерирането на еозинофилни клетки от костния мозък.</li></ul><li>Инхибират генната транскрипция на протеини и за други рецептори освен цитокините.</li><li><strong>Стимулират транскрипцията на β-2-адренергичните гени</strong> и експресията на тези рецептори в епителните клетки и гладкомускулните клетки в ДП, <strong>стимулирайки β-2-адренергичния отговор.</strong></li><li>Инхибират <strong>медиаторното освобождаване&nbsp;</strong>и <strong>синтеза на мукус</strong> в ДП.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Биологични свойства на системните кортикостероиди</h2><table><tbody><tr><td><strong><span style=\"color: rgb(88, 129, 87)\">Продължителност на действие</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Представител</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Плазмен полуживот (мин)</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Биологичен полуживот (часове)</span></strong></td></tr><tr><td>С кратко действие</td><td>Hydrocortison (Sopolcort)</td><td>90</td><td>8-12</td></tr><tr><td>С междинно действие</td><td>Prednisone (Dehydrocortison)<br>Prednisolone<br>Methylprednisolone (Urbason)</td><td>200<br>200<br>200</td><td>12-36<br>12-36<br>12-36</td></tr><tr><td>С продължително действие</td><td>Betametason (Celestone)<br>Dexametason (Prednisolone F)</td><td>300<br>300</td><td>36-54<br>36-54</td></tr></tbody></table><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Инхалаторни кортикостероиди (ИКС)</h2><table><tbody><tr><td><strong><span style=\"color: rgb(88, 129, 87)\">Представител</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Търговско име</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Доза/Форма</span></strong></td></tr><tr><td><strong>Beclomethasone</strong></td><td>Aldecin<br>Becotide<br>Becloforte</td><td>pMDI-50 µg<br>pMDI-50 µg<br>pMDI-250 µg</td></tr><tr><td><strong>Budesonide</strong></td><td>Pulmicort<br>Budiair Jet</td><td>TBH–100, 200 µg<br>pMDI–200 µg</td></tr><tr><td><strong>Flunisolide</strong></td><td>Inhacort</td><td>pMDI-250 µg</td></tr><tr><td><strong>Fluticasone</strong></td><td>Flixotide</td><td>pMDI–50, 125, 250 µg</td></tr><tr><td><strong>Ciclesonid</strong></td><td>Alvesko</td><td>pMDI –160 µg</td></tr></tbody></table><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Еквивалентни дневни дози ИКС</h2><table><tbody><tr><td><strong><span style=\"color: rgb(88, 129, 87)\">Медикамент/доза</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Ниски дози (µg)</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Средни дози (µg)</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Високи дози (µg)</span></strong></td></tr><tr><td><strong>Beclomethasone</strong></td><td>200-500</td><td>&gt;500-1000</td><td>&gt;1000-2000</td></tr><tr><td><strong>Budesonide</strong></td><td>200-400</td><td>&gt;400-800</td><td>&gt;800-1600</td></tr><tr><td><strong>Fluticasone</strong></td><td>100-250</td><td>&gt;250-500</td><td>&gt;500-1000</td></tr><tr><td><strong>Momethasone</strong></td><td>200-400</td><td>&gt;400-800</td><td>&gt;800-1200</td></tr><tr><td><strong>Flunisolide</strong></td><td>500-1000</td><td>1000-2000</td><td>&gt;2000</td></tr></tbody></table><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Активност на ИКС</h2><ul><li><strong>Белодробната противовъзпалителна активност зависи от</strong>:</li><ul><li><strong>Афинитета към глюкокортикоидния рецептор</strong>,</li><li><strong>Фармакокинетичните характеристики</strong> (Бионаличност, Ретенция, Системна експозиция),</li><li><strong>Липофилността на молекулата</strong>.</li></ul><li><strong>Относителна активност на ИКС</strong>:</li><ul><li>Корелира с афинитета на теиз лекарства към глюкокортикоидния рецептор.</li><li>Fluticasone furoate &gt; Fluticasone propionate ≥ Mometasone furoate ≥ Budesonide &gt; Beclomethasone dipropionate &gt; Triamcinolone acetonide</li><li><strong>Ciclesonide</strong> се трансформира във фармакологично активен метаболит (<strong>des-ciclesonide</strong>) в ДП, минимизирайки риска от <strong>орална кандидоза</strong>.</li></ul></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Принципи на лечение със системни КС</h2><ul><li><strong>Кратки курсове</strong> с постепенна редукция на дозата (5-7 дни).</li><li>Приемът да се съобразява с <strong>денонощния ритъм на секреция на АКТХ</strong>, който е най-висок сутрин.</li><li>Прилагане на <strong>алтернираща схема</strong> при необходимост от продължително лечение с ниски дози КС.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Нежелани странични ефекти на системните КС</h2><ul><li><strong>Остеопороза</strong> и <strong>костни фрактури</strong>.</li><li><strong>Миопатия</strong>.</li><li><strong>Хипертония</strong></li><li><strong>Хипергликемия</strong>.</li><li><strong>Синдром на Кушинг</strong>.</li><li><strong>Потискащ ефект върху хипофизо-надбъбречната функция</strong>.</li></ul><h2>Потенциални странични ефекти при лечение с високи дози ИКС</h2><ul><li><strong>Орална кандидоза</strong></li><li><strong>Дрезгав глас</strong></li><li><strong>Болки в гърлото</strong>.</li><li><strong>Кожни промени</strong>.</li><li><strong>Катаракта</strong>, <strong>Глаукома</strong>.</li><li><strong>Нарушение на костната плътност</strong>.</li><li><strong>Надбъбречна супресия</strong>.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>ИКС в лечението на Бронхиална астма (БА)</h2><ul><li><strong>ИКС</strong> са <strong>най-ефективното лекарство</strong> за контролиране на симптомите на <strong>астмата</strong> (GINA).</li><li><strong>ИКС осигуряват</strong>:</li><ul><li><strong>Редуциране на възпалението</strong>, намалена <strong>системна експозиция</strong>, подобряване на <strong>клиничната симптоматика</strong>.</li></ul><li><strong>Включването на ИКС</strong>:</li><ul><li>Подобрява качеството на живот</li><li>Подобрява белодробната функция</li><li>Намалява денонощната вариабилност</li><li>Предпазва от антиген-провокираната бронхоконстрикция</li><li>Намалява необходимостта от ОКС</li><li>Редуцира употребата на бронходилататори при нужда</li><li>Намалява хоспитализациите и смъртността</li></ul></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>ИКС в лечението на ХОББ – кога?</h2><p>Показания за включване на <strong>ИКС</strong> в лечението на <strong>ХОББ</strong>:</p><ul><li><strong>Анамнеза за астма</strong> в детска възраст.</li><li>Начало на респираторните нарушения преди 40 г. възраст.</li><li>Нарастване на <strong>ФЕО1</strong> с ≥ 12% и с ≥ 400 ml при <strong>бронходилататорен тест</strong>.</li><li><strong>Нормален дифузионен капацитет</strong>.</li><li><strong>Периферна еозинофилия</strong> и/или <strong>еозинофилия в храчките</strong>.</li><li>Наличието на данни за <strong>астма в анамнезата</strong> е <strong>независим фактор</strong> за добра преживяемост при употреба на <strong>ИКС</strong>.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Послания за клиничната практика</h2><ul><li><strong>ИКС</strong> имат своето място в лечението на <strong>ХОББ</strong> – при пациенти с фенотип <strong>ACOS</strong> (Asthma-COPD Overlap Syndrome), както и тези от групи <strong>C и D</strong>, които са с <strong>чести екзацербации</strong> и изразени симптоми.</li><li>Повишеният брой на <strong>еозинофилите в храчка</strong>, както и <strong>периферната еозинофилия</strong> са с предимство пред положителния <strong>бронходилататорен тест</strong> като маркери за очакван положителен ефект от <strong>ИКС</strong>.</li><li>Въпреки че FENO по-често се измерва при БА, определянето му припациенти с ХОББ също може да се използва като предиктор заположителен ефект от приложението на ИКС.</li></ul>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\n<script>\nrenderMathInElement(document.body, {\n  delimiters: [\n    {left: '$$', right: '$$', display: true},\n    {left: '$', right: '$', display: false},\n    {left: '\\\\[', right: '\\\\]', display: true},\n    {left: '\\\\(', right: '\\\\)', display: false}\n  ],\n  throwOnError: false\n});\n</script>\n</body>\n</html>";
